import { OfflineService } from '../utils/offlineService';

// Mock NetInfo to control connectivity events
jest.mock('@react-native-community/netinfo', () => ({
    addEventListener: jest.fn((cb) => {
        // Immediately report online
        cb({ isConnected: true });
        return () => { };
    }),
}));

describe('OfflineService', () => {
    beforeEach(async () => {
        // Reset singleton between tests
        // @ts-ignore access private static for test reset
        (OfflineService as any).instance = undefined;
    });

    afterEach(async () => {
        // ensure cleanup
        const inst = OfflineService.getInstance();
        try { await inst.clearQueue(); } catch { };
        try { inst.cleanup(); } catch { };
        // reset again
        // @ts-ignore
        (OfflineService as any).instance = undefined;
    });

    it('pauseAndWait should timeout instead of hanging when processor is stuck', async () => {
        jest.useFakeTimers();

        const offline = OfflineService.getInstance();

        // register a handler that never resolves immediately (simulated long running op)
        offline.registerSyncHandler('delayed', async (_op) => {
            return new Promise<boolean>((resolve) => {
                setTimeout(() => resolve(true), 5000);
            });
        });

        // enqueue one delayed operation which will start processing
        await offline.queueOperation('delayed', { foo: 'bar' });

        // call pauseAndWait with a short timeout and ensure it returns after the timeout
        const p = offline.pauseAndWait(1000);

        // advance timers to trigger timeout
        jest.advanceTimersByTime(1000);

        await expect(p).resolves.toBeUndefined();

        // cleanup fake timers
        jest.useRealTimers();
    });

    it('concurrent queueOperation calls are processed exactly once each', async () => {
        const offline = OfflineService.getInstance();

        const processed: string[] = [];

        offline.registerSyncHandler('counter', async (op) => {
            processed.push(op.id);
            return true;
        });

        // enqueue multiple operations rapidly
        const ops = await Promise.all([
            offline.queueOperation('counter', { i: 1 }),
            offline.queueOperation('counter', { i: 2 }),
            offline.queueOperation('counter', { i: 3 }),
        ]);

        // Trigger a sync and wait for completion
        const res = await offline.syncNow();

        expect(res.success).toBe(true);
        expect(processed.length).toBe(3);

        // Ensure uniqueness
        const unique = new Set(processed);
        expect(unique.size).toBe(3);

        // Ensure ids match enqueued ids (order not strictly required)
        for (const id of ops) {
            expect(unique.has(id)).toBe(true);
        }
    });
});

import { SecurityMiddleware } from '../utils/securityMiddleware';

describe('SecurityMiddleware', () => {
    describe('sanitizeInput', () => {
        it('should remove script tags from input', () => {
            const input = '<script>alert("xss")</script>Hello';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('Hello');
        });

        it('should remove javascript protocol from input', () => {
            const input = 'javascript:alert("xss")';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('');
        });

        it('should remove event handlers from input', () => {
            const input = '<img src="x" onerror="alert(1)" onclick="malicious()">';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('<img src="x" >');
        });

        it('should trim whitespace', () => {
            const input = '  test@example.com  ';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('test@example.com');
        });

        it('should return empty string for null or undefined input', () => {
            expect(SecurityMiddleware.sanitizeInput('')).toBe('');
            expect(SecurityMiddleware.sanitizeInput(null as any)).toBe('');
            expect(SecurityMiddleware.sanitizeInput(undefined as any)).toBe('');
        });

        it('should collapse multiple spaces into one', () => {
            const input = 'hello    world   test';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('hello world test');
        });

        it('should handle nested script tags', () => {
            const input = '<script><script>alert(1)</script></script>Safe text';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).not.toContain('<script');
        });

        it('should handle case-insensitive script tags', () => {
            const input = '<SCRIPT>alert(1)</SCRIPT>Clean';
            const result = SecurityMiddleware.sanitizeInput(input);
            expect(result).toBe('Clean');
        });
    });

    describe('isValidEmail', () => {
        it('should validate correct email format', () => {
            expect(SecurityMiddleware.isValidEmail('test@example.com')).toBe(true);
            expect(SecurityMiddleware.isValidEmail('user.name@domain.co.uk')).toBe(true);
            expect(SecurityMiddleware.isValidEmail('user+tag@example.com')).toBe(true);
        });

        it('should reject invalid email format', () => {
            expect(SecurityMiddleware.isValidEmail('invalid-email')).toBe(false);
            expect(SecurityMiddleware.isValidEmail('@example.com')).toBe(false);
            expect(SecurityMiddleware.isValidEmail('test@.com')).toBe(false);
            expect(SecurityMiddleware.isValidEmail('test@com')).toBe(false);
        });

        it('should reject empty string', () => {
            expect(SecurityMiddleware.isValidEmail('')).toBe(false);
        });
    });

    describe('isStrongPassword', () => {
        it('should accept strong password', () => {
            const result = SecurityMiddleware.isStrongPassword('StrongPass1!');
            expect(result.valid).toBe(true);
            expect(result.message).toBe('Password is strong');
        });

        it('should reject short password', () => {
            const result = SecurityMiddleware.isStrongPassword('Ab1!');
            expect(result.valid).toBe(false);
            expect(result.message).toContain('at least 8 characters');
        });

        it('should reject password without uppercase', () => {
            const result = SecurityMiddleware.isStrongPassword('lowercase1!');
            expect(result.valid).toBe(false);
            expect(result.message).toContain('uppercase');
        });

        it('should reject password without lowercase', () => {
            const result = SecurityMiddleware.isStrongPassword('UPPERCASE1!');
            expect(result.valid).toBe(false);
            expect(result.message).toContain('lowercase');
        });

        it('should reject password without number', () => {
            const result = SecurityMiddleware.isStrongPassword('NoNumber!@');
            expect(result.valid).toBe(false);
            expect(result.message).toContain('number');
        });

        it('should reject password without special character', () => {
            const result = SecurityMiddleware.isStrongPassword('NoSpecial1A');
            expect(result.valid).toBe(false);
            expect(result.message).toContain('special character');
        });
    });

    describe('createRateLimiter', () => {
        it('should allow requests under the limit', () => {
            const limiter = SecurityMiddleware.createRateLimiter(3, 60000);
            const mockReq = { ip: '127.0.0.1' };
            const mockRes = {
                status: jest.fn().mockReturnThis(),
                json: jest.fn(),
                setHeader: jest.fn(),
                redirect: jest.fn(),
            };
            const mockNext = jest.fn();

            // First request — should pass
            limiter(mockReq, mockRes, mockNext);
            expect(mockNext).toHaveBeenCalledTimes(1);
        });

        it('should block requests over the limit', () => {
            const limiter = SecurityMiddleware.createRateLimiter(2, 60000);
            const mockReq = { ip: '192.168.1.1' };
            const mockRes = {
                status: jest.fn().mockReturnThis(),
                json: jest.fn(),
                setHeader: jest.fn(),
                redirect: jest.fn(),
            };
            const mockNext = jest.fn();

            // First and second requests
            limiter(mockReq, mockRes, mockNext);
            limiter(mockReq, mockRes, mockNext);
            expect(mockNext).toHaveBeenCalledTimes(2);

            // Third request — should be blocked
            limiter(mockReq, mockRes, mockNext);
            expect(mockRes.status).toHaveBeenCalledWith(429);
            expect(mockRes.json).toHaveBeenCalledWith(
                expect.objectContaining({ error: 'Too many requests' })
            );
        });

        it('should set rate limit headers', () => {
            const limiter = SecurityMiddleware.createRateLimiter(10, 60000);
            const mockReq = { ip: '10.0.0.1' };
            const mockRes = {
                status: jest.fn().mockReturnThis(),
                json: jest.fn(),
                setHeader: jest.fn(),
                redirect: jest.fn(),
            };
            const mockNext = jest.fn();

            limiter(mockReq, mockRes, mockNext);

            expect(mockRes.setHeader).toHaveBeenCalledWith('X-RateLimit-Limit', 10);
            expect(mockRes.setHeader).toHaveBeenCalledWith('X-RateLimit-Remaining', expect.any(Number));
            expect(mockRes.setHeader).toHaveBeenCalledWith('X-RateLimit-Reset', expect.any(Number));
        });

        it('should track different IPs separately', () => {
            const limiter = SecurityMiddleware.createRateLimiter(1, 60000);
            const mockRes = {
                status: jest.fn().mockReturnThis(),
                json: jest.fn(),
                setHeader: jest.fn(),
                redirect: jest.fn(),
            };
            const mockNext = jest.fn();

            limiter({ ip: '1.1.1.1' }, mockRes, mockNext);
            limiter({ ip: '2.2.2.2' }, mockRes, mockNext);

            // Both should pass since they have different IPs
            expect(mockNext).toHaveBeenCalledTimes(2);
        });
    });

    describe('addSecurityHeaders', () => {
        it('should set security headers', () => {
            const mockReq = {};
            const mockRes = {
                setHeader: jest.fn(),
                status: jest.fn().mockReturnThis(),
                redirect: jest.fn()
            };
            const mockNext = jest.fn();

            SecurityMiddleware.addSecurityHeaders(mockReq, mockRes, mockNext);

            expect(mockRes.setHeader).toHaveBeenCalledWith('X-Frame-Options', 'DENY');
            expect(mockRes.setHeader).toHaveBeenCalledWith('X-Content-Type-Options', 'nosniff');
            expect(mockRes.setHeader).toHaveBeenCalledWith('X-XSS-Protection', '1; mode=block');
            expect(mockRes.setHeader).toHaveBeenCalledWith('Referrer-Policy', 'strict-origin-when-cross-origin');
            expect(mockRes.setHeader).toHaveBeenCalledWith(
                'Permissions-Policy',
                'camera=(), microphone=(), geolocation=(), payment=()'
            );
            expect(mockRes.setHeader).toHaveBeenCalledWith(
                'Content-Security-Policy',
                expect.stringContaining("default-src 'self'")
            );
            expect(mockNext).toHaveBeenCalled();
        });
    });

    describe('validateCSRFToken', () => {
        it('should validate matching tokens', () => {
            const token = 'abc123';
            expect(SecurityMiddleware.validateCSRFToken(token, token)).toBe(true);
        });

        it('should reject mismatched tokens', () => {
            expect(SecurityMiddleware.validateCSRFToken('token1', 'token2')).toBe(false);
        });

        it('should reject empty tokens', () => {
            expect(SecurityMiddleware.validateCSRFToken('', 'token')).toBe(false);
            expect(SecurityMiddleware.validateCSRFToken('token', '')).toBe(false);
            expect(SecurityMiddleware.validateCSRFToken('', '')).toBe(false);
        });

        it('should reject null/undefined tokens', () => {
            expect(SecurityMiddleware.validateCSRFToken(null as any, 'token')).toBe(false);
            expect(SecurityMiddleware.validateCSRFToken('token', null as any)).toBe(false);
        });
    });

    describe('logSecurityEvent', () => {
        it('should log security events', () => {
            const consoleSpy = jest.spyOn(console, 'log').mockImplementation();

            SecurityMiddleware.logSecurityEvent('LOGIN_ATTEMPT', { userId: '123', ip: '127.0.0.1' });

            expect(consoleSpy).toHaveBeenCalledWith(
                '[SECURITY]',
                expect.stringContaining('LOGIN_ATTEMPT'),
                expect.objectContaining({ userId: '123' })
            );

            consoleSpy.mockRestore();
        });
    });
});

import React, { useEffect, useRef, useMemo, useCallback } from 'react';
import {
  View,
  Text,
  StyleSheet,
  Animated,
  TouchableOpacity,
  ViewStyle,
  TextStyle,
} from 'react-native';
import { useAnimation } from '../animations/Animations';
import { COLORS, BORDER_RADIUS, SHADOWS, SPACING } from '../config/theme';

interface AnimatedCardProps {
  children: React.ReactNode;
  style?: ViewStyle;
  onPress?: () => void;
  animationType?: 'fadeIn' | 'slideUp' | 'scale' | 'bounce';
  delay?: number;
  duration?: number;
  disabled?: boolean;
}

const AnimatedCard: React.FC<AnimatedCardProps> = ({
  children,
  style,
  onPress,
  animationType = 'fadeIn',
  delay = 0,
  duration = 300,
  disabled = false,
}) => {
  const { value, fadeIn, slideUp, scale, bounce } = useAnimation(0);
  const opacity = useRef(new Animated.Value(0)).current;
  const animationRef = useRef<Animated.CompositeAnimation | null>(null);

  useEffect(() => {
    // Clear any ongoing animation
    if (animationRef.current) {
      animationRef.current.stop();
      animationRef.current = null;
    }

    const timer = setTimeout(() => {
      let animation: Animated.CompositeAnimation;
      switch (animationType) {
        case 'fadeIn':
          animation = fadeIn(1, duration);
          opacity.setValue(1);
          break;
        case 'slideUp':
          animation = slideUp(0, duration);
          opacity.setValue(1);
          break;
        case 'scale':
          animation = scale({ x: 1, y: 1 }, duration);
          opacity.setValue(1);
          break;
        case 'bounce':
          animation = bounce(duration);
          opacity.setValue(1);
          break;
        default:
          animation = fadeIn(1, duration);
          opacity.setValue(1);
      }
      animationRef.current = animation;
      animation.start();
    }, delay);

    return () => {
      clearTimeout(timer);
      if (animationRef.current) {
        animationRef.current.stop();
        animationRef.current = null;
      }
    };
  }, [animationType, delay, duration, fadeIn, slideUp, scale, bounce, opacity]);

  // Memoize card style to prevent recalculation on every render
  const cardStyle: ViewStyle = useMemo(() => ({
    opacity,
    transform: [
      {
        translateY: animationType === 'slideUp' ? value : 0,
      },
      {
        scale: animationType === 'scale' ? value : 1,
      },
      {
        translateY: animationType === 'bounce' ? value : 0,
      },
    ],
  }), [opacity, animationType, value]);

  // Memoize CardComponent to prevent re-creation on every render
  const CardComponent = useMemo(() => (
    <Animated.View style={[styles.card, cardStyle, style]}>
      {children}
    </Animated.View>
  ), [styles.card, cardStyle, style, children]);

  if (onPress && !disabled) {
    return (
      <TouchableOpacity
        onPress={onPress}
        disabled={disabled}
        activeOpacity={0.8}
        style={style}
      >
        {CardComponent}
      </TouchableOpacity>
    );
  }

  return CardComponent;
};

const styles = StyleSheet.create({
  // 8px grid aligned card
  card: {
    backgroundColor: '#FFFFFF',
    borderRadius: BORDER_RADIUS.lg,
    padding: SPACING.lg,
    borderWidth: 1,
    borderColor: COLORS.borderLight,
    ...SHADOWS.card,
  },
});

// Memoize component to prevent re-renders when props don't change
export default React.memo(AnimatedCard);

import React, { useEffect, useRef, useMemo } from 'react';
import {
  View,
  Text,
  StyleSheet,
  Animated,
  Easing,
  ViewStyle,
  TextStyle,
  Dimensions,
} from 'react-native';

interface AnimatedProgressProps {
  progress: number; // 0 to 100
  width?: number;
  height?: number;
  backgroundColor?: string;
  progressColor?: string;
  showPercentage?: boolean;
  animated?: boolean;
  duration?: number;
  style?: ViewStyle;
  textStyle?: TextStyle;
  borderRadius?: number;
}

const AnimatedProgress: React.FC<AnimatedProgressProps> = ({
  progress,
  width = 200,
  height = 8,
  backgroundColor = '#E5E7EB',
  progressColor = '#4F46E5',
  showPercentage = true,
  animated = true,
  duration = 1000,
  style,
  textStyle,
  borderRadius = 4,
}) => {
  const animatedWidth = useRef(new Animated.Value(0)).current;
  const animationRef = useRef<Animated.CompositeAnimation | null>(null);

  useEffect(() => {
    // Cleanup previous animation
    if (animationRef.current) {
      animationRef.current.stop();
      animationRef.current = null;
    }

    if (animated) {
      const animation = Animated.timing(animatedWidth, {
        toValue: (progress / 100) * width,
        duration,
        easing: Easing.bezier(0.4, 0, 0.2, 1),
        useNativeDriver: false,
      });
      animationRef.current = animation;
      animation.start();
    } else {
      animatedWidth.setValue((progress / 100) * width);
    }

    return () => {
      // Cleanup animation on unmount or before new animation starts
      if (animationRef.current) {
        animationRef.current.stop();
        animationRef.current = null;
      }
    };
  }, [progress, animated, duration, width, animatedWidth]);

  // Memoize container style to prevent recalculation on every render
  const containerStyle: ViewStyle = useMemo(() => ({
    width,
    height,
    backgroundColor,
    borderRadius,
    overflow: 'hidden',
    ...style,
  }), [width, height, backgroundColor, borderRadius, style]);

  // Memoize progress style to prevent recalculation on every render
  const progressStyle: Animated.AnimatedProps<ViewStyle> & ViewStyle = useMemo(() => ({
    height: '100%',
    backgroundColor: progressColor,
    borderRadius,
    width: animated ? animatedWidth : (progress / 100) * width,
  }), [progressColor, borderRadius, animated, animatedWidth, progress, width]);

  return (
    <View style={styles.container}>
      <View style={containerStyle}>
        <Animated.View style={progressStyle} />
      </View>
      {showPercentage && (
        <Text style={[styles.percentageText, textStyle]}>
          {Math.round(progress)}%
        </Text>
      )}
    </View>
  );
};

const styles = StyleSheet.create({
  container: {
    alignItems: 'center',
  },
  percentageText: {
    fontSize: 14,
    fontWeight: '600',
    color: '#1F2937',
    marginTop: 8,
  },
});

// Memoize component to prevent re-renders when props don't change
export default React.memo(AnimatedProgress);

import React, { useEffect, useRef } from 'react';
import {
    View,
    Text,
    StyleSheet,
    TouchableOpacity,
    Modal,
    Animated,
    Dimensions,
} from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { COLORS, TYPOGRAPHY, SPACING, BORDER_RADIUS, SHADOWS, GRADIENTS } from '../config/theme';

const { width } = Dimensions.get('window');

export type AlertType = 'success' | 'error' | 'warning' | 'info' | 'confirm' | 'destructive';

interface AlertButton {
    text: string;
    onPress?: () => void;
    style?: 'default' | 'cancel' | 'destructive';
}

interface CustomAlertProps {
    visible: boolean;
    title: string;
    message?: string;
    type?: AlertType;
    buttons?: AlertButton[];
    onDismiss?: () => void;
    icon?: string;
}

const ALERT_CONFIG: Record<AlertType, { gradient: string[]; icon: string; iconColor: string }> = {
    success: { gradient: ['#10B981', '#34D399'], icon: 'checkmark-circle', iconColor: '#fff' },
    error: { gradient: ['#EF4444', '#F87171'], icon: 'close-circle', iconColor: '#fff' },
    warning: { gradient: ['#F59E0B', '#FBBF24'], icon: 'warning', iconColor: '#fff' },
    info: { gradient: ['#6366F1', '#8B5CF6'], icon: 'information-circle', iconColor: '#fff' },
    confirm: { gradient: ['#6366F1', '#8B5CF6'], icon: 'help-circle', iconColor: '#fff' },
    destructive: { gradient: ['#EF4444', '#DC2626'], icon: 'trash', iconColor: '#fff' },
};

const CustomAlert: React.FC<CustomAlertProps> = ({
    visible,
    title,
    message,
    type = 'info',
    buttons = [{ text: 'OK' }],
    onDismiss,
    icon,
}) => {
    const scaleAnim = useRef(new Animated.Value(0.8)).current;
    const opacityAnim = useRef(new Animated.Value(0)).current;
    const config = ALERT_CONFIG[type];

    useEffect(() => {
        if (visible) {
            Animated.parallel([
                Animated.spring(scaleAnim, { toValue: 1, damping: 15, stiffness: 200, useNativeDriver: true }),
                Animated.timing(opacityAnim, { toValue: 1, duration: 200, useNativeDriver: true }),
            ]).start();
        } else {
            Animated.parallel([
                Animated.timing(scaleAnim, { toValue: 0.8, duration: 150, useNativeDriver: true }),
                Animated.timing(opacityAnim, { toValue: 0, duration: 150, useNativeDriver: true }),
            ]).start();
        }
    }, [visible]);

    const renderButton = (btn: AlertButton, index: number, total: number) => {
        const isDestructive = btn.style === 'destructive';
        const isCancel = btn.style === 'cancel';

        if (isCancel) {
            return (
                <TouchableOpacity
                    key={index}
                    style={[styles.button, styles.cancelButton, total === 1 && styles.fullButton]}
                    onPress={() => { btn.onPress?.(); onDismiss?.(); }}
                    activeOpacity={0.7}
                >
                    <Text style={styles.cancelButtonText}>{btn.text}</Text>
                </TouchableOpacity>
            );
        }

        return (
            <TouchableOpacity
                key={index}
                style={[styles.button, total === 1 && styles.fullButton]}
                onPress={() => { btn.onPress?.(); onDismiss?.(); }}
                activeOpacity={0.8}
            >
                <LinearGradient
                    colors={isDestructive ? ['#EF4444', '#DC2626'] as const : config.gradient as [string, string]}
                    start={{ x: 0, y: 0 }}
                    end={{ x: 1, y: 0 }}
                    style={styles.buttonGradient}
                >
                    <Text style={[styles.buttonText, isDestructive && { color: '#fff' }]}>{btn.text}</Text>
                </LinearGradient>
            </TouchableOpacity>
        );
    };

    return (
        <Modal visible={visible} transparent animationType="none" onRequestClose={onDismiss}>
            <Animated.View style={[styles.overlay, { opacity: opacityAnim }]}>
                <Animated.View style={[styles.container, { transform: [{ scale: scaleAnim }] }]}>
                    {/* Icon Header */}
                    <LinearGradient
                        colors={config.gradient as [string, string]}
                        start={{ x: 0, y: 0 }}
                        end={{ x: 1, y: 1 }}
                        style={styles.iconHeader}
                    >
                        {/* eslint-disable-next-line @typescript-eslint/no-explicit-any */}
                        <Ionicons name={(icon || config.icon) as any} size={36} color={config.iconColor} />
                    </LinearGradient>

                    {/* Content */}
                    <View style={styles.content}>
                        <Text style={styles.title}>{title}</Text>
                        {message ? <Text style={styles.message}>{message}</Text> : null}
                    </View>

                    {/* Buttons */}
                    <View style={[styles.buttonRow, buttons.length === 1 && styles.singleButton]}>
                        {buttons.map((btn, i) => renderButton(btn, i, buttons.length))}
                    </View>
                </Animated.View>
            </Animated.View>
        </Modal>
    );
};

const styles = StyleSheet.create({
    overlay: {
        flex: 1,
        backgroundColor: 'rgba(0,0,0,0.6)',
        justifyContent: 'center',
        alignItems: 'center',
        paddingHorizontal: SPACING.xl,
    },
    container: {
        backgroundColor: COLORS.surface,
        borderRadius: BORDER_RADIUS.xl,
        overflow: 'hidden',
        width: '100%',
        maxWidth: 360,
        ...SHADOWS.xl,
    },
    iconHeader: {
        paddingVertical: SPACING.xl,
        alignItems: 'center',
        justifyContent: 'center',
    },
    content: {
        paddingHorizontal: SPACING.xl,
        paddingTop: SPACING.xl,
        paddingBottom: SPACING.lg,
        alignItems: 'center',
    },
    title: {
        ...TYPOGRAPHY.h3,
        color: COLORS.text,
        textAlign: 'center',
        marginBottom: SPACING.sm,
    },
    message: {
        ...TYPOGRAPHY.body,
        color: COLORS.textSecondary,
        textAlign: 'center',
        lineHeight: 22,
    },
    buttonRow: {
        flexDirection: 'row',
        paddingHorizontal: SPACING.lg,
        paddingBottom: SPACING.lg,
        gap: SPACING.sm,
    },
    singleButton: {
        justifyContent: 'center',
    },
    button: {
        flex: 1,
        borderRadius: BORDER_RADIUS.md,
        overflow: 'hidden',
    },
    fullButton: {
        flex: 1,
    },
    buttonGradient: {
        paddingVertical: SPACING.md,
        alignItems: 'center',
    },
    cancelButton: {
        backgroundColor: COLORS.surfaceSecondary,
        paddingVertical: SPACING.md,
        alignItems: 'center',
        borderRadius: BORDER_RADIUS.md,
    },
    cancelButtonText: {
        ...TYPOGRAPHY.captionBold,
        color: COLORS.textSecondary,
    },
    buttonText: {
        ...TYPOGRAPHY.captionBold,
        color: COLORS.textInverse,
    },
});

export default CustomAlert;

// Helper hook for easy usage
export const useAlert = () => {
    const [alertConfig, setAlertConfig] = React.useState<CustomAlertProps & { visible: boolean }>({
        visible: false,
        title: '',
    });

