      case 'vitamin': return '#FF9600';
      case 'mineral': return '#1CB0F6';
      default: return '#CE82FF';
    }
  };

  const categoryColor = getCategoryColor(item.category || item.type);

  return (
    <Modal
      transparent
      visible={visible}
      animationType="none"
      onRequestClose={onClose}
      statusBarTranslucent
