import { Session } from '@supabase/supabase-js';
import { SupabaseService } from '../services/supabase';
import { OfflineService } from '../utils/offlineService';
import { ContentModerationService } from '../services/contentModerationService';
import { DeepLinkingService } from '../utils/deepLinking';
import { Platform } from 'react-native';
import { signInAndExchange, proxiedRequest, defaultEdgeFunctionUrl } from '../services/webSession';
import { importMetaFallback } from '../utils/importMetaFallback';

interface AuthContextType {
  session: Session | null;
  user: any | null;
  loading: boolean;
  isBanned: boolean;
  banMessage: string | null;
  signOut: () => Promise<void>;
  signIn?: (email: string, password: string) => Promise<any>;
  proxiedFetch?: (method: string, path: string, options?: { query?: string; body?: any }) => Promise<any>;
}

const AuthContext = createContext<AuthContextType | undefined>(undefined);

export const useSupabaseAuth = () => {
  const context = useContext(AuthContext);
  if (!context) {
    throw new Error('useSupabaseAuth must be used within a SupabaseProvider');
  }
  return context;
};

interface SupabaseProviderProps {
  children: React.ReactNode;
}

export const SupabaseProvider: React.FC<SupabaseProviderProps> = ({ children }) => {
  const [session, setSession] = useState<Session | null>(null);
  const [user, setUser] = useState<any | null>(null);
  const [loading, setLoading] = useState(true);
  const [isBanned, setIsBanned] = useState(false);
  const [banMessage, setBanMessage] = useState<string | null>(null);

  const supabaseService = SupabaseService.getInstance();


  // Edge function URL for proxy calls (web)
  // Resolve edge function URL, preferring explicit config, then importMeta fallback, then env
  const EDGE_FN = defaultEdgeFunctionUrl() || (importMetaFallback.env && importMetaFallback.env.EXPO_PUBLIC_SESSION_EXCHANGE_URL) || (importMetaFallback.env && importMetaFallback.env.SESSION_EXCHANGE_URL) || '';

  // Debug: log the resolved Edge Function URL on provider mount so web startup reveals runtime value
  useEffect(() => {
    try {
      if (__DEV__) {
        console.debug('[SupabaseProvider] EDGE_FN:', EDGE_FN, 'Platform:', Platform.OS);
      }
    } catch (e) {
      if (__DEV__) {
        console.debug('[SupabaseProvider] EDGE_FN log failed', e);
      }
    }
  }, [EDGE_FN]);

  // Check ban status whenever user changes
  useEffect(() => {
    if (user?.id) {
      ContentModerationService.getInstance().checkBanStatus(user.id).then(status => {
        setIsBanned(status.isBanned);
        if (status.isBanned) {
          const msg = ContentModerationService.getInstance().getBanMessage(status, false);
          setBanMessage(msg.message);
        } else {
          setBanMessage(null);
        }
      }).catch(() => { });
    } else {
      setIsBanned(false);
      setBanMessage(null);
    }
  }, [user?.id]);

  useEffect(() => {
    // Get initial session
    const getInitialSession = async () => {
      try {
        const { data: { session: initialSession } } = await supabaseService.getClient().auth.getSession();
        setSession(initialSession);
        setUser(initialSession?.user ?? null);
      } catch (error) {
        console.error('Error getting initial session:', error);
      } finally {
        setLoading(false);
      }
    };

    getInitialSession();

    // Listen for auth changes
    const { data: { subscription } } = supabaseService.getClient().auth.onAuthStateChange(
      (_event, session) => {
        setSession(session);
        setUser(session?.user ?? null);
        setLoading(false);
      }
    );

    return () => subscription.unsubscribe();
  }, []);

  const signOut = useCallback(async () => {
    try {
      const offline = OfflineService.getInstance();

      // Pause offline processing and wait for any in-flight sync to finish
      // to avoid operations being sent under the wrong user context.
      await offline.pauseAndWait();

      await supabaseService.signOut();

      // Clear offline queue to prevent cross-user data leakage
      await offline.clearQueue();
    } catch (error) {
      console.error('Error signing out:', error);
    } finally {
      // Resume offline processor so the service can continue operating
      try {
        OfflineService.getInstance().resume();
      } catch (_) { }

      // Always clear local state regardless of signOut success
      setSession(null);
      setUser(null);
    }
  }, [supabaseService]);

  // Register handler for refresh failures so the app can run deterministic logout
  useEffect(() => {
    const handler = async () => {
      try {
        // Use the same signOut flow so queues are paused and cleared
        await signOut();
      } catch (_) { }
    };

    try {
      supabaseService.onRefreshFailure(handler);
    } catch (_) { }

    return () => {
      try {
        supabaseService.onRefreshFailure(() => { });
      } catch (_) { }
    };
  }, [supabaseService, signOut]);

  // After successful authentication (session becomes non-null), process any
  // deep links that were queued while auth/navigation was initializing.
  useEffect(() => {
    if (session) {
      try {
        DeepLinkingService.getInstance().processPendingURLs();
      } catch (_) { }
    }
  }, [session]);

  // Sign-in wrapper that uses signInAndExchange on web to set HttpOnly cookie and clear client session
  const signIn = useCallback(async (email: string, password: string) => {
    try {
      const result = await signInAndExchange(supabaseService.getClient(), email, password, { edgeFunctionUrl: EDGE_FN });
      // If web, client session is cleared; keep user info from result if available
      const userFromResult = (result as any)?.data?.user || (result as any)?.user || null;
      if (Platform.OS === 'web') {
        setUser(userFromResult);
        setSession(null);
      } else {
        const sessionObj = (result as any)?.data?.session || null;
        setSession(sessionObj);
        setUser(sessionObj?.user ?? userFromResult);
      }
      return result;
    } catch (err) {
      return { error: err };
    }
  }, [supabaseService]);

  // Proxied fetch helper - on web routes through Edge Function, on native uses client directly for simple GETs
  const proxiedFetch = useCallback(async (method: string, path: string, options?: { query?: string; body?: any }) => {
    if (Platform.OS === 'web') {
      return proxiedRequest(EDGE_FN, method, path, options);
    }
    try {
      const client = supabaseService.getClient();
      if (method.toUpperCase() === 'GET') {
        const selectQuery = options?.query || '*';
        const { data, error } = await client.from(path).select(selectQuery);
        return { ok: !error, data, error };
      }
      // For non-GET on native, prefer using Supabase client methods directly
      return { ok: false, error: 'Use Supabase client directly for non-GET requests on native' };
    } catch (err) {
      return { ok: false, error: err };
    }
  }, [supabaseService]);

  const value = useMemo<AuthContextType>(() => ({
    session,
    user,
    loading,
    isBanned,
    banMessage,
    signOut,
    signIn,
    proxiedFetch,
  }), [session, user, loading, isBanned, banMessage, signOut]);

  return (
    <AuthContext.Provider value={value}>
      {children}
    </AuthContext.Provider>
  );
};

import { useState, useCallback, useEffect } from 'react';
import { SupabaseService } from '../services/supabase';
import { StreakService, StreakData } from '../services/streakService';
import { HealthService, HealthInsight } from '../services/healthService';
import { LeagueService, UserLeagueData } from '../services/leagueService';
import { StoreService, UserCurrency } from '../services/storeService';
import { MissionService, DailyMission } from '../services/missionService';
import { NotificationService } from '../services/notificationService';
import { DailyItem } from '../components/HomeScreen/DailyProgramChecklist';
import { getLocalDateString } from '../utils/dateUtils';
import { offlineCache } from '../services/offlineCache';
import { Language } from '../locales/i18n';

const CACHE_KEY_HOME = 'home_screen_data';

export interface HomeData {
  profile: any;
  streakData: StreakData | null;
  healthInsights: HealthInsight[];
  todaysWorkouts: any[];
  leagueData: UserLeagueData | null;
  currency: UserCurrency | null;
  dailyMissions: DailyMission[];
  dailyProgram: DailyItem[];
  loading: boolean;
  refreshing: boolean;
  error: Error | null;
  isOfflineData: boolean;
}

export const useHomeData = (language: Language = 'en') => {
  const [data, setData] = useState<HomeData>({
    profile: null,
    streakData: null,
    healthInsights: [],
    todaysWorkouts: [],
    leagueData: null,
    currency: null,
    dailyMissions: [],
    dailyProgram: [],
    loading: true,
    refreshing: false,
    error: null,
    isOfflineData: false,
  });

  const loadData = useCallback(async (isRefresh = false) => {
    if (isRefresh) {
      setData(prev => ({ ...prev, refreshing: true }));
    } else {
      setData(prev => ({ ...prev, loading: true }));
    }

    // Try to load from cache first for immediate UI
    if (!isRefresh) {
      try {
        const cached = await offlineCache.get<Partial<HomeData>>(CACHE_KEY_HOME);
        if (cached) {
          setData(prev => ({
            ...prev,
            ...cached,
            loading: false, // Show cached content immediately
            isOfflineData: true
          }));
        }
      } catch (e) {
        console.warn('Failed to load home cache:', e);
      }
    }

    try {
      const supa = SupabaseService.getInstance();
      const { user } = await supa.getCurrentUser();
      
      if (!user) {
        throw new Error('No user found');
      }

      // Fetch Profile
      let profileData = null;
      try {
        const { data } = await supa.getUserProfile(user.id);
        profileData = data;
      } catch (error) {
        console.warn('Failed to load user profile:', error);
        // If we have cached profile, keep it, otherwise use fallback
        if (!data.profile) {
            profileData = {
            id: user.id,
            email: user.email,
            full_name: 'User',
            username: `user_${user.id.slice(0, 8)}`
            };
        } else {
            profileData = data.profile;
        }
      }

      const today = getLocalDateString();

      // Parallel Data Fetching
      const results = await Promise.allSettled([
        StreakService.getInstance().getStreak(),
        (async () => {
          const hs = HealthService.getInstance();
          await hs.initialize();
          const hData = await hs.getTodayHealthData();
          const insights = hs.generateHealthInsights(hData, profileData?.gender || null);
          await NotificationService.getInstance().checkSmartReminders(hData, language);
          return insights;
        })(),
        supa.getClient().from('workouts').select('*').eq('user_id', user.id).gte('created_at', today + 'T00:00:00').order('created_at', { ascending: false }).limit(5),
        LeagueService.getInstance().getUserLeague(),
        StoreService.getInstance().getUserCurrency(),
        MissionService.getInstance().getDailyMissions(),
        // Daily Program Items
        (async () => {
          const [wRes, nRes, sRes] = await Promise.all([
            supa.getAssignedWorkouts(user.id),
            supa.getAssignedNutritionPlans(user.id),
            supa.getAssignedSupplements(user.id).catch(() => ({ data: [] }))
          ]);

          const items: DailyItem[] = [];
          const todayStr = new Date().toISOString().split('T')[0];

          if (wRes.data) {
            wRes.data.forEach((w: any) => {
              if (w.scheduled_date && w.scheduled_date.startsWith(todayStr)) {
                items.push({
                  id: w.id,
                  type: 'workout',
                  title: w.workout_name || 'Workout',
                  subtitle: `${w.duration_minutes || 0} min • ${w.calories_burned || 0} cal`,
                  completed: w.is_completed,
                  time: w.scheduled_time 
                });
              }
            });
          }
          // Add nutrition and supplements processing here if needed
          return items;
        })()
      ]);

      // Extract results
      const streakData = results[0].status === 'fulfilled' ? results[0].value : null;
      const healthInsights = results[1].status === 'fulfilled' ? results[1].value : [];
      const todaysWorkouts = results[2].status === 'fulfilled' ? (results[2].value.data || []) : [];
      const leagueData = results[3].status === 'fulfilled' ? results[3].value : null;
      const currency = results[4].status === 'fulfilled' ? results[4].value : null;
      const dailyMissions = results[5].status === 'fulfilled' ? results[5].value : [];
      const dailyProgram = results[6].status === 'fulfilled' ? results[6].value : [];

      // Background task
      MissionService.getInstance().getWeeklyMissions().catch(err => console.warn('Weekly mission generation trigger:', err));

      const newData = {
        profile: profileData,
        streakData,
        healthInsights,
        todaysWorkouts,
        leagueData,
        currency,
        dailyMissions,
        dailyProgram,
        loading: false,
        refreshing: false,
        error: null,
        isOfflineData: false,
      };

      setData(newData);

      // Update Cache
      offlineCache.set(CACHE_KEY_HOME, {
        profile: profileData,
        streakData,
        healthInsights,
        todaysWorkouts,
        leagueData,
        currency,
        dailyMissions,
        dailyProgram,
      });

    } catch (error: any) {
      console.error('Home data load error:', error);
      setData(prev => ({ 
        ...prev, 
        loading: false, 
        refreshing: false, 
        error: error,
        // Keep isOfflineData true if we are falling back to cache
        isOfflineData: prev.isOfflineData || !!prev.profile 
      }));
    }
  }, [language]);

  return { ...data, loadData };
};

import { useMemo as useReactMemo, useRef } from 'react';

export function useCustomMemo<T>(
  factory: () => T,
  deps: React.DependencyList,
  options?: {
    equalityFn?: (a: T, b: T) => boolean;
  }
): T {
  const prevValueRef = useRef<T | undefined>(undefined);
  const prevDepsRef = useRef<React.DependencyList | undefined>(undefined);

  // Check if deps have changed
  const depsChanged = !prevDepsRef.current ||
    deps.length !== prevDepsRef.current.length ||
    deps.some((dep, i) => !Object.is(dep, prevDepsRef.current![i]));

  if (depsChanged) {
    const newValue = factory();

    if (options?.equalityFn && prevValueRef.current !== undefined) {
      // If custom equality says values are equal, keep old reference
      if (options.equalityFn(prevValueRef.current, newValue)) {
        prevDepsRef.current = deps;
        return prevValueRef.current;
      }
    }

    prevValueRef.current = newValue;
    prevDepsRef.current = deps;
  }

  return prevValueRef.current as T;
}

import { useState, useEffect, useCallback } from 'react';
import { SupabaseService } from '../services/supabase';

export type Period = 'weekly' | 'monthly' | 'yearly';

export interface BodyMetric {
    weight: number;
    bodyFat?: number;
    muscleMass?: number;
    waterPercentage?: number;
    boneMass?: number;
    bmi?: number;
    recordedAt: string;
}

export interface WorkoutSummary {
    totalWorkouts: number;
    totalDuration: number;
    avgDuration: number;
    streak: number;
    caloriesBurned: number;
}

export interface NutritionSummary {
    avgCalories: number;
    avgProtein: number;
    avgCarbs: number;
    avgFat: number;
    adherenceRate: number;
}

export function useProgressReport(period: Period, isTurkish: boolean, targetUserId?: string) {
    const [loading, setLoading] = useState(true);
    const [refreshing, setRefreshing] = useState(false);
    const [bodyMetrics, setBodyMetrics] = useState<BodyMetric[]>([]);
    const [workoutSummary, setWorkoutSummary] = useState<WorkoutSummary | null>(null);
    const [nutritionSummary, setNutritionSummary] = useState<NutritionSummary | null>(null);
    const [goalProgress, setGoalProgress] = useState<{ label: string; current: number; target: number; unit: string; icon: string; color: string }[]>([]);

    const supabase = SupabaseService.getInstance();

    const loadData = useCallback(async () => {
        setLoading(true);
        try {
            const { user: currentUser } = await supabase.getCurrentUser();
            const userId = targetUserId || currentUser?.id;
            
            if (!userId) return;

            const now = new Date();
            let startDate: Date;
            if (period === 'weekly') startDate = new Date(now.getTime() - 7 * 24 * 60 * 60 * 1000);
            else if (period === 'monthly') startDate = new Date(now.getTime() - 30 * 24 * 60 * 60 * 1000);
            else startDate = new Date(now.getTime() - 365 * 24 * 60 * 60 * 1000);

            const startIso = startDate.toISOString();
            const startDateOnly = startIso.split('T')[0];

            const [{ data: healthData }, { data: workoutData, error: wErr }, { data: nutData, error: nErr }] = await Promise.all([
                supabase.getClient()
                    .from('health_data')
                    .select('*')
                    .eq('user_id', userId)
                    .gte('timestamp', startIso)
                    .not('weight', 'is', null)
                    .order('timestamp', { ascending: true }),
                supabase.getClient()
                    .rpc('get_workout_summary', { p_user_id: userId, p_start_date: startIso }),
                supabase.getClient()
                    .rpc('get_nutrition_summary', { p_user_id: userId, p_start_date: startDateOnly }),
            ]);

            const metrics: BodyMetric[] = (healthData || []).map((r: any) => ({
                weight: r.weight,
                bodyFat: r.body_fat_percentage,
                muscleMass: r.muscle_mass_percentage,
                waterPercentage: r.water_percentage,
                boneMass: r.bone_mass_kg,
                bmi: r.bmi,
                recordedAt: r.timestamp,
            }));
            setBodyMetrics(metrics);

            if (workoutData && workoutData.length > 0) {
                const w = workoutData[0];
                const totalWorkouts = Number(w.total_workouts) || 0;
                setWorkoutSummary({
                    totalWorkouts,
                    totalDuration: Number(w.total_duration) || 0,
                    avgDuration: totalWorkouts > 0 ? Math.round(Number(w.total_duration) / totalWorkouts) : 0,
                    streak: 0, // Implement streak separately if needed
                    caloriesBurned: Number(w.calories_burned) || 0,
                });
            } else if (wErr) {
                console.warn('RPC get_workout_summary error:', wErr);
            }

            if (nutData && nutData.length > 0) {
                const n = nutData[0];
                const daysLogged = Number(n.days_logged) || 0;
                const expectedDays = period === 'weekly' ? 7 : period === 'monthly' ? 30 : 365;

                if (daysLogged > 0) {
                    setNutritionSummary({
                        avgCalories: Number(n.avg_calories) || 0,
                        avgProtein: Number(n.avg_protein) || 0,
                        avgCarbs: Number(n.avg_carbs) || 0,
                        avgFat: Number(n.avg_fat) || 0,
                        adherenceRate: Math.min(100, Math.round((daysLogged / expectedDays) * 100)),
                    });
                } else {
                    setNutritionSummary(null);
                }
            } else if (nErr) {
                console.warn('RPC get_nutrition_summary error:', nErr);
            }

            // Goal Progress calculation
            const goals: typeof goalProgress = [];

            if (metrics.length > 0) {
                const latestWeight = metrics[metrics.length - 1].weight;
                goals.push({
                    label: isTurkish ? 'Kilo' : 'Weight',
                    current: latestWeight,
                    target: 75,
                    unit: 'kg',
                    icon: 'scale-outline',
                    color: '#3498db',
                });
                if (metrics[metrics.length - 1].bodyFat) {
                    goals.push({
                        label: isTurkish ? 'Vücut Yağı' : 'Body Fat',
                        current: metrics[metrics.length - 1].bodyFat!,
                        target: 15,
                        unit: '%',
                        icon: 'flame-outline',
                        color: '#e74c3c',
                    });
                }
                if (metrics[metrics.length - 1].muscleMass) {
                    goals.push({
                        label: isTurkish ? 'Kas' : 'Muscle',
                        current: metrics[metrics.length - 1].muscleMass!,
                        target: 45,
                        unit: '%',
                        icon: 'fitness-outline',
                        color: '#2ecc71',
                    });
                }
            }
            // Simplified goal adding
            if (workoutData && workoutData.length > 0) {
                goals.push({
                    label: isTurkish ? 'Antrenman' : 'Workouts',
                    current: Number(workoutData[0].total_workouts) || 0,
                    target: period === 'weekly' ? 5 : period === 'monthly' ? 20 : 240,
                    unit: '',
                    icon: 'barbell-outline',
                    color: '#9b59b6',
                });
            }
            setGoalProgress(goals);

        } catch (err) {
            console.error('useProgressReport error:', err);
        } finally {
            setLoading(false);
            setRefreshing(false);
        }
    }, [period, targetUserId, isTurkish]);

    useEffect(() => {
        loadData();
    }, [loadData]);

    const onRefresh = () => {
        setRefreshing(true);
        loadData();
    };

    return {
        loading,
        refreshing,
        bodyMetrics,
        workoutSummary,
        nutritionSummary,
        goalProgress,
        onRefresh,
    };
}

