export default AIToolsScreen;

import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, TouchableOpacity } from 'react-native';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import Animated, { useSharedValue, useAnimatedStyle, withRepeat, withTiming, withSequence, Easing, cancelAnimation } from 'react-native-reanimated';
import { useTranslation } from '../hooks/useTranslation';
import AnimatedButton from '../components/AnimatedButton';
import { useAlert } from '../components/CustomAlert';
import { SupabaseService } from '../services/supabase';
import { MissionService } from '../services/missionService';
import { LeagueService } from '../services/leagueService';
import { StreakService } from '../services/streakService';
import { HealthService } from '../services/healthService';
import { COLORS, TYPOGRAPHY, SPACING, COMMON_STYLES, BORDER_RADIUS, SHADOWS } from '../config/theme';
import { useTheme } from '../contexts/ThemeContext';
import { safeGoBack } from '../utils/navigation';

export default function ActiveWorkoutScreen({ navigation, route }: any) {
    const { colors, isDark } = useTheme();
    const styles = React.useMemo(() => getStyles(colors), [colors]);

    const { isTurkish } = useTranslation();
    const insets = useSafeAreaInsets();
    const { showAlert, AlertComponent } = useAlert();

    // Workout State
    const [elapsedTime, setElapsedTime] = useState(0);
    const [heartRate, setHeartRate] = useState<number | null>(null);
    const [calories, setCalories] = useState(0);
    const [isPaused, setIsPaused] = useState(false);
    const [sensorSource, setSensorSource] = useState<'apple_health' | 'google_health' | 'manual' | null>(null);

    const workoutName = route.params?.workoutName || (isTurkish ? 'Serbest İdman' : 'Freestyle Workout');
    const muscleGroups = route.params?.muscleGroups || [];
    const [saving, setSaving] = useState(false);
    const workoutStartRef = React.useRef(new Date());

    // Heartbeat Animation
    const scale = useSharedValue(1);

    useEffect(() => {
        // Start Heartbeat Animation
        scale.value = withRepeat(
            withSequence(
                withTiming(1.2, { duration: 200, easing: Easing.ease }),
                withTiming(1, { duration: 200, easing: Easing.ease }),
                withTiming(1.1, { duration: 200, easing: Easing.ease }),
                withTiming(1, { duration: 400, easing: Easing.ease })
            ),
            -1, // infinite
            false
        );

        return () => {
            // Cleanup infinite animation on unmount
            cancelAnimation(scale);
        };
    }, []);

    const animatedHeartStyle = useAnimatedStyle(() => {
        return { transform: [{ scale: scale.value }] };
    });

    useEffect(() => {
        let interval: NodeJS.Timeout;
        if (!isPaused) {
            interval = setInterval(() => {
                setElapsedTime(prev => prev + 1);
            }, 1000);
        }
        return () => clearInterval(interval);
    }, [isPaused]);

    useEffect(() => {
        const healthService = HealthService.getInstance();
        if (isPaused) return;
        const stopStream = healthService.startWorkoutMetricsStream(
            workoutStartRef.current,
            (metrics) => {
                setSensorSource(metrics.source);
                setHeartRate(metrics.heartRate);
                setCalories(metrics.calories);
            },
            { intervalMs: 3000 }
        );

        return () => {
            stopStream();
        };
    }, [isPaused]);

    const formatTime = (seconds: number) => {
        const m = Math.floor(seconds / 60).toString().padStart(2, '0');
        const s = (seconds % 60).toString().padStart(2, '0');
        const h = Math.floor(seconds / 3600);
        return h > 0 ? `${h}:${m}:${s}` : `${m}:${s}`;
    };

    const handleFinish = async () => {
        if (saving) return;
        setSaving(true);
        let saveSuccess = true;
        try {
            const supabase = SupabaseService.getInstance();
            const { user } = await supabase.getCurrentUser();
            if (user) {
                // Save workout to Supabase
                await supabase.getClient().from('workout_sessions').insert({
                    user_id: user.id,
                    start_time: workoutStartRef.current.toISOString(),
                    end_time: new Date().toISOString(),
                    duration: elapsedTime,
                    calories_burned: calories,
                    exercises: Array.isArray(muscleGroups) ? muscleGroups : [],
                    notes: workoutName,
                });
                // Log streak
                try { await StreakService.getInstance().logWorkout(); } catch { }
                // Award XP (10 base + 1 per minute + 1 per 50 cal)
                const xpAmount = 10 + Math.round(elapsedTime / 60) + Math.round(calories / 50);
                try { await LeagueService.getInstance().addXP(xpAmount, 'workout', workoutName); } catch { }
                
                // Update Missions
                try { await MissionService.getInstance().updateProgressByCategory('workout', 1); } catch { }
            }
        } catch (err) {
            console.warn('Workout save error:', err);
            saveSuccess = false;
        } finally {
            setSaving(false);
        }
        if (saveSuccess) {
            showAlert({
                type: 'success',
                title: isTurkish ? 'İdman Tamamlandı!' : 'Workout Complete!',
                message: isTurkish
                    ? `Süre: ${formatTime(elapsedTime)}\nYakılan: ${calories} kcal\nOrtalama Nabız: ${heartRate ?? '-'} BPM`
                    : `Duration: ${formatTime(elapsedTime)}\nBurned: ${calories} kcal\nAvg HR: ${heartRate ?? '-'} BPM`,
                buttons: [{ text: isTurkish ? 'Harika!' : 'Awesome!', onPress: () => safeGoBack(navigation, 'Workout') }],
            });
        } else {
            showAlert({
                type: 'error',
                title: isTurkish ? 'Kaydetme Hatası' : 'Save Error',
                message: isTurkish
                    ? 'İdman kaydedilemedi. Lütfen tekrar deneyin.'
                    : 'Failed to save workout. Please try again.',
                buttons: [{ text: isTurkish ? 'Tamam' : 'OK' }],
            });
        }
    };

    return (
        <View style={[COMMON_STYLES.screenContainer, { backgroundColor: colors.background }]}>
            <AlertComponent />
            <View style={[styles.header, { paddingTop: insets.top + 16 }]}>
                <TouchableOpacity onPress={() => {
                    showAlert({
                        type: 'confirm',
                        title: isTurkish ? 'İdmanı Bırak' : 'Quit Workout',
                        message: isTurkish ? 'İdmanı bitirmek istediğinize emin misiniz? İlerleme kaydedilmeyecek.' : 'Are you sure you want to quit? Progress will not be saved.',
                        buttons: [
                            { text: isTurkish ? 'İptal' : 'Cancel', style: 'cancel' },
                            { text: isTurkish ? 'Bırak' : 'Quit', style: 'destructive', onPress: () => safeGoBack(navigation, 'Workout') },
                        ],
                    });
                }} style={styles.iconBtn}>
                    <Ionicons name="close" size={28} color={colors.text} />
                </TouchableOpacity>
                <View style={[styles.statusBadge, isPaused && { backgroundColor: colors.warning + '20' }]}>
                    <View style={[styles.statusDot, isPaused && { backgroundColor: colors.warning }]} />
                    <Text style={[styles.statusText, isPaused && { color: colors.warning }]}>
                        {isPaused
                            ? (isTurkish ? 'Duraklatıldı' : 'Paused')
                            : sensorSource
                                ? (isTurkish ? 'Canlı Sensör Verisi' : 'Live Sensor Data')
                                : (isTurkish ? 'Sensör Bağlantısı Bekleniyor' : 'Waiting for Sensor Connection')}
                    </Text>
                </View>
                <TouchableOpacity style={styles.iconBtn} onPress={() => navigation.navigate('Spotify')}>
                    <Ionicons name="musical-notes" size={24} color={colors.text} />
                </TouchableOpacity>
            </View>

            <View style={styles.content}>
                <Text style={styles.workoutName}>{workoutName}</Text>
                <Text style={styles.timerLarge}>{formatTime(elapsedTime)}</Text>

                <View style={styles.metricsGrid}>
                    {/* Heart Rate Metric */}
                    <View style={styles.metricCard}>
                        <Animated.View style={[styles.heartContainer, animatedHeartStyle]}>
                            <Ionicons name="heart" size={48} color={colors.error} />
                        </Animated.View>
                        <Text style={styles.metricValue}>{heartRate ?? '--'} <Text style={styles.metricUnit}>BPM</Text></Text>
                        <Text style={styles.metricLabel}>{isTurkish ? 'Nabız' : 'Heart Rate'}</Text>
                    </View>

                    {/* Calories Metric */}
                    <View style={styles.metricCard}>
                        <View style={styles.iconContainer}>
                            <Ionicons name="flame" size={32} color={colors.streak} />
                        </View>
                        <Text style={styles.metricValue}>{calories} <Text style={styles.metricUnit}>kcal</Text></Text>
                        <Text style={styles.metricLabel}>{isTurkish ? 'Yakılan' : 'Burned'}</Text>
                    </View>
                </View>
            </View>

            <View style={[styles.controls, { paddingBottom: insets.bottom + 20 }]}>
                <TouchableOpacity
                    style={[styles.playPauseBtn, isPaused && { backgroundColor: colors.success }]}
                    onPress={() => setIsPaused(!isPaused)}
                >
                    <Ionicons name={isPaused ? "play" : "pause"} size={32} color={colors.textInverse} />
                </TouchableOpacity>

                <AnimatedButton
                    title={isTurkish ? 'İdmanı Bitir' : 'Finish Workout'}
                    onPress={handleFinish}
                    style={styles.finishBtn}
                />
            </View>
        </View>
    );
}

const getStyles = (colors: any) => StyleSheet.create({
    header: { flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between', paddingHorizontal: SPACING.lg },
    iconBtn: { width: 44, height: 44, borderRadius: 22, backgroundColor: colors.surface, justifyContent: 'center', alignItems: 'center' },
    statusBadge: { flexDirection: 'row', alignItems: 'center', backgroundColor: colors.success + '20', paddingHorizontal: SPACING.md, paddingVertical: 6, borderRadius: BORDER_RADIUS.pill },
    statusDot: { width: 8, height: 8, borderRadius: 4, backgroundColor: colors.success, marginRight: 6 },
    statusText: { ...TYPOGRAPHY.captionBold, color: colors.success },
    content: { flex: 1, justifyContent: 'center', alignItems: 'center', paddingHorizontal: SPACING.xl },
    workoutName: { ...TYPOGRAPHY.h2, color: colors.textSecondary, marginBottom: SPACING.sm },
    timerLarge: { fontSize: 72, fontWeight: '800', color: colors.text, fontFamily: 'monospace', marginBottom: SPACING.xxl },
    metricsGrid: { flexDirection: 'row', gap: SPACING.lg, width: '100%', paddingHorizontal: SPACING.md },
    metricCard: { flex: 1, backgroundColor: colors.surface, padding: SPACING.lg, borderRadius: BORDER_RADIUS.xl, alignItems: 'center', ...SHADOWS.sm },
    heartContainer: { height: 60, justifyContent: 'center', alignItems: 'center', marginBottom: SPACING.sm },
    iconContainer: { height: 60, justifyContent: 'center', alignItems: 'center', marginBottom: SPACING.sm },
    metricValue: { ...TYPOGRAPHY.h2, color: colors.text },
    metricUnit: { ...TYPOGRAPHY.body, color: colors.textSecondary },
    metricLabel: { ...TYPOGRAPHY.caption, color: colors.textTertiary, marginTop: 4 },
    controls: { paddingHorizontal: SPACING.xl, gap: SPACING.lg },
    playPauseBtn: { width: 80, height: 80, borderRadius: 40, backgroundColor: colors.warning, justifyContent: 'center', alignItems: 'center', alignSelf: 'center', marginBottom: SPACING.md },
    finishBtn: { backgroundColor: colors.error }
});

import React, { useState, useEffect } from 'react';
import { View, Text, StyleSheet, ScrollView, ActivityIndicator, TouchableOpacity, Modal, TextInput } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import { SupabaseService } from '../services/supabase';
import { NotificationService } from '../services/notificationService';
import { useTranslation } from '../hooks/useTranslation';
import GlassCard from '../components/GlassCard';
import { COLORS, GRADIENTS, TYPOGRAPHY, SPACING, BORDER_RADIUS, SHADOWS } from '../config/theme';
import { useTheme } from '../contexts/ThemeContext';
import { safeGoBack } from '../utils/navigation';

export default function AssignmentsScreen({ navigation, route }: any) {
    const { colors, isDark } = useTheme();
    const styles = React.useMemo(() => getStyles(colors), [colors]);

    const { t, isTurkish, language } = useTranslation();
    const insets = useSafeAreaInsets();
    const [loading, setLoading] = useState(true);
    const [workouts, setWorkouts] = useState<any[]>([]);
    const [nutrition, setNutrition] = useState<any[]>([]);
    const [supplements, setSupplements] = useState<any[]>([]);
    const [activeTab, setActiveTab] = useState<'workout' | 'nutrition' | 'supplement'>('workout');
    const [feedbackVisible, setFeedbackVisible] = useState(false);
    const [selectedWorkout, setSelectedWorkout] = useState<any | null>(null);
    const [weeklyAction, setWeeklyAction] = useState<'increase' | 'decrease' | 'stable'>('stable');
    const [feedbackNotes, setFeedbackNotes] = useState('');
    const [exerciseFeedback, setExerciseFeedback] = useState<Array<{ name: string; sets: string; reps: string; weight: string; action: 'increase' | 'decrease' | 'stable' }>>([]);
    const locale = isTurkish ? 'tr-TR' : 'en-US';

    useEffect(() => {
        if (route.params?.tab) {
            setActiveTab(route.params.tab);
        }
    }, [route.params]);

    const formatDate = (value?: string) => {
        if (!value) return t('no_date');
        const parsed = new Date(value);
        if (Number.isNaN(parsed.getTime())) return t('invalid_date');
        return parsed.toLocaleDateString(locale);
    };

    const completedWorkouts = workouts.filter(item => item.is_completed).length;
    const workoutCompletionRate = workouts.length > 0 ? Math.round((completedWorkouts / workouts.length) * 100) : 0;
    const activeNutritionPlans = nutrition.filter(item => item.is_active !== false).length;

    useEffect(() => {
        loadAssignments();
    }, []);

    const loadAssignments = async () => {
        try {
            setLoading(true);
            const supabase = SupabaseService.getInstance();
            const { user } = await supabase.getCurrentUser();
            if (!user) return;

            const [workoutRes, nutritionRes, suppRes] = await Promise.all([
                supabase.getAssignedWorkouts(user.id),
                supabase.getAssignedNutritionPlans(user.id),
                supabase.getAssignedSupplements(user.id).catch(() => ({ data: [] }))
            ]);

            if (workoutRes.data) setWorkouts(workoutRes.data);
            if (nutritionRes.data) setNutrition(nutritionRes.data);
            if (suppRes?.data) {
                setSupplements(suppRes.data);
                setupReminders(suppRes.data);
            }
        } catch (error) {
            console.error('Error loading assignments:', error);
        } finally {
            setLoading(false);
        }
    };

    const setupReminders = async (data: any[]) => {
        const notifService = NotificationService.getInstance();
        const hasPermission = await notifService.requestPermissions();
        if (!hasPermission) return;

        for (const item of data) {
            if (item.reminder_time) {
                // Handle both array (text[]) and string formats
                const times = Array.isArray(item.reminder_time) ? item.reminder_time : [item.reminder_time];
                
                for (const timeStr of times) {
                    if (typeof timeStr === 'string' && timeStr.includes(':')) {
                        const [h, m] = timeStr.split(':');
                        if (h && m) {
                            await notifService.scheduleSmartReminder(
                                'supplement',
                                parseInt(h),
                                parseInt(m),
                                `supp_reminder_${item.id}_${h}${m}`,
                                'Assignments',
                                { screen: 'Assignments', params: { tab: 'supplement' } },
                                language,
                                { name: item.title || item.name }
                            );
                        }
                    }
                }
            }
        }
    };

    const openWorkoutFeedback = (workout: any) => {
        const exercises = Array.isArray(workout?.exercises) && workout.exercises.length > 0
            ? workout.exercises
            : [{ name: isTurkish ? 'Genel Antrenman' : 'General Workout', sets: '', reps: '', weight: '' }];
        const normalized = exercises.map((exercise: any, index: number) => ({
            name: exercise?.name || exercise?.exercise_name || `${isTurkish ? 'Hareket' : 'Exercise'} ${index + 1}`,
            sets: exercise?.sets ? String(exercise.sets) : '',
            reps: exercise?.reps ? String(exercise.reps) : '',
            weight: exercise?.weight ? String(exercise.weight) : '',
            action: 'stable' as const,
        }));
        setSelectedWorkout(workout);
        setExerciseFeedback(normalized);
        setWeeklyAction('stable');
        setFeedbackNotes('');
        setFeedbackVisible(true);
    };

    const updateExerciseField = (index: number, field: 'sets' | 'reps' | 'weight' | 'action', value: string) => {
        setExerciseFeedback((prev) => prev.map((row, rowIndex) => (
            rowIndex === index
                ? { ...row, [field]: value }
                : row
        )));
    };

    const handleCompleteWorkout = async (id: string, feedbackPayload?: any) => {
        try {
            const supabase = SupabaseService.getInstance();
            await supabase.completeWorkout(
                id,
                feedbackPayload ? JSON.stringify(feedbackPayload) : 'Completed from mobile app'
            );
            // Refresh
            loadAssignments();
        } catch (e) {
            console.error('Error completing workout', e);
        }
    };

    const submitWorkoutFeedback = async () => {
        if (!selectedWorkout?.id) return;
        const payload = {
            weeklyAction,
            notes: feedbackNotes.trim(),
            exerciseFeedback,
            submittedAt: new Date().toISOString(),
            weeklyAutoUpdate: true,
        };
        await handleCompleteWorkout(selectedWorkout.id, payload);
        setFeedbackVisible(false);
        setSelectedWorkout(null);
    };

    return (
        <View style={[styles.container, { paddingBottom: insets.bottom }]}>
            <LinearGradient colors={GRADIENTS.primary as any} style={[styles.header, { paddingTop: insets.top + 16 }]}>
                <TouchableOpacity onPress={() => safeGoBack(navigation, 'Profile')} style={styles.backBtn}>
                    <Ionicons name="arrow-back" size={24} color="#fff" />
                </TouchableOpacity>
                <Text style={styles.headerTitle}>{t('my_assignments')}</Text>
                <View style={{ width: 40 }} />
            </LinearGradient>

            <View style={styles.tabContainer}>
                <TouchableOpacity
                    style={[styles.tab, activeTab === 'workout' && styles.activeTab]}
                    onPress={() => setActiveTab('workout')}
                >
                    <Text style={[styles.tabText, activeTab === 'workout' && styles.activeTabText]}>
                        {t('workout')}
                    </Text>
                </TouchableOpacity>
                <TouchableOpacity
                    style={[styles.tab, activeTab === 'nutrition' && styles.activeTab]}
                    onPress={() => setActiveTab('nutrition')}
                >
                    <Text style={[styles.tabText, activeTab === 'nutrition' && styles.activeTabText]}>
                        {t('nutrition')}
                    </Text>
                </TouchableOpacity>
                <TouchableOpacity
                    style={[styles.tab, activeTab === 'supplement' && styles.activeTab]}
                    onPress={() => setActiveTab('supplement')}
                >
                    <Text style={[styles.tabText, activeTab === 'supplement' && styles.activeTabText]}>
                        {t('supplements')}
                    </Text>
                </TouchableOpacity>
            </View>

            {loading ? (
                <View style={styles.center}>
                    <ActivityIndicator size="large" color={colors.primary} />
                </View>
            ) : (
                <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
                    <View style={styles.summaryRow}>
                        <View style={styles.summaryCard}>
                            <Text style={styles.summaryValue}>{workouts.length}</Text>
                            <Text style={styles.summaryLabel}>{t('total_workouts')}</Text>
                        </View>
                        <View style={styles.summaryCard}>
                            <Text style={styles.summaryValue}>{workoutCompletionRate}%</Text>
                            <Text style={styles.summaryLabel}>{t('completion_rate')}</Text>
                        </View>
                        <View style={styles.summaryCard}>
                            <Text style={styles.summaryValue}>{activeNutritionPlans}</Text>
                            <Text style={styles.summaryLabel}>{t('active_nutrition')}</Text>
                        </View>
                    </View>

                    {activeTab === 'workout' ? (
                        workouts.length > 0 ? workouts.map(item => (
                            <GlassCard key={item.id} style={styles.card}>
                                <View style={styles.cardHeader}>
                                    <View>
                                        <Text style={styles.cardTitle}>{item.title}</Text>
                                        <Text style={styles.cardDate}>{formatDate(item.scheduled_date)}</Text>
                                    </View>
                                    {item.is_completed ? (
                                        <View style={styles.badgeSuccess}>
                                            <Ionicons name="checkmark-circle" size={14} color={colors.success} />
                                            <Text style={styles.badgeTextSuccess}>{t('completed')}</Text>
                                        </View>
                                    ) : (
                                        <View style={styles.badgePending}>
                                            <Ionicons name="time-outline" size={14} color={colors.warning} />
                                            <Text style={styles.badgeTextPending}>{t('pending')}</Text>
                                        </View>
                                    )}
                                </View>
                                <Text style={styles.cardDesc}>{item.description || t('no_description')}</Text>
                                <View style={styles.proInfo}>
                                    <Ionicons name="person-circle-outline" size={18} color={colors.textTertiary} />
                                    <Text style={styles.proText}>
                                        {item.pt?.first_name} {item.pt?.last_name}
                                    </Text>
                                </View>
                                {!item.is_completed && (
                                    <TouchableOpacity style={styles.completeBtn} onPress={() => openWorkoutFeedback(item)}>
                                        <Text style={styles.completeBtnText}>{t('mark_complete')}</Text>
                                    </TouchableOpacity>
                                )}
                            </GlassCard>
                        )) : (
                            <Text style={styles.emptyText}>{t('no_workouts_assigned')}</Text>
                        )
                    ) : activeTab === 'nutrition' ? (
                        nutrition.length > 0 ? nutrition.map(item => (
                            <GlassCard key={item.id} style={styles.card}>
                                <Text style={styles.cardTitle}>{item.title}</Text>
                                <Text style={styles.cardDesc}>{formatDate(item.start_date)} - {formatDate(item.end_date)}</Text>

                                <View style={styles.macrosContainer}>
                                    <View style={styles.macroBox}>
                                        <Text style={styles.macroValue}>{item.target_calories || 0}</Text>
                                        <Text style={styles.macroLabel}>{t('calories')}</Text>
                                    </View>
                                    <View style={styles.macroBox}>
                                        <Text style={styles.macroValue}>{item.target_protein || 0}g</Text>
                                        <Text style={styles.macroLabel}>{t('protein')}</Text>
                                    </View>
                                    <View style={styles.macroBox}>
                                        <Text style={styles.macroValue}>{item.target_carbs || 0}g</Text>
                                        <Text style={styles.macroLabel}>{t('carbs')}</Text>
                                    </View>
                                    <View style={styles.macroBox}>
                                        <Text style={styles.macroValue}>{item.target_fats || 0}g</Text>
                                        <Text style={styles.macroLabel}>{t('fat')}</Text>
                                    </View>
                                </View>

                                {item.notes && <Text style={[styles.cardDesc, { marginTop: 8 }]}>{item.notes}</Text>}
                                <View style={[styles.proInfo, { marginTop: 12 }]}>
                                    <Ionicons name="person-circle-outline" size={18} color={colors.textTertiary} />
                                    <Text style={styles.proText}>
                                        {item.dietitian?.first_name} {item.dietitian?.last_name}
                                    </Text>
                                </View>
                            </GlassCard>
                        )) : (
                            <Text style={styles.emptyText}>{t('no_nutrition_assigned')}</Text>
                        )
                    ) : (
                        supplements.length > 0 ? supplements.map(item => (
                            <GlassCard key={item.id} style={styles.card}>
                                <View style={styles.cardHeader}>
                                    <View>
                                        <Text style={styles.cardTitle}>{item.title}</Text>
                                        <Text style={styles.cardDate}>{formatDate(item.created_at)}</Text>
                                    </View>
                                    {item.reminder_time && (
                                        <View style={styles.badgePending}>
                                            <Ionicons name="notifications-outline" size={14} color={colors.warning} />
                                            <Text style={styles.badgeTextPending}>{item.reminder_time}</Text>
                                        </View>
                                    )}
                                </View>
                                <Text style={styles.cardDesc}>
                                    {t('dosage')}: {item.dosage || '-'}
                                </Text>
                                {item.notes && <Text style={[styles.cardDesc, { marginTop: 4 }]}>{item.notes}</Text>}
                                <View style={styles.proInfo}>
                                    <Ionicons name="person-circle-outline" size={18} color={colors.textTertiary} />
                                    <Text style={styles.proText}>
                                        {item.dietitian?.first_name || item.pt?.first_name} {item.dietitian?.last_name || item.pt?.last_name}
                                    </Text>
                                </View>
                            </GlassCard>
                        )) : (
                            <Text style={styles.emptyText}>{t('no_supplements_assigned')}</Text>
                        )
                    )}
                </ScrollView>
            )}

            <Modal visible={feedbackVisible} transparent animationType="slide" onRequestClose={() => setFeedbackVisible(false)}>
                <View style={styles.feedbackOverlay}>
                    <View style={styles.feedbackSheet}>
                        <Text style={styles.feedbackTitle}>{isTurkish ? 'Antrenman Geri Bildirimi' : 'Workout Feedback'}</Text>
                        <Text style={styles.feedbackSubtitle}>
                            {isTurkish ? 'Programı haftalık güncellemek için kısa geri bildirim ver.' : 'Give quick feedback for weekly plan updates.'}
                        </Text>

                        <Text style={styles.feedbackSectionLabel}>{isTurkish ? 'Haftalık genel karar' : 'Weekly overall action'}</Text>
                        <View style={styles.feedbackActionRow}>
                            {[
                                { key: 'increase', label: isTurkish ? 'Artır' : 'Increase' },
                                { key: 'stable', label: isTurkish ? 'Sabit' : 'Stable' },
                                { key: 'decrease', label: isTurkish ? 'Azalt' : 'Decrease' },
                            ].map((opt) => (
                                <TouchableOpacity
                                    key={opt.key}
                                    style={[styles.actionChip, weeklyAction === opt.key && styles.actionChipActive]}
                                    onPress={() => setWeeklyAction(opt.key as 'increase' | 'decrease' | 'stable')}
                                >
                                    <Text style={[styles.actionChipText, weeklyAction === opt.key && styles.actionChipTextActive]}>{opt.label}</Text>
                                </TouchableOpacity>
                            ))}
                        </View>

                        <ScrollView style={styles.feedbackExerciseList} showsVerticalScrollIndicator={false}>
                            {exerciseFeedback.map((exercise, index) => (
                                <View key={`${exercise.name}_${index}`} style={styles.exerciseFeedbackCard}>
                                    <Text style={styles.exerciseFeedbackName}>{exercise.name}</Text>
                                    <View style={styles.exerciseFieldsRow}>
                                        <TextInput
                                            value={exercise.sets}
                                            onChangeText={(value) => updateExerciseField(index, 'sets', value)}
                                            placeholder={isTurkish ? 'Set' : 'Sets'}
                                            keyboardType="number-pad"
                                            style={styles.exerciseInput}
                                        />
                                        <TextInput
                                            value={exercise.reps}
                                            onChangeText={(value) => updateExerciseField(index, 'reps', value)}
                                            placeholder={isTurkish ? 'Tekrar' : 'Reps'}
                                            keyboardType="number-pad"
                                            style={styles.exerciseInput}
                                        />
                                        <TextInput
                                            value={exercise.weight}
                                            onChangeText={(value) => updateExerciseField(index, 'weight', value)}
                                            placeholder={isTurkish ? 'Ağırlık' : 'Weight'}
                                            keyboardType="decimal-pad"
                                            style={styles.exerciseInput}
                                        />
                                    </View>
                                    <View style={styles.feedbackActionRow}>
                                        {[
                                            { key: 'increase', label: isTurkish ? '↑ Artır' : '↑ Increase' },
                                            { key: 'stable', label: isTurkish ? '→ Sabit' : '→ Stable' },
                                            { key: 'decrease', label: isTurkish ? '↓ Azalt' : '↓ Decrease' },
                                        ].map((opt) => (
                                            <TouchableOpacity
                                                key={opt.key}
                                                style={[styles.actionChipSmall, exercise.action === opt.key && styles.actionChipSmallActive]}
                                                onPress={() => updateExerciseField(index, 'action', opt.key)}
                                            >
                                                <Text style={[styles.actionChipSmallText, exercise.action === opt.key && styles.actionChipSmallTextActive]}>{opt.label}</Text>
                                            </TouchableOpacity>
                                        ))}
                                    </View>
                                </View>
                            ))}
                        </ScrollView>

                        <TextInput
                            value={feedbackNotes}
                            onChangeText={setFeedbackNotes}
                            placeholder={isTurkish ? 'Notlar (opsiyonel)' : 'Notes (optional)'}
                            multiline
                            style={styles.feedbackNotesInput}
                        />

                        <View style={styles.feedbackFooter}>
                            <TouchableOpacity style={styles.feedbackCancelBtn} onPress={() => setFeedbackVisible(false)}>
                                <Text style={styles.feedbackCancelText}>{isTurkish ? 'İptal' : 'Cancel'}</Text>
                            </TouchableOpacity>
                            <TouchableOpacity style={styles.feedbackSaveBtn} onPress={submitWorkoutFeedback}>
                                <Text style={styles.feedbackSaveText}>{isTurkish ? 'Bitir ve Kaydet' : 'Finish & Save'}</Text>
                            </TouchableOpacity>
                        </View>
                    </View>
                </View>
            </Modal>
        </View>
    );
}

