    actionChipSmall: { paddingHorizontal: 10, paddingVertical: 6, borderRadius: 10, borderWidth: 1, borderColor: colors.borderLight },
    actionChipSmallActive: { borderColor: colors.primary, backgroundColor: colors.primarySoft },
