                            <Text style={styles.emptySub}>
                                {isTurkish
                                    ? 'Müşteri henüz veri girişi yapmamış.'
                                    : 'Client hasn\'t logged any data yet.'}
                            </Text>
                        </View>
                    )}
                </ScrollView>
            )}
        </View>
    );
}

