              </View>
            ) : (
              <TouchableOpacity onPress={() => setShowWaterSetup(true)} style={styles.waterEmpty}>
                <Ionicons name="water" size={32} color="#1CB0F6" />
                <Text style={styles.waterEmptyText}>{isTurkish ? 'Hedef belirle' : 'Set a goal'}</Text>
              </TouchableOpacity>
