import React, { useEffect, useRef } from 'react';
import {
    View,
    Text,
    StyleSheet,
    Animated,
    Dimensions,
    Easing,
} from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';

const { width, height } = Dimensions.get('window');

const SplashScreen = ({ onFinish }: { onFinish: () => void }) => {
    const logoScale = useRef(new Animated.Value(0.3)).current;
    const logoOpacity = useRef(new Animated.Value(0)).current;
    const taglineOpacity = useRef(new Animated.Value(0)).current;
    const taglineSlide = useRef(new Animated.Value(20)).current;
    const iconRotate = useRef(new Animated.Value(0)).current;
    const iconOpacity = useRef(new Animated.Value(0)).current;
    const barWidth = useRef(new Animated.Value(0)).current;
    const barOpacity = useRef(new Animated.Value(0)).current;
    const pulseAnim = useRef(new Animated.Value(1)).current;
    const glowOpacity = useRef(new Animated.Value(0)).current;

    useEffect(() => {
        // Phase 1: Icon appears with rotation (0-500ms)
        Animated.parallel([
            Animated.timing(iconOpacity, { toValue: 1, duration: 400, useNativeDriver: true }),
            Animated.timing(iconRotate, { toValue: 1, duration: 600, useNativeDriver: true, easing: Easing.out(Easing.back(1.5)) }),
        ]).start();

        // Phase 2: Logo scales in (300-900ms)
        setTimeout(() => {
            Animated.parallel([
                Animated.spring(logoScale, { toValue: 1, friction: 6, tension: 80, useNativeDriver: true }),
                Animated.timing(logoOpacity, { toValue: 1, duration: 500, useNativeDriver: true }),
                Animated.timing(glowOpacity, { toValue: 0.6, duration: 800, useNativeDriver: true }),
            ]).start();
        }, 300);

        // Phase 3: Tagline slides in (800-1200ms)
        setTimeout(() => {
            Animated.parallel([
                Animated.timing(taglineOpacity, { toValue: 1, duration: 400, useNativeDriver: true }),
                Animated.timing(taglineSlide, { toValue: 0, duration: 400, useNativeDriver: true, easing: Easing.out(Easing.cubic) }),
            ]).start();
        }, 800);

        // Phase 4: Loading bar (1000-2200ms)
        setTimeout(() => {
            Animated.timing(barOpacity, { toValue: 1, duration: 200, useNativeDriver: false }).start();
            Animated.timing(barWidth, { toValue: width * 0.5, duration: 1200, useNativeDriver: false, easing: Easing.inOut(Easing.ease) }).start();
        }, 1000);

        // Continuous pulse on glow
        Animated.loop(
            Animated.sequence([
                Animated.timing(pulseAnim, { toValue: 1.08, duration: 1200, useNativeDriver: true, easing: Easing.inOut(Easing.ease) }),
                Animated.timing(pulseAnim, { toValue: 1, duration: 1200, useNativeDriver: true, easing: Easing.inOut(Easing.ease) }),
            ])
        ).start();

        const timer = setTimeout(() => onFinish(), 2500);
        return () => clearTimeout(timer);
    }, []);

    const spin = iconRotate.interpolate({ inputRange: [0, 1], outputRange: ['-180deg', '0deg'] });

    return (
        <LinearGradient colors={['#0F0C29', '#302B63', '#24243E']} style={styles.container}>
            {/* Decorative circles */}
            <Animated.View style={[styles.bgCircle1, { opacity: glowOpacity }]} />
            <Animated.View style={[styles.bgCircle2, { opacity: glowOpacity }]} />

            {/* Icon */}
            <Animated.View style={[styles.iconWrap, { opacity: iconOpacity, transform: [{ rotate: spin }] }]}>
                <LinearGradient colors={['#58CC02', '#38A802']} style={styles.iconGradient}>
                    <Ionicons name="pulse" size={32} color="#FFFFFF" />
                </LinearGradient>
            </Animated.View>

            {/* Logo */}
            <Animated.View style={[styles.logoWrap, { opacity: logoOpacity, transform: [{ scale: Animated.multiply(logoScale, pulseAnim) }] }]}>
                <Text style={styles.logoBio}>Bio</Text>
                <Text style={styles.logoSync}>Sync</Text>
                <Text style={styles.logoDot}>.</Text>
            </Animated.View>

            {/* Tagline */}
            <Animated.View style={{ opacity: taglineOpacity, transform: [{ translateY: taglineSlide }] }}>
                <Text style={styles.tagline}>INTELLIGENT PERFORMANCE</Text>
            </Animated.View>

            {/* Loading bar */}
            <Animated.View style={[styles.barContainer, { opacity: barOpacity }]}>
                <Animated.View style={[styles.barFill, { width: barWidth }]}>
                    <LinearGradient colors={['#58CC02', '#38ef7d']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={styles.barGradient} />
                </Animated.View>
            </Animated.View>
        </LinearGradient>
    );
};

const styles = StyleSheet.create({
    container: {
        flex: 1,
        justifyContent: 'center',
        alignItems: 'center',
    },
    bgCircle1: {
        position: 'absolute',
        width: 300,
        height: 300,
        borderRadius: 150,
        backgroundColor: '#58CC02',
        opacity: 0.05,
        top: height * 0.15,
        left: -80,
    },
    bgCircle2: {
        position: 'absolute',
        width: 200,
        height: 200,
        borderRadius: 100,
        backgroundColor: '#764ba2',
        opacity: 0.08,
        bottom: height * 0.2,
        right: -60,
    },
    iconWrap: {
        marginBottom: 24,
    },
    iconGradient: {
        width: 72,
        height: 72,
        borderRadius: 22,
        justifyContent: 'center',
        alignItems: 'center',
        shadowColor: '#58CC02',
        shadowOpacity: 0.4,
        shadowRadius: 16,
        shadowOffset: { width: 0, height: 6 },
        elevation: 12,
    },
    logoWrap: {
        flexDirection: 'row',
        alignItems: 'baseline',
        marginBottom: 10,
    },
    logoBio: {
        fontSize: width * 0.12,
        fontWeight: '800',
        color: '#FFFFFF',
        letterSpacing: -1,
    },
    logoSync: {
        fontSize: width * 0.12,
        fontWeight: '800',
        color: '#58CC02',
        letterSpacing: -1,
    },
    logoDot: {
        fontSize: width * 0.12,
        fontWeight: '800',
        color: '#58CC02',
    },
    tagline: {
        fontSize: 12,
        fontWeight: '600',
        color: 'rgba(255,255,255,0.45)',
        letterSpacing: 4,
    },
    barContainer: {
        position: 'absolute',
        bottom: height * 0.12,
        width: width * 0.5,
        height: 3,
        backgroundColor: 'rgba(255,255,255,0.1)',
        borderRadius: 2,
        overflow: 'hidden',
    },
    barFill: {
        height: '100%',
        borderRadius: 2,
        overflow: 'hidden',
    },
    barGradient: {
        flex: 1,
    },
});

export default SplashScreen;

import React, { useState, useEffect, useCallback } from 'react';
import { View, Text, ScrollView, StyleSheet, TouchableOpacity, Image, ActivityIndicator } from 'react-native';
import { LinearGradient } from 'expo-linear-gradient';
import { Ionicons } from '@expo/vector-icons';
import { useSafeAreaInsets } from 'react-native-safe-area-context';
import GlassCard from '../components/GlassCard';
import GradientButton from '../components/GradientButton';
import { useTranslation } from '../hooks/useTranslation';
import { COLORS, TYPOGRAPHY, SPACING, BORDER_RADIUS, SHADOWS } from '../config/theme';
import { useTheme } from '../contexts/ThemeContext';
import { safeGoBack } from '../utils/navigation';
import { SpotifyService, SpotifyPlaylist, SpotifyTrack } from '../services/spotifyService';

const SpotifyScreen = ({ navigation }: any) => {
  const { colors, isDark } = useTheme();
  const styles = React.useMemo(() => getStyles(colors), [colors]);
  const insets = useSafeAreaInsets();

  const { isTurkish } = useTranslation();
  const [isConnected, setIsConnected] = useState(false);
  const [loading, setLoading] = useState(true);
  const [playlists, setPlaylists] = useState<SpotifyPlaylist[]>([]);
  const [currentTrack, setCurrentTrack] = useState<SpotifyTrack | null>(null);
  const [isPlaying, setIsPlaying] = useState(false);

  const spotifyService = SpotifyService.getInstance();

  // Check connection status on mount
  useEffect(() => {
    const init = async () => {
      const authenticated = spotifyService.isAuthenticated() || await spotifyService.loadTokenFromSession();
      setIsConnected(authenticated);
      if (authenticated) {
        await loadPlaylists();
        await loadCurrentTrack();
      }
      setLoading(false);
    };
    init();
  }, []);

  const loadPlaylists = useCallback(async () => {
    try {
      const [userPl, workoutPl] = await Promise.allSettled([
        spotifyService.getUserPlaylists(),
        spotifyService.getWorkoutPlaylists(),
      ]);
      const combined: SpotifyPlaylist[] = [];
      if (userPl.status === 'fulfilled') combined.push(...userPl.value);
      if (workoutPl.status === 'fulfilled') combined.push(...workoutPl.value);
      // Deduplicate by id
      const seen = new Set<string>();
      setPlaylists(combined.filter(p => { if (seen.has(p.id)) return false; seen.add(p.id); return true; }));
    } catch (err) {
      console.error('Load playlists error:', err);
    }
  }, []);

  const loadCurrentTrack = useCallback(async () => {
    try {
      const track = await spotifyService.getCurrentlyPlaying();
      if (track) {
        setCurrentTrack(track);
        setIsPlaying(true);
      }
    } catch (err) {
      console.error('Load current track error:', err);
    }
  }, []);

  const handleConnect = async () => {
    setLoading(true);
    const success = await spotifyService.authenticate();
    if (success) {
      setIsConnected(true);
      await loadPlaylists();
      await loadCurrentTrack();
    }
    setLoading(false);
  };

  const handlePlayPlaylist = async (playlist: SpotifyPlaylist) => {
    try {
      await spotifyService.playPlaylist(playlist.uri);
      setIsPlaying(true);
      setTimeout(loadCurrentTrack, 1500);
    } catch (err) {
      console.error('Play playlist error:', err);
    }
  };

  const handlePlayPause = async () => {
    try {
      if (isPlaying) {
        await spotifyService.pausePlayback();
        setIsPlaying(false);
      } else {
        await spotifyService.resumePlayback();
        setIsPlaying(true);
      }
    } catch (err) {
      console.error('Play/pause error:', err);
    }
  };

  const handleNext = async () => {
    try {
      await spotifyService.skipToNext();
      setTimeout(loadCurrentTrack, 1000);
    } catch (err) {
      console.error('Skip error:', err);
    }
  };

  const handlePrev = async () => {
    try {
      await spotifyService.skipToPrevious();
      setTimeout(loadCurrentTrack, 1000);
    } catch (err) {
      console.error('Skip error:', err);
    }
  };

  if (loading) {
    return (
      <View style={[styles.container, { justifyContent: 'center', alignItems: 'center' }]}>
        <ActivityIndicator size="large" color="#1DB954" />
      </View>
    );
  }

  return (
    <View style={[styles.container, { backgroundColor: colors.background }]}>
      <LinearGradient colors={['#1DB954', '#1ED760']} start={{ x: 0, y: 0 }} end={{ x: 1, y: 0 }} style={[styles.header, { paddingTop: insets.top + SPACING.xl }]}>
        <View style={styles.headerRow}>
          <TouchableOpacity onPress={() => safeGoBack(navigation, 'Workout')} style={{ marginRight: SPACING.sm }}>
            <Ionicons name="arrow-back" size={24} color={colors.textInverse} />
          </TouchableOpacity>
          <Ionicons name="musical-notes" size={32} color={colors.textInverse} />
          <View style={{ flex: 1, marginLeft: SPACING.md }}>
            <Text style={styles.headerTitle}>Spotify</Text>
            <Text style={styles.headerSub}>{isTurkish ? 'Antrenman müzikleri' : 'Workout music'}</Text>
          </View>
        </View>
      </LinearGradient>

      <ScrollView contentContainerStyle={styles.content} showsVerticalScrollIndicator={false}>
        {!isConnected ? (
          <GlassCard elevated style={styles.connectCard}>
            <View style={styles.connectIcon}>
              <Ionicons name="musical-notes" size={48} color="#1DB954" />
            </View>
            <Text style={styles.connectTitle}>
              {isTurkish ? 'Spotify\'a bağlanın' : 'Connect to Spotify'}
            </Text>
            <Text style={styles.connectDesc}>
              {isTurkish ? 'Antrenmanlarınız sırasında müzik dinleyin' : 'Listen to music during your workouts'}
            </Text>
            <GradientButton
              title={isTurkish ? 'Bağlan' : 'Connect'}
              onPress={handleConnect}
              gradient={['#1DB954', '#1ED760']}
              size="lg"
              style={{ marginTop: SPACING.xl }}
            />
          </GlassCard>
        ) : (
          <>
            {/* Now Playing */}
            {currentTrack && (
              <GlassCard elevated style={styles.nowPlayingCard}>
                <Text style={styles.nowPlayingLabel}>
                  {isTurkish ? 'Şimdi Çalıyor' : 'Now Playing'}
                </Text>
                <View style={styles.nowPlayingRow}>
                  {currentTrack.imageUrl ? (
                    <Image source={{ uri: currentTrack.imageUrl }} style={styles.nowPlayingArt} />
                  ) : (
                    <View style={[styles.nowPlayingArt, { backgroundColor: colors.surfaceElevated, justifyContent: 'center', alignItems: 'center' }]}>
                      <Ionicons name="musical-note" size={24} color={colors.textSecondary} />
                    </View>
                  )}
                  <View style={{ flex: 1, marginLeft: SPACING.md }}>
                    <Text style={styles.nowPlayingTrack} numberOfLines={1}>{currentTrack.name}</Text>
                    <Text style={styles.nowPlayingArtist} numberOfLines={1}>{currentTrack.artist}</Text>
                  </View>
                </View>
                <View style={styles.controlsRow}>
                  <TouchableOpacity onPress={handlePrev} style={styles.controlBtn}>
                    <Ionicons name="play-skip-back" size={24} color={colors.text} />
                  </TouchableOpacity>
                  <TouchableOpacity onPress={handlePlayPause} style={styles.playPauseBtn}>
                    <Ionicons name={isPlaying ? 'pause' : 'play'} size={28} color="#fff" />
                  </TouchableOpacity>
                  <TouchableOpacity onPress={handleNext} style={styles.controlBtn}>
                    <Ionicons name="play-skip-forward" size={24} color={colors.text} />
                  </TouchableOpacity>
                </View>
              </GlassCard>
            )}

            <Text style={styles.sectionTitle}>{isTurkish ? 'Çalma Listeleri' : 'Playlists'}</Text>
            {playlists.map((playlist) => (
              <GlassCard key={playlist.id} style={styles.playlistCard}>
                <View style={styles.playlistRow}>
                  {playlist.imageUrl ? (
                    <Image source={{ uri: playlist.imageUrl }} style={styles.playlistImage} />
                  ) : (
                    <View style={[styles.playlistIcon, { backgroundColor: '#1DB95415' }]}>
                      <Ionicons name="musical-notes" size={24} color="#1DB954" />
                    </View>
                  )}
                  <View style={styles.playlistInfo}>
                    <Text style={styles.playlistName} numberOfLines={1}>{playlist.name}</Text>
                    {playlist.description ? (
                      <Text style={styles.playlistMeta} numberOfLines={1}>{playlist.description}</Text>
                    ) : null}
                  </View>
                  <TouchableOpacity style={styles.playButton} onPress={() => handlePlayPlaylist(playlist)}>
                    <Ionicons name="play-circle" size={36} color="#1DB954" />
                  </TouchableOpacity>
                </View>
              </GlassCard>
            ))}
          </>
        )}
      </ScrollView>
    </View>
  );
};

