const TermsScreen = ({ navigation, route }: any) => {
    const { colors, isDark } = useTheme();
    const styles = React.useMemo(() => getStyles(colors), [colors]);

    const { isTurkish } = useTranslation();
    const insets = useSafeAreaInsets();
    const section = route.params?.section || 'terms';
    const fromAuth = route.params?.fromAuth || false;
    const userId = route.params?.userId;

    const fadeAnim = useRef(new Animated.Value(0)).current;
    const [accepted, setAccepted] = useState<boolean | null>(null);
    const [accepting, setAccepting] = useState(false);
    const [allAccepted, setAllAccepted] = useState(false);

    useEffect(() => {
        Animated.timing(fadeAnim, { toValue: 1, duration: 400, useNativeDriver: true }).start();
        checkAcceptance();
    }, []);

    const checkAcceptance = async () => {
        try {
            const { user } = await SupabaseService.getInstance().getCurrentUser();
            const currentUserId = userId || user?.id;
            if (currentUserId) {
                const agreementService = AgreementService.getInstance();
                if (fromAuth) {
                    // Check all agreements when coming from auth
                    const { allAccepted: all } = await agreementService.hasAcceptedAll(currentUserId);
                    setAllAccepted(all);
                    setAccepted(all);
                } else {
                    const isAccepted = await agreementService.hasAccepted(currentUserId, section as AgreementType);
                    setAccepted(isAccepted);
                }
            }
        } catch {
            setAccepted(false);
            setAllAccepted(false);
        }
    };

