                        >
                            <View style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between' }}>
                                <View style={{ flexDirection: 'row', alignItems: 'center', flex: 1 }}>
                                    <Ionicons name="lock-closed" size={24} color={colors.accent} style={{ marginRight: 12 }} />
                                    <Text style={styles.contentText}>
                                        {isTurkish ? 'Gizlilik Politikası' : 'Privacy Policy'}
                                    </Text>
                                </View>
                                <Ionicons name="chevron-forward" size={20} color={colors.textTertiary} />
                            </View>
                        </TouchableOpacity>

                        {/* Terms */}
                        <TouchableOpacity
                            style={[styles.card, { marginBottom: 12 }]}
                            onPress={() => navigation.navigate('Terms', { section: 'terms' })}
                        >
                            <View style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between' }}>
                                <View style={{ flexDirection: 'row', alignItems: 'center', flex: 1 }}>
                                    <Ionicons name="receipt" size={24} color={colors.warning} style={{ marginRight: 12 }} />
                                    <Text style={styles.contentText}>
                                        {isTurkish ? 'Kullanım Koşulları' : 'Terms of Service'}
                                    </Text>
                                </View>
                                <Ionicons name="chevron-forward" size={20} color={colors.textTertiary} />
                            </View>
                        </TouchableOpacity>

                        {/* Subscription */}
                        <TouchableOpacity
                            style={[styles.card, { marginBottom: 24 }]}
                            onPress={() => navigation.navigate('Terms', { section: 'subscription' })}
                        >
                            <View style={{ flexDirection: 'row', alignItems: 'center', justifyContent: 'space-between' }}>
                                <View style={{ flexDirection: 'row', alignItems: 'center', flex: 1 }}>
                                    <Ionicons name="card" size={24} color={colors.orange} style={{ marginRight: 12 }} />
                                    <Text style={styles.contentText}>
                                        {isTurkish ? 'Abonelik ve İade Politikası' : 'Subscription & Refund Policy'}
                                    </Text>
                                </View>
                                <Ionicons name="chevron-forward" size={20} color={colors.textTertiary} />
                            </View>
                        </TouchableOpacity>

                        <View style={{ height: 120 }} />
                    </ScrollView>
                </Animated.View>

                {/* Accept All Button */}
                <View style={[styles.bottomBar, { paddingBottom: insets.bottom > 0 ? insets.bottom : 20 }]}>
                    <TouchableOpacity
                        style={styles.acceptButton}
                        onPress={handleAccept}
                        disabled={accepting}
                        activeOpacity={0.8}
                    >
                        <LinearGradient
                            colors={GRADIENTS.primary as any}
                            style={styles.acceptGradient}
                            start={{ x: 0, y: 0 }}
                            end={{ x: 1, y: 0 }}
                        >
                            {accepting ? (
                                <ActivityIndicator color="#fff" size="small" />
                            ) : (
                                <>
                                    <Ionicons name="checkmark-circle" size={20} color="#fff" />
                                    <Text style={styles.acceptText}>
                                        {isTurkish ? 'Tümünü Okudum ve Kabul Ediyorum' : 'I Have Read and Accept All'}
                                    </Text>
                                </>
                            )}
                        </LinearGradient>
                    </TouchableOpacity>
                </View>
            </View>
        );
    }

    return (
        <View style={styles.container}>
            <LinearGradient
                colors={GRADIENTS.primary as any}
                style={[styles.header, { paddingTop: insets.top + 12 }]}
                start={{ x: 0, y: 0 }}
                end={{ x: 1, y: 0 }}
            >
                <TouchableOpacity onPress={() => safeGoBack(navigation, 'Settings')} style={styles.backBtn} activeOpacity={0.7}>
                    <Ionicons name="arrow-back" size={24} color="#fff" />
                </TouchableOpacity>
