            </Animated.View>

            {/* Accept Button */}
            {accepted === false && (
                <View style={[styles.bottomBar, { paddingBottom: insets.bottom > 0 ? insets.bottom : 20 }]}>
                    <TouchableOpacity
                        style={styles.acceptButton}
                        onPress={handleAccept}
