     * Get category by ID
     */
    static async getCategory(categoryId: string): Promise<ForumCategory | null> {
        try {
            const { data, error } = await supabase
                .from('forum_categories')
                .select('*')
                .eq('id', categoryId)
                .single();

            if (error) throw error;
            return data;
        } catch (error) {
            console.error('Error getting category:', error);
            return null;
        }
