        try {
            const offset = (page - 1) * pageSize;

            const { data, error, count } = await supabase
                .from('forum_posts')
                .select('*', { count: 'exact' })
                .eq('topic_id', topicId)
                .order('created_at', { ascending: true })
                .range(offset, offset + pageSize - 1);

            if (error) throw error;
            return { posts: data || [], total: count || 0 };
