    /**
     * Add post to topic
     */
    static async addPost(
        topicId: string,
        content: string,
        authorId: string,
        parentPostId?: string
    ): Promise<ForumPost | null> {
        try {
            // Get author profile
            const { data: authorProfile, error: authorError } = await supabase
                .from('profiles')
                .select('username, avatar_url')
                .eq('id', authorId)
                .single();

            if (authorError) throw authorError;

            // Get topic to update last reply info
            const topic = await this.getTopic(topicId);
            if (!topic) return null;

            const { data, error } = await supabase
                .from('forum_posts')
                .insert({
                    topic_id: topicId,
                    content,
                    author_id: authorId,
                    author_name: authorProfile.username,
                    author_avatar: authorProfile.avatar_url,
                    likes_count: 0,
                    is_solution: false,
                    parent_post_id: parentPostId,
                    mentions: this.extractMentions(content)
                })
                .select()
                .single();

            if (error) throw error;

            // Update topic reply count and last reply info
            await supabase
                .from('forum_topics')
                .update({
                    replies_count: topic.replies_count + 1,
                    last_reply_at: new Date().toISOString(),
                    last_reply_by: authorId,
                    last_reply_by_name: authorProfile.username,
                    updated_at: new Date().toISOString()
                })
                .eq('id', topicId);

            // Update category stats
            await this.updateCategoryStats(topic.category_id);

            // Send notifications to mentioned users
            await this.notifyMentionedUsers(data.mentions, topicId, data.id, authorId);

            return data;
        } catch (error) {
            console.error('Error adding post:', error);
            return null;
        }
    }

