    /**
     * Like a topic
     */
    static async likeTopic(userId: string, topicId: string): Promise<boolean> {
        try {
            // Check if already liked
            const { data: existingLike, error: checkError } = await supabase
                .from('topic_likes')
                .select('id')
                .eq('user_id', userId)
                .eq('topic_id', topicId)
                .single();

            if (checkError && checkError.code === 'PGRST116') {
                // No existing like found (PGRST116 = no rows), add like
                const { error: insertError } = await supabase
                    .from('topic_likes')
                    .insert({
                        user_id: userId,
                        topic_id: topicId
                    });

                if (insertError) throw insertError;

                // Increment likes count
                await this.incrementTopicLikes(topicId);
            } else if (!checkError && existingLike) {
                // Already liked, unlike
                const { error: deleteError } = await supabase
                    .from('topic_likes')
                    .delete()
                    .eq('user_id', userId)
                    .eq('topic_id', topicId);

                if (deleteError) throw deleteError;

                // Decrement likes count
                await this.decrementTopicLikes(topicId);
            } else if (checkError) {
                throw checkError;
            }

            return true;
        } catch (error) {
            console.error('Error liking topic:', error);
            return false;
        }
    }

