    }

    // Helper to map DB snake_case to CamelCase
    private mapWeeklyMission(m: any): WeeklyMission {
        return {
            id: m.id,
            title: m.title,
            titleTr: m.title_tr,
            description: m.description,
            descriptionTr: m.description_tr,
