    /**
     * Update subscription plan
     */
    public async updateSubscriptionPlan(
        userId: string,
        newPlanId: string,
        prorate: boolean = true
    ): Promise<boolean> {
        try {
            const subscription = await this.getUserSubscription(userId);
            if (!subscription) {
                throw new Error('No active subscription found');
            }

            const newPlan = await this.getSubscriptionPlan(newPlanId);
            if (!newPlan) {
                throw new Error('New plan not found');
            }

            // Calculate prorated amount if needed
            let proratedAmount = 0;
            if (prorate) {
                proratedAmount = await this.calculateProratedAmount(
                    subscription,
                    newPlan,
                    subscription.billing_cycle
                );
            }

            // Update subscription
            const { error } = await supabase
                .from('user_subscriptions')
                .update({
                    plan_id: newPlanId,
                    updated_at: new Date().toISOString()
                })
                .eq('id', subscription.id);

            if (error) throw error;

            // Create invoice for prorated amount if applicable
            if (proratedAmount > 0) {
                await this.createInvoice(
                    userId,
                    subscription.id,
                    proratedAmount,
                    newPlan.currency,
                    'Prorated plan upgrade'
                );
            }

            return true;
        } catch (error) {
            console.error('Error updating subscription plan:', error);
            return false;
        }
    }

