    private static calculateDailyMetrics(
        healthData: any[],
        workoutData: any[],
        nutritionData: any[],
        sleepData: any[]
    ): ProgressMetric[] {
        // Simplified implementation
        const metrics: ProgressMetric[] = [];

        // Calculate steps
        const totalSteps = healthData
            .filter(d => d.metric === 'steps')
            .reduce((sum, d) => sum + this.toFiniteNumber(d.value), 0);
        metrics.push({
            name: 'Steps',
            value: totalSteps,
            unit: 'steps',
            change_percentage: 0,
            trend: totalSteps > 10000 ? 'up' : totalSteps < 5000 ? 'down' : 'stable',
            target_value: 10000,
            progress_percentage: Math.min(100, (totalSteps / 10000) * 100)
        });

        // Calculate workout minutes
        const workoutMinutes = workoutData.reduce((sum, session) => {
            const start = new Date(session.start_time);
            const end = new Date(session.end_time);
            const duration = Math.round((end.getTime() - start.getTime()) / (1000 * 60));
            return sum + Math.max(0, this.toFiniteNumber(duration));
        }, 0);
        metrics.push({
            name: 'Workout Time',
            value: workoutMinutes,
            unit: 'minutes',
            change_percentage: 0,
            trend: workoutMinutes > 30 ? 'up' : 'down',
            target_value: 30,
            progress_percentage: Math.min(100, (workoutMinutes / 30) * 100)
        });

        // Calculate calories
        const totalCalories = nutritionData.reduce((sum, log) => sum + this.toFiniteNumber(log.calories), 0);
        metrics.push({
            name: 'Calories',
            value: totalCalories,
            unit: 'kcal',
            change_percentage: 0,
            trend: 'stable',
            target_value: 2000,
            progress_percentage: Math.min(100, (totalCalories / 2000) * 100)
        });

        // Calculate sleep hours
        const sleepHours = sleepData.reduce((sum, sleep) => {
            const duration = this.toFiniteNumber(sleep.duration_minutes);
            return sum + duration / 60;
        }, 0);
        metrics.push({
            name: 'Sleep',
            value: sleepHours,
            unit: 'hours',
            change_percentage: 0,
            trend: sleepHours >= 7 ? 'up' : sleepHours < 6 ? 'down' : 'stable',
            target_value: 7,
            progress_percentage: Math.min(100, (sleepHours / 7) * 100)
        });

        return metrics;
    }

    private static calculateWeeklyMetrics(
        dailyReports: ProgressReport[],
        healthData: any[],
        workoutData: any[],
        nutritionData: any[]
    ): ProgressMetric[] {
        // Simplified implementation - average of daily metrics
        if (dailyReports.length === 0) {
            return this.calculateDailyMetrics(healthData, workoutData, nutritionData, []);
        }

        const weeklyMetrics: ProgressMetric[] = [];
        const metricNames = ['Steps', 'Workout Time', 'Calories', 'Sleep'];
        const reportMetricMaps = dailyReports.map(report => {
            const metricByName = new Map<string, number>();
            report.metrics.forEach(metric => metricByName.set(metric.name, this.toFiniteNumber(metric.value)));
            return metricByName;
        });

        for (const metricName of metricNames) {
            const dailyValues = reportMetricMaps.map(metricMap => metricMap.get(metricName) || 0);

            const divisor = Math.max(1, dailyValues.length);
            const avgValue = dailyValues.reduce((sum, val) => sum + val, 0) / divisor;
            const firstValue = dailyValues[0] || 0;
            const lastValue = dailyValues[dailyValues.length - 1] || 0;
            const changePercentage = firstValue > 0 ? ((lastValue - firstValue) / firstValue) * 100 : 0;

            weeklyMetrics.push({
                name: metricName,
                value: Math.round(avgValue),
                unit: metricName === 'Sleep' ? 'hours' : metricName === 'Calories' ? 'kcal' : metricName === 'Workout Time' ? 'minutes' : 'steps',
                change_percentage: Math.round(changePercentage * 100) / 100,
                trend: changePercentage > 5 ? 'up' : changePercentage < -5 ? 'down' : 'stable',
                target_value: metricName === 'Steps' ? 70000 : metricName === 'Workout Time' ? 210 : metricName === 'Calories' ? 14000 : 49,
                progress_percentage: 0 // Would need target values
            });
        }

        return weeklyMetrics;
    }

    private static calculateMonthlyMetrics(
        weeklyReports: ProgressReport[],
        healthData: any[],
        workoutData: any[],
        nutritionData: any[]
    ): ProgressMetric[] {
        // Simplified implementation - sum of weekly metrics
        if (weeklyReports.length === 0) {
            return this.calculateWeeklyMetrics([], healthData, workoutData, nutritionData);
        }

        const monthlyMetrics: ProgressMetric[] = [];
        const metricNames = ['Steps', 'Workout Time', 'Calories', 'Sleep'];
        const reportMetricMaps = weeklyReports.map(report => {
            const metricByName = new Map<string, number>();
            report.metrics.forEach(metric => metricByName.set(metric.name, this.toFiniteNumber(metric.value)));
            return metricByName;
        });

        for (const metricName of metricNames) {
            const weeklyValues = reportMetricMaps.map(metricMap => metricMap.get(metricName) || 0);

            const totalValue = weeklyValues.reduce((sum, val) => sum + val, 0);
            const firstValue = weeklyValues[0] || 0;
            const lastValue = weeklyValues[weeklyValues.length - 1] || 0;
            const changePercentage = firstValue > 0 ? ((lastValue - firstValue) / firstValue) * 100 : 0;

            monthlyMetrics.push({
                name: metricName,
                value: Math.round(totalValue),
                unit: metricName === 'Sleep' ? 'hours' : metricName === 'Calories' ? 'kcal' : metricName === 'Workout Time' ? 'minutes' : 'steps',
                change_percentage: Math.round(changePercentage * 100) / 100,
                trend: changePercentage > 5 ? 'up' : changePercentage < -5 ? 'down' : 'stable',
                target_value: metricName === 'Steps' ? 300000 : metricName === 'Workout Time' ? 900 : metricName === 'Calories' ? 60000 : 210,
                progress_percentage: 0 // Would need target values
            });
        }

        return monthlyMetrics;
    }

