import { Platform } from 'react-native';
import { SupabaseService } from './supabase';
import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';
import Constants from 'expo-constants';
import { translations, TranslationKey } from '../locales/i18n';
import PlatformStorage from '../utils/platformStorage';

const supabase = SupabaseService.getInstance().getClient();

export interface Notification {
    id: string;
    user_id: string;
    title: string;
    body: string;
    data?: any;
    type: 'reminder' | 'achievement' | 'social' | 'system' | 'promotional';
    priority: 'low' | 'normal' | 'high';
    read: boolean;
    action_url?: string;
    sent_at: string;
    created_at: string;
}

export interface NotificationPreferences {
    user_id: string;
    enabled: boolean;
    reminder_notifications: boolean;
    achievement_notifications: boolean;
    social_notifications: boolean;
    system_notifications: boolean;
    promotional_notifications: boolean;
    quiet_hours_start?: string;
    quiet_hours_end?: string;
    daily_summary_time?: string;
    weekly_report_day?: number;
    weekly_report_time?: string;
    updated_at: string;
}

export class PushNotificationService {
    private static instance: PushNotificationService;
    private expoPushToken: string | null = null;
    private notificationListener: Notifications.Subscription | null = null;
    private responseListener: Notifications.Subscription | null = null;

    private constructor() {
        this.init();
    }

    public static getInstance(): PushNotificationService {
        if (!PushNotificationService.instance) {
            PushNotificationService.instance = new PushNotificationService();
        }
        return PushNotificationService.instance;
    }

    private async init() {
        try {
            await this.registerForPushNotifications();
            await this.setupNotificationHandlers();
        } catch (error) {
            console.error('Error initializing push notifications:', error);
        }
    }

    private async registerForPushNotifications(): Promise<void> {
        try {
            // Expo Go no longer supports push notifications in SDK 53+
            if (Constants.appOwnership === 'expo') {
                console.log('Push notifications are not supported in Expo Go.');
                return;
            }

            if (!Device.isDevice) {
                console.log('Must use physical device for push notifications');
                return;
            }

            const { status: existingStatus } = await Notifications.getPermissionsAsync();
            let finalStatus = existingStatus;

            if (existingStatus !== 'granted') {
                const { status } = await Notifications.requestPermissionsAsync();
                finalStatus = status;
            }

            if (finalStatus !== 'granted') {
                console.log('Failed to get push token for push notification!');
                return;
            }

            const token = (await Notifications.getExpoPushTokenAsync()).data;
            this.expoPushToken = token;
            console.log('Expo push token received');

            if (Platform.OS === 'android') {
                await Notifications.setNotificationChannelAsync('default', {
                    name: 'Default',
                    importance: Notifications.AndroidImportance.DEFAULT,
                    vibrationPattern: [0, 250, 250, 250],
                    lightColor: '#FF231F7C',
                });
                await Notifications.setNotificationChannelAsync('workout', {
                    name: 'Workouts',
                    importance: Notifications.AndroidImportance.HIGH,
                    sound: 'default',
                    vibrationPattern: [0, 500, 200, 500],
                });
                await Notifications.setNotificationChannelAsync('nutrition', {
                    name: 'Nutrition',
                    importance: Notifications.AndroidImportance.DEFAULT,
                    sound: 'default',
                });
                await Notifications.setNotificationChannelAsync('supplement', {
                    name: 'Supplements',
                    importance: Notifications.AndroidImportance.HIGH,
                    sound: 'default',
                });
            }
        } catch (error) {
            console.error('Error registering for push notifications:', error);
        }
    }

    /**
     * Setup notification handlers
     */
    private async setupNotificationHandlers(): Promise<void> {
        try {
            // Clean up existing listeners before adding new ones to prevent accumulation
            if (this.notificationListener) {
                this.notificationListener.remove();
                this.notificationListener = null;
            }
            if (this.responseListener) {
                this.responseListener.remove();
                this.responseListener = null;
            }

            // Handle notifications received while app is foregrounded
            this.notificationListener = Notifications.addNotificationReceivedListener(notification => {
                console.log('Notification received');
                this.handleNotification(notification);
            });

            // Handle user tapping on notification
            this.responseListener = Notifications.addNotificationResponseReceivedListener(response => {
                console.log('Notification response received');
                this.handleNotificationResponse(response);
            });

            // Configure notification behavior
            await Notifications.setNotificationHandler({
                handleNotification: async () => ({
                    shouldShowAlert: true,
                    shouldPlaySound: true,
                    shouldSetBadge: true,
                    shouldShowBanner: true,
                    shouldShowList: true,
                }),
            });
        } catch (error) {
            console.error('Error setting up notification handlers:', error);
        }
    }

    /**
     * Save user's push token to database
     */
    public async savePushToken(userId: string): Promise<boolean> {
        try {
            if (!this.expoPushToken) {
                console.log('No push token available');
                return false;
            }

            const { error } = await supabase
                .from('user_push_tokens')
                .upsert({
                    user_id: userId,
                    expo_push_token: this.expoPushToken,
                    platform: Platform.OS,
                    device_model: Device.modelName,
                    updated_at: new Date().toISOString()
                }, {
                    onConflict: 'user_id'
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error saving push token:', error);
            return false;
        }
    }

    /**
     * Get user's notification preferences
     */
    public async getNotificationPreferences(userId: string): Promise<NotificationPreferences | null> {
        try {
            const { data, error } = await supabase
                .from('notification_preferences')
                .select('*')
                .eq('user_id', userId)
                .single();

            if (error && error.code !== 'PGRST116') throw error; // PGRST116 = no rows returned
            return data;
        } catch (error) {
            console.error('Error getting notification preferences:', error);
            return null;
        }
    }

    /**
     * Update notification preferences
     */
    public async updateNotificationPreferences(
        userId: string,
        preferences: Partial<NotificationPreferences>
    ): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('notification_preferences')
                .upsert({
                    user_id: userId,
                    ...preferences,
                    updated_at: new Date().toISOString()
                }, {
                    onConflict: 'user_id'
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error updating notification preferences:', error);
            return false;
        }
    }

    /**
     * Send push notification to user
     */
    public async sendPushNotification(
        userId: string,
        title: string,
        body: string,
        type: Notification['type'] = 'system',
        data?: any,
        priority: Notification['priority'] = 'normal'
    ): Promise<boolean> {
        try {
            // Check user preferences
            const preferences = await this.getNotificationPreferences(userId);
            if (!preferences?.enabled) {
                console.log('Notifications disabled for current user');
                return false;
            }

            // Check type-specific preferences
            if (!this.isNotificationTypeEnabled(preferences, type)) {
                console.log(`Notification type ${type} disabled for current user`);
                return false;
            }

            // Check quiet hours
            if (this.isInQuietHours(preferences)) {
                console.log('In quiet hours, notification delayed');
                // Schedule for later
                await this.scheduleNotification(userId, title, body, type, data, priority);
                return true;
            }

            // Get user's push token
            const { data: tokenData, error: tokenError } = await supabase
                .from('user_push_tokens')
                .select('expo_push_token')
                .eq('user_id', userId)
                .single();

            if (tokenError || !tokenData?.expo_push_token) {
                console.error('No push token found for current user');
                return false;
            }

            // Send notification via Expo
            const message = {
                to: tokenData.expo_push_token,
                sound: 'default',
                title,
                body,
                data: data || {},
                priority: this.mapPriorityToExpo(priority),
                channelId: this.getChannelIdForType(type)
            };

            const response = await fetch('https://exp.host/--/api/v2/push/send', {
                method: 'POST',
                headers: {
                    Accept: 'application/json',
                    'Accept-encoding': 'gzip, deflate',
                    'Content-Type': 'application/json',
                },
                body: JSON.stringify(message),
            });

            if (!response.ok) {
                throw new Error(`Failed to send notification: ${response.statusText}`);
            }

            // Save notification to database
            await this.saveNotificationToDB(userId, title, body, type, data, priority);

            return true;
        } catch (error) {
            console.error('Error sending push notification:', error);
            return false;
        }
    }

    /**
     * Send local notification
     */
    public async sendLocalNotification(
        title: string,
        body: string,
        data?: any,
        trigger?: Notifications.NotificationTriggerInput
    ): Promise<string | null> {
        try {
            const notificationId = await Notifications.scheduleNotificationAsync({
                content: {
                    title,
                    body,
                    data: data || {},
                    sound: true,
                },
                trigger: trigger || null,
            });

            return notificationId;
        } catch (error) {
            console.error('Error sending local notification:', error);
            return null;
        }
    }

    /**
     * Schedule recurring notification
     */
    public async scheduleRecurringNotification(
        userId: string,
        title: string,
        body: string,
        type: Notification['type'],
        trigger: Notifications.NotificationTriggerInput,
        data?: any
    ): Promise<string | null> {
        try {
            const notificationId = await Notifications.scheduleNotificationAsync({
                content: {
                    title,
                    body,
                    data: {
                        ...data,
                        user_id: userId,
                        type
                    },
                    sound: true,
                },
                trigger,
            });

            // Save scheduled notification to database
            await this.saveScheduledNotification(userId, title, body, type, trigger, data);

            return notificationId;
        } catch (error) {
            console.error('Error scheduling recurring notification:', error);
            return null;
        }
    }

    /**
     * Cancel scheduled notification
     */
    public async cancelScheduledNotification(notificationId: string): Promise<void> {
        try {
            await Notifications.cancelScheduledNotificationAsync(notificationId);

            // Remove from database
            await supabase
                .from('scheduled_notifications')
                .delete()
                .eq('notification_id', notificationId);
        } catch (error) {
            console.error('Error canceling scheduled notification:', error);
        }
    }

    private async getTranslation(key: TranslationKey, params?: Record<string, string | number>): Promise<string> {
        try {
            const lang = await PlatformStorage.getItem('NextSelf_language') || 'en';
            // @ts-ignore
            const translation = translations[lang]?.[key] || translations.en[key] || key;

            if (params) {
                return Object.entries(params).reduce(
                    (str, [param, value]) => str.replaceAll(`{${param}}`, String(value)),
                    translation
                );
            }
            return translation;
        } catch (error) {
            console.error('Error translating:', error);
            // Fallback to English
            // @ts-ignore
            const translation = translations.en[key] || key;
            if (params) {
                return Object.entries(params).reduce(
                    (str, [param, value]) => str.replaceAll(`{${param}}`, String(value)),
                    translation
                );
            }
            return translation;
        }
    }

