    private isNotificationTypeEnabled(preferences: NotificationPreferences, type: Notification['type']): boolean {
        switch (type) {
            case 'reminder':
                return preferences.reminder_notifications;
            case 'achievement':
                return preferences.achievement_notifications;
            case 'social':
                return preferences.social_notifications;
            case 'system':
                return preferences.system_notifications;
            case 'promotional':
                return preferences.promotional_notifications;
            default:
                return true;
        }
    }

    private isInQuietHours(preferences: NotificationPreferences): boolean {
        if (!preferences.quiet_hours_start || !preferences.quiet_hours_end) {
            return false;
        }

        const now = new Date();
        const currentTime = now.getHours() * 60 + now.getMinutes();

        const startTime = this.parseTimeString(preferences.quiet_hours_start);
        const endTime = this.parseTimeString(preferences.quiet_hours_end);

        if (startTime <= endTime) {
            // Quiet hours don't cross midnight
            return currentTime >= startTime && currentTime <= endTime;
        } else {
            // Quiet hours cross midnight
            return currentTime >= startTime || currentTime <= endTime;
        }
    }

    private parseTimeString(timeString: string): number {
        const [hours, minutes] = timeString.split(':').map(Number);
        return hours * 60 + minutes;
    }

    private async scheduleNotification(
        userId: string,
        title: string,
        body: string,
        type: Notification['type'],
        data?: any,
        priority: Notification['priority'] = 'normal'
    ): Promise<void> {
        try {
            // Schedule for 1 hour later (after quiet hours)
            const triggerDate = new Date(Date.now() + 60 * 60 * 1000); // 1 hour from now

            await Notifications.scheduleNotificationAsync({
                content: {
                    title,
                    body,
                    data: {
                        ...data,
                        user_id: userId,
                        type,
                        priority
                    },
                    sound: true,
                },
                trigger: {
                    type: 'date',
                    date: triggerDate,
                } as Notifications.NotificationTriggerInput,
            });

            // Save to scheduled notifications
            await supabase
                .from('scheduled_notifications')
                .insert({
                    user_id: userId,
                    title,
                    body,
                    type,
                    data: data || {},
                    priority,
                    scheduled_for: triggerDate.toISOString(),
                    created_at: new Date().toISOString()
                });
        } catch (error) {
            console.error('Error scheduling notification:', error);
        }
    }

    private async saveNotificationToDB(
        userId: string,
        title: string,
        body: string,
        type: Notification['type'],
        data?: any,
        priority: Notification['priority'] = 'normal'
    ): Promise<void> {
        try {
            await supabase
                .from('notifications')
                .insert({
                    user_id: userId,
                    title,
                    body,
                    type,
                    data: data || {},
                    priority,
                    read: false,
                    sent_at: new Date().toISOString(),
                    created_at: new Date().toISOString()
                });
        } catch (error) {
            console.error('Error saving notification to DB:', error);
        }
    }

    private async saveScheduledNotification(
        userId: string,
        title: string,
        body: string,
        type: Notification['type'],
        trigger: Notifications.NotificationTriggerInput,
        data?: any
    ): Promise<void> {
        try {
            let scheduledFor: string;

            if (trigger && typeof trigger === 'object' && 'date' in trigger) {
                scheduledFor = (trigger.date as Date).toISOString();
            } else if (trigger && typeof trigger === 'object' && 'seconds' in trigger) {
                const seconds = (trigger as any).seconds;
                scheduledFor = new Date(Date.now() + seconds * 1000).toISOString();
            } else {
                scheduledFor = new Date().toISOString();
            }

            await supabase
                .from('scheduled_notifications')
                .insert({
                    user_id: userId,
                    title,
                    body,
                    type,
                    data: data || {},
                    scheduled_for: scheduledFor,
                    created_at: new Date().toISOString()
                });
        } catch (error) {
            console.error('Error saving scheduled notification:', error);
        }
    }

    private mapPriorityToExpo(priority: Notification['priority']): 'default' | 'normal' | 'high' {
        switch (priority) {
            case 'high':
                return 'high';
            case 'normal':
                return 'normal';
            case 'low':
                return 'default';
            default:
                return 'normal';
        }
    }

    private getChannelIdForType(type: Notification['type']): string {
        switch (type) {
            case 'reminder':
                return 'workout'; // Assuming reminders are mostly workouts/supplements
            case 'achievement':
                return 'default';
            case 'social':
                return 'default';
            case 'system':
                return 'default';
            case 'promotional':
                return 'default';
            default:
                return 'default';
        }
    }

    /**
     * Cleanup resources
     */
    public cleanup(): void {
        if (this.notificationListener) {
            this.notificationListener.remove();
            this.notificationListener = null;
        }

        if (this.responseListener) {
            this.responseListener.remove();
            this.responseListener = null;
        }
    }
}

