import { SupabaseService } from './supabase';

const supabase = SupabaseService.getInstance().getClient();

// Sanitize user input for PostgREST .or() filters to prevent injection
function sanitizePostgrestValue(input: string): string {
    return input.replace(/[%_,().\\]/g, '');
}

export interface UserProfile {
    id: string;
    username: string;
    full_name: string;
    avatar_url: string;
    bio: string;
    level: number;
    xp: number;
    streak: number;
    followers_count: number;
    following_count: number;
    created_at: string;
}

export interface Friendship {
    id: string;
    user_id: string;
    friend_id: string;
    status: 'pending' | 'accepted' | 'rejected' | 'blocked';
    current_streak?: number;
    longest_streak?: number;
    last_streak_date?: string | null;
    created_at: string;
    updated_at: string;
}

export interface Challenge {
    id: string;
    title: string;
    description: string;
    type: 'steps' | 'calories' | 'workout' | 'nutrition' | 'streak';
    target_value: number;
    unit: string;
    start_date: string;
    end_date: string;
    created_by: string;
    participants_count: number;
    is_public: boolean;
    created_at: string;
}

export interface ChallengeParticipant {
    id: string;
    challenge_id: string;
    user_id: string;
    current_value: number;
    completed: boolean;
    rank: number;
    joined_at: string;
    updated_at: string;
}

export interface LeaderboardEntry {
    user_id: string;
    username: string;
    avatar_url: string;
    score: number;
    rank: number;
    level: number;
    streak: number;
}

export class SocialService {
    /**
     * Search for users by username or name
     */
    static async searchUsers(query: string, limit: number = 20): Promise<UserProfile[]> {
        try {
            const sanitized = sanitizePostgrestValue(query);
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .or(`username.ilike.%${sanitized}%,full_name.ilike.%${sanitized}%`)
                .limit(limit);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error searching users:', error);
            return [];
        }
    }

    /**
     * Get user profile by ID
     */
    static async getUserProfile(userId: string): Promise<UserProfile | null> {
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('*')
                .eq('id', userId)
                .single();

            if (error) throw error;
            return data;
        } catch (error) {
            console.error('Error getting user profile:', error);
            return null;
        }
    }

    /**
     * Send friend request
     */
    static async sendFriendRequest(userId: string, friendId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('friendships')
                .insert({
                    user_id: userId,
                    friend_id: friendId,
                    status: 'pending'
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error sending friend request:', error);
            return false;
        }
    }

    /**
     * Accept friend request
     */
    static async acceptFriendRequest(friendshipId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('friendships')
                .update({ status: 'accepted', updated_at: new Date().toISOString() })
                .eq('id', friendshipId);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error accepting friend request:', error);
            return false;
        }
    }

    /**
     * Reject friend request
     */
    static async rejectFriendRequest(friendshipId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('friendships')
                .update({ status: 'rejected', updated_at: new Date().toISOString() })
                .eq('id', friendshipId);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error rejecting friend request:', error);
            return false;
        }
    }

    /**
     * Get user's friends
     */
    static async getUserFriends(userId: string, status: 'pending' | 'accepted' = 'accepted'): Promise<Friendship[]> {
        try {
            const { data, error } = await supabase
                .from('friendships')
                .select('*')
                .or(`user_id.eq.${userId},friend_id.eq.${userId}`)
                .eq('status', status);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error getting user friends:', error);
            return [];
        }
    }

    /**
     * Create a new challenge
     */
    static async createChallenge(challenge: Omit<Challenge, 'id' | 'created_at' | 'participants_count'>): Promise<Challenge | null> {
        try {
            const { data, error } = await supabase
                .from('challenges')
                .insert({
                    ...challenge,
                    participants_count: 1
                })
                .select()
                .single();

            if (error) throw error;

            // Auto-join the creator
            await this.joinChallenge(data.id, challenge.created_by);

            return data;
        } catch (error) {
            console.error('Error creating challenge:', error);
            return null;
        }
    }

    /**
     * Join a challenge
     */
    static async joinChallenge(challengeId: string, userId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('challenge_participants')
                .insert({
                    challenge_id: challengeId,
                    user_id: userId,
                    current_value: 0,
                    completed: false,
                    rank: 0
                });

            if (error) throw error;

            // Update participants count
            await supabase.rpc('increment_challenge_participants', { challenge_id: challengeId });

            return true;
        } catch (error) {
            console.error('Error joining challenge:', error);
            return false;
        }
    }

    /**
     * Update challenge progress
     */
    static async updateChallengeProgress(participantId: string, currentValue: number): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('challenge_participants')
                .update({
                    current_value: currentValue,
                    updated_at: new Date().toISOString()
                })
                .eq('id', participantId);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error updating challenge progress:', error);
            return false;
        }
    }

    /**
     * Get active challenges
     */
    static async getActiveChallenges(userId?: string, limit: number = 20): Promise<Challenge[]> {
        try {
            let query = supabase
                .from('challenges')
                .select('*')
                .gte('end_date', new Date().toISOString())
                .order('created_at', { ascending: false })
                .limit(limit);

            if (userId) {
                query = query.eq('created_by', userId);
            }

            const { data, error } = await query;

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error getting active challenges:', error);
            return [];
        }
    }

    /**
     * Get challenge leaderboard
     */
    static async getChallengeLeaderboard(challengeId: string): Promise<LeaderboardEntry[]> {
        try {
            const { data, error } = await supabase
                .from('challenge_participants')
                .select(`
          id,
          current_value,
          completed,
          rank,
          profiles:user_id (
            id,
            username,
            full_name,
            avatar_url,
            level,
            streak
          )
        `)
                .eq('challenge_id', challengeId)
                .order('current_value', { ascending: false })
                .limit(50);

            if (error) throw error;

            return (data || []).map((participant: any, index: number) => ({
                user_id: participant.profiles.id,
                username: participant.profiles.username,
                avatar_url: participant.profiles.avatar_url,
                score: participant.current_value,
                rank: index + 1,
                level: participant.profiles.level,
                streak: participant.profiles.streak
            }));
        } catch (error) {
            console.error('Error getting challenge leaderboard:', error);
            return [];
        }
    }

    /**
     * Get global leaderboard
     */
    static async getGlobalLeaderboard(type: 'xp' | 'streak' | 'level', limit: number = 50): Promise<LeaderboardEntry[]> {
        try {
            const { data, error } = await supabase
                .from('profiles')
                .select('id, username, avatar_url, level, xp, streak')
                .order(type, { ascending: false })
                .limit(limit);

            if (error) throw error;

            return (data || []).map((profile: any, index: number) => ({
                user_id: profile.id,
                username: profile.username,
                avatar_url: profile.avatar_url,
                score: profile[type],
                rank: index + 1,
                level: profile.level,
                streak: profile.streak
            }));
        } catch (error) {
            console.error('Error getting global leaderboard:', error);
            return [];
        }
    }

    /**
     * Follow a user
     */
    static async followUser(followerId: string, followingId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('follows')
                .insert({
                    follower_id: followerId,
                    following_id: followingId
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error following user:', error);
            return false;
        }
    }

    /**
     * Unfollow a user
     */
    static async unfollowUser(followerId: string, followingId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('follows')
                .delete()
                .eq('follower_id', followerId)
                .eq('following_id', followingId);

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error unfollowing user:', error);
            return false;
        }
    }

    /**
     * Get user's followers
     */
    static async getUserFollowers(userId: string): Promise<UserProfile[]> {
        try {
            const { data, error } = await supabase
                .from('follows')
                .select(`
          follower:profiles!follows_follower_id_fkey (
            id,
            username,
            full_name,
            avatar_url,
            bio,
            level,
            xp,
            streak
          )
        `)
                .eq('following_id', userId);

            if (error) throw error;

            return (data || []).map((item: any) => item.follower);
        } catch (error) {
            console.error('Error getting user followers:', error);
            return [];
        }
    }

    /**
     * Get users that a user is following
     */
    static async getUserFollowing(userId: string): Promise<UserProfile[]> {
        try {
            const { data, error } = await supabase
                .from('follows')
                .select(`
          following:profiles!follows_following_id_fkey (
            id,
            username,
            full_name,
            avatar_url,
            bio,
            level,
            xp,
            streak
          )
        `)
                .eq('follower_id', userId);

            if (error) throw error;

            return (data || []).map((item: any) => item.following);
        } catch (error) {
            console.error('Error getting user following:', error);
            return [];
        }
    }

    /**
     * Share achievement or progress
     */
    static async shareAchievement(userId: string, type: string, data: any): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('social_posts')
                .insert({
                    user_id: userId,
                    type,
                    data,
                    likes_count: 0,
                    comments_count: 0
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error sharing achievement:', error);
            return false;
        }
    }

    /**
     * Like a post
     */
    static async likePost(postId: string, userId: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('post_likes')
                .insert({
                    post_id: postId,
                    user_id: userId
                });

            if (error) throw error;

            // Update likes count
            await supabase.rpc('increment_post_likes', { post_id: postId });

            return true;
        } catch (error) {
            console.error('Error liking post:', error);
            return false;
        }
    }

    /**
     * Comment on a post
     */
    static async commentOnPost(postId: string, userId: string, content: string): Promise<boolean> {
        try {
            const { error } = await supabase
                .from('post_comments')
                .insert({
                    post_id: postId,
                    user_id: userId,
                    content
                });

            if (error) throw error;

            // Update comments count
            await supabase.rpc('increment_post_comments', { post_id: postId });

            return true;
        } catch (error) {
            console.error('Error commenting on post:', error);
            return false;
        }
    }

    /**
     * Get user's feed (posts from followed users)
     */
    static async getUserFeed(userId: string, limit: number = 20): Promise<any[]> {
        try {
            // Get the list of followed user IDs first
            const { data: followsData } = await supabase
                .from('follows')
                .select('following_id')
                .eq('follower_id', userId);

            const followingIds = followsData?.map(item => item.following_id) || [];

            // Guard: .in() with an empty array causes a PostgREST error
            if (followingIds.length === 0) return [];

            const { data, error } = await supabase
                .from('social_posts')
                .select(`
          *,
          profiles:user_id (
            id,
            username,
            full_name,
            avatar_url
          )
        `)
                .in('user_id', followingIds)
                .order('created_at', { ascending: false })
                .limit(limit);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error getting user feed:', error);
            return [];
        }
    }
}

import { SupabaseService } from './supabase';
import { Linking, Platform } from 'react-native';

const SPOTIFY_API_BASE = 'https://api.spotify.com/v1';

export interface SpotifyTrack {
  id: string;
  name: string;
  artist: string;
  album: string;
  duration: number;
  previewUrl?: string;
  imageUrl?: string;
  uri: string;
}

export interface SpotifyPlaylist {
  id: string;
  name: string;
  description?: string;
  tracks: SpotifyTrack[];
  imageUrl?: string;
  uri: string;
}

export class SpotifyService {
  private static instance: SpotifyService;
  private accessToken: string | null = null;
  private tokenExpiresAt: number = 0;
  private refreshToken: string | null = null;

  private constructor() { }

  public static getInstance(): SpotifyService {
    if (!SpotifyService.instance) {
      SpotifyService.instance = new SpotifyService();
    }
    return SpotifyService.instance;
  }

  /**
   * Authenticate via Supabase's Spotify OAuth provider.
   * After successful sign-in, the provider_token (Spotify access token)
   * is available on the Supabase session.
   */
  public async authenticate(): Promise<boolean> {
    try {
      const supabase = SupabaseService.getInstance().getClient();

      const { data, error } = await supabase.auth.signInWithOAuth({
        provider: 'spotify',
        options: {
          scopes: 'user-read-playback-state user-modify-playback-state user-read-currently-playing playlist-read-private',
          redirectTo: Platform.OS === 'web'
            ? window.location.origin
            : 'NextSelf://spotify-callback',
        },
      });

      if (error) {
        console.error('Spotify OAuth error:', error.message);
        return false;
      }

      // On web, signInWithOAuth opens a redirect. On native, we open the URL.
      if (data?.url && Platform.OS !== 'web') {
        await Linking.openURL(data.url);
      }

      // After redirect the session will contain provider_token
      return await this.loadTokenFromSession();
    } catch (error) {
      console.error('Spotify authentication failed:', error);
      return false;
    }
  }

  /**
   * Extract the Spotify access token from the current Supabase session.
   */
  public async loadTokenFromSession(): Promise<boolean> {
    try {
      const supabase = SupabaseService.getInstance().getClient();
      const { data: { session } } = await supabase.auth.getSession();

      if (session?.provider_token) {
        this.accessToken = session.provider_token;
        this.refreshToken = session.provider_refresh_token ?? null;
        // provider_token typically expires in 1 hour
        this.tokenExpiresAt = Date.now() + 3500 * 1000;
        return true;
      }
      return false;
    } catch (error) {
      console.error('Failed to load Spotify token from session:', error);
      return false;
    }
  }

  /** Ensure token is valid before API calls */
  private async ensureToken(): Promise<void> {
    if (!this.accessToken) {
      throw new Error('Not authenticated with Spotify');
    }
    // Refresh 60s before expiry
    if (Date.now() > this.tokenExpiresAt - 60000) {
      const refreshed = await this.loadTokenFromSession();
      if (!refreshed) {
        this.accessToken = null;
        throw new Error('Spotify token expired. Please re-authenticate.');
      }
    }
  }

  /** Generic Spotify API call with auth header */
  private async spotifyFetch<T>(endpoint: string, options: RequestInit = {}): Promise<T | null> {
    await this.ensureToken();

    const response = await fetch(`${SPOTIFY_API_BASE}${endpoint}`, {
      ...options,
      headers: {
        Authorization: `Bearer ${this.accessToken}`,
        'Content-Type': 'application/json',
        ...(options.headers || {}),
      },
    });

    if (response.status === 204) return null;

    if (response.status === 401) {
      // Token expired, try refreshing once
      const refreshed = await this.loadTokenFromSession();
      if (refreshed) {
        const retryResponse = await fetch(`${SPOTIFY_API_BASE}${endpoint}`, {
          ...options,
          headers: {
            Authorization: `Bearer ${this.accessToken}`,
            'Content-Type': 'application/json',
            ...(options.headers || {}),
          },
        });
        if (retryResponse.status === 204) return null;
        if (!retryResponse.ok) throw new Error(`Spotify API error: ${retryResponse.status}`);
        return retryResponse.json();
      }
      this.accessToken = null;
      throw new Error('Spotify session expired');
    }

    if (!response.ok) {
      throw new Error(`Spotify API error: ${response.status}`);
    }

    return response.json();
  }

  public async getCurrentlyPlaying(): Promise<SpotifyTrack | null> {
    try {
      const data = await this.spotifyFetch<any>('/me/player/currently-playing');
      if (!data?.item) return null;

      const item = data.item;
      return {
        id: item.id,
        name: item.name,
        artist: item.artists?.map((a: any) => a.name).join(', ') || 'Unknown',
        album: item.album?.name || '',
        duration: item.duration_ms || 0,
        imageUrl: item.album?.images?.[0]?.url,
        uri: item.uri,
      };
    } catch (error) {
      console.error('Failed to get currently playing:', error);
      return null;
    }
  }

  public async pausePlayback(): Promise<void> {
    await this.spotifyFetch('/me/player/pause', { method: 'PUT' });
  }

  public async resumePlayback(): Promise<void> {
    await this.spotifyFetch('/me/player/play', { method: 'PUT' });
  }

  public async skipToNext(): Promise<void> {
    await this.spotifyFetch('/me/player/next', { method: 'POST' });
  }

  public async skipToPrevious(): Promise<void> {
    await this.spotifyFetch('/me/player/previous', { method: 'POST' });
  }

  public async setVolume(volume: number): Promise<void> {
    const clamped = Math.max(0, Math.min(100, Math.round(volume)));
    await this.spotifyFetch(`/me/player/volume?volume_percent=${clamped}`, { method: 'PUT' });
  }

  public async playTrack(trackUri: string): Promise<void> {
    await this.spotifyFetch('/me/player/play', {
      method: 'PUT',
      body: JSON.stringify({ uris: [trackUri] }),
    });
  }

  public async playPlaylist(playlistUri: string): Promise<void> {
    await this.spotifyFetch('/me/player/play', {
      method: 'PUT',
      body: JSON.stringify({ context_uri: playlistUri }),
    });
  }

  public async getWorkoutPlaylists(): Promise<SpotifyPlaylist[]> {
    try {
      // Search Spotify for workout playlists
      const data = await this.spotifyFetch<any>(
        '/search?q=workout&type=playlist&limit=10'
      );
      if (!data?.playlists?.items) return [];

      return data.playlists.items.map((p: any) => ({
        id: p.id,
        name: p.name,
        description: p.description || '',
        tracks: [],
        imageUrl: p.images?.[0]?.url,
        uri: p.uri,
      }));
    } catch (error) {
      console.error('Failed to get workout playlists:', error);
      return [];
    }
  }

  public async getUserPlaylists(): Promise<SpotifyPlaylist[]> {
    try {
      const data = await this.spotifyFetch<any>('/me/playlists?limit=20');
      if (!data?.items) return [];

      return data.items.map((p: any) => ({
        id: p.id,
        name: p.name,
        description: p.description || '',
        tracks: [],
        imageUrl: p.images?.[0]?.url,
        uri: p.uri,
      }));
    } catch (error) {
      console.error('Failed to get user playlists:', error);
      return [];
    }
  }

  public async searchTracks(query: string): Promise<SpotifyTrack[]> {
    if (!query.trim()) return [];
    try {
      const encoded = encodeURIComponent(query.trim());
      const data = await this.spotifyFetch<any>(
        `/search?q=${encoded}&type=track&limit=10`
      );
      if (!data?.tracks?.items) return [];

      return data.tracks.items.map((t: any) => ({
        id: t.id,
        name: t.name,
        artist: t.artists?.map((a: any) => a.name).join(', ') || 'Unknown',
        album: t.album?.name || '',
        duration: t.duration_ms || 0,
        imageUrl: t.album?.images?.[0]?.url,
        uri: t.uri,
      }));
    } catch (error) {
      console.error('Failed to search tracks:', error);
      return [];
    }
  }

  public isAuthenticated(): boolean {
    return this.accessToken !== null && Date.now() < this.tokenExpiresAt;
  }

  public getAccessToken(): string | null {
    return this.accessToken;
  }

  /** Disconnect Spotify by clearing tokens */
  public disconnect(): void {
    this.accessToken = null;
    this.refreshToken = null;
    this.tokenExpiresAt = 0;
  }
}

import { SupabaseService } from './supabase';
import { LogManager } from '../utils/LogManager';

export interface StoreItem {
    id: string;
    name: string;
    nameTr: string;
    description: string;
    descriptionTr: string;
    category: 'booster' | 'cosmetic' | 'utility' | 'equipment' | 'nutrition' | 'recovery' | 'seasonal' | 'premium';
    icon: string;
    pricePoints: number;
    priceReal?: number;
    effectType: string;
    effectDurationMinutes?: number;
    maxStack: number;
    isConsumable: boolean;
    isActive: boolean;
    rarity?: 'common' | 'uncommon' | 'rare' | 'epic' | 'legendary';
    badgeText?: string;
    badgeColor?: string;
}

export interface UserInventoryItem {
    id: string;
    itemId: string;
    quantity: number;
    isActive: boolean;
    activatedAt?: string;
    expiresAt?: string;
    item: StoreItem;
}

export interface UserCurrency {
    points: number;
    gems: number;
    totalEarnedPoints: number;
    totalSpentPoints: number;
}

export class StoreService {
    private static instance: StoreService;

    private constructor() { }

    public static getInstance(): StoreService {
        if (!StoreService.instance) {
            StoreService.instance = new StoreService();
        }
        return StoreService.instance;
    }

    private mapStoreItem(item: any): StoreItem {
        const fallbackName = item.name || item.name_tr || 'Store Item';
        const fallbackNameTr = item.name_tr || item.name || 'Mağaza Ürünü';
        const fallbackDesc = item.description || 'Useful store item for your fitness journey.';
        const fallbackDescTr = item.description_tr || 'Fitness yolculuğun için faydalı bir mağaza ürünü.';
        return {
            id: item.id,
            name: fallbackName,
            nameTr: fallbackNameTr,
            description: fallbackDesc,
            descriptionTr: fallbackDescTr,
            category: item.category,
            icon: item.icon,
            pricePoints: item.price_points,
            priceReal: item.price_real,
            effectType: item.effect_type,
            effectDurationMinutes: item.effect_duration_minutes,
            maxStack: item.max_stack,
            isConsumable: item.is_consumable,
            isActive: item.is_active,
            rarity: item.rarity,
            badgeText: item.badge_text,
            badgeColor: item.badge_color,
        };
    }

    // Get available store items with pagination
    public async getStoreItems(category: string = 'all', page: number = 0, pageSize: number = 20): Promise<StoreItem[]> {
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const safePageSize = Math.max(1, Math.min(pageSize, 100));
            const safePage = Math.max(0, page);
            const from = safePage * safePageSize;
            const to = from + safePageSize - 1;
            let query = supabase
                .from('store_items')
                .select('*')
                .eq('is_active', true)
                .order('sort_order', { ascending: true })
                .range(from, to);

            if (category !== 'all') {
                query = query.eq('category', category);
            }

            const { data, error } = await query;

            if (error) throw error;
            return (data || []).map(this.mapStoreItem);
        } catch (err) {
            LogManager.getInstance().warn('Store items fetch error:', err);
            // Return default items as fallback
            return this.getDefaultItems();
        }
    }

    // Get user's currency balance
    public async getUserCurrency(): Promise<UserCurrency> {
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) throw new Error('Not authenticated');

            const { data, error } = await supabase
                .from('user_currency')
                .select('*')
                .eq('user_id', user.id)
                .single();

            if (error || !data) {
                // Initialize currency
                const { data: newCurrency } = await supabase
                    .from('user_currency')
                    .upsert({
                        user_id: user.id,
                        points: 100, // Starting bonus
                        gems: 0,
                        total_earned_points: 100,
                        total_spent_points: 0,
                    }, { onConflict: 'user_id' })
                    .select()
                    .single();

                return newCurrency ? {
                    points: newCurrency.points,
                    gems: newCurrency.gems,
                    totalEarnedPoints: newCurrency.total_earned_points,
                    totalSpentPoints: newCurrency.total_spent_points
                } : { points: 100, gems: 0, totalEarnedPoints: 100, totalSpentPoints: 0 };
            }

            return {
                points: data.points,
                gems: data.gems,
                totalEarnedPoints: data.total_earned_points,
                totalSpentPoints: data.total_spent_points
            };
        } catch (err) {
            LogManager.getInstance().warn('Currency fetch error:', err);
            return { points: 0, gems: 0, totalEarnedPoints: 0, totalSpentPoints: 0 };
        }
    }

    // Get user's inventory
    public async getUserInventory(): Promise<UserInventoryItem[]> {
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) throw new Error('Not authenticated');

            const { data, error } = await supabase
                .from('user_inventory')
                .select('*, store_items:item_id(*)')
                .eq('user_id', user.id)
                .gt('quantity', 0);

            if (error) throw error;

            return (data || []).map((item: any) => ({
                id: item.id,
                itemId: item.item_id,
                quantity: item.quantity,
                isActive: item.is_active,
                activatedAt: item.activated_at,
                expiresAt: item.expires_at,
                item: this.mapStoreItem(item.store_items),
            }));
        } catch (err) {
            LogManager.getInstance().warn('Inventory fetch error:', err);
            return [];
        }
    }

    // Purchase an item
    // Uses optimistic concurrency control to prevent double-spend race conditions.
    // The currency deduction includes the current balance in the WHERE clause so
    // concurrent purchases can't both succeed with stale balance data.
    public async purchaseItem(itemId: string): Promise<{ success: boolean; message: string }> {
        const MAX_RETRIES = 3;
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return { success: false, message: 'Not authenticated' };

            // Get item details
            const { data: item } = await supabase
                .from('store_items')
                .select('*')
                .eq('id', itemId)
                .single();

            if (!item) return { success: false, message: 'Item not found' };

            for (let attempt = 0; attempt < MAX_RETRIES; attempt++) {
                // Read fresh currency each attempt
                const currency = await this.getUserCurrency();
                if (currency.points < item.price_points) {
                    return { success: false, message: 'insufficient_points' };
                }

                // Check max stack
                const { data: existingInventory } = await supabase
                    .from('user_inventory')
                    .select('quantity')
                    .eq('user_id', user.id)
                    .eq('item_id', itemId)
                    .single();

                if (existingInventory && existingInventory.quantity >= item.max_stack) {
                    return { success: false, message: 'max_stack_reached' };
                }

                // Deduct points with optimistic lock:
                // Only succeeds if points haven't changed since we read them.
                // This prevents double-spend from concurrent purchase requests.
                const { data: deductResult, error: deductError } = await supabase
                    .from('user_currency')
                    .update({
                        points: currency.points - item.price_points,
                        total_spent_points: currency.totalSpentPoints + item.price_points,
                    })
                    .eq('user_id', user.id)
                    .eq('points', currency.points)
                    .select();

                if (deductError || !deductResult || deductResult.length === 0) {
                    // Conflict: balance changed between read and write (concurrent purchase).
                    LogManager.getInstance().warn(`Purchase currency deduction conflict (attempt ${attempt + 1}/${MAX_RETRIES}), retrying...`);
                    continue;
                }

                // Currency deducted successfully — proceed with inventory + logging.
                // Add to inventory
                let inventoryError: any = null;
                if (existingInventory) {
                    const { error } = await supabase
                        .from('user_inventory')
                        .update({ quantity: existingInventory.quantity + 1 })
                        .eq('user_id', user.id)
                        .eq('item_id', itemId);
                    inventoryError = error;
                } else {
                    const { error } = await supabase
                        .from('user_inventory')
                        .insert({
                            user_id: user.id,
                            item_id: itemId,
                            quantity: 1,
                            is_active: false,
                        });
                    inventoryError = error;
                }

                if (inventoryError) {
                    await supabase
                        .from('user_currency')
                        .update({
                            points: currency.points,
                            total_spent_points: Math.max(0, currency.totalSpentPoints),
                        })
                        .eq('user_id', user.id);
                    LogManager.getInstance().warn('Inventory update failed after deduction, rolled back currency');
                    continue;
                }

                // Log purchase
                const { error: purchaseLogError } = await supabase
                    .from('purchase_history')
                    .insert({
                        user_id: user.id,
                        item_id: itemId,
                        quantity: 1,
                        price_paid: item.price_points,
                    });

                if (purchaseLogError) {
                    await supabase
                        .from('user_currency')
                        .update({
                            points: currency.points,
                            total_spent_points: Math.max(0, currency.totalSpentPoints),
                        })
                        .eq('user_id', user.id);

                    await supabase
                        .from('user_inventory')
                        .update({ quantity: existingInventory ? existingInventory.quantity : 0 })
                        .eq('user_id', user.id)
                        .eq('item_id', itemId);
                    LogManager.getInstance().warn('Purchase history insert failed after deduction, rolled back changes');
                    continue;
                }

                return { success: true, message: 'purchase_success' };
            }

            // All retries exhausted — likely heavy contention
            LogManager.getInstance().warn('Purchase failed after max retries due to concurrent modifications');
            return { success: false, message: 'purchase_failed' };
        } catch (err) {
            LogManager.getInstance().warn('Purchase error:', err);
            return { success: false, message: 'purchase_failed' };
        }
    }

    // Activate a booster item
    public async activateItem(itemId: string): Promise<{ success: boolean; message: string }> {
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return { success: false, message: 'Not authenticated' };

            // Get inventory item
            const { data: invItem } = await supabase
                .from('user_inventory')
                .select('*, store_items:item_id(*)')
                .eq('user_id', user.id)
                .eq('item_id', itemId)
                .gt('quantity', 0)
                .single();

            if (!invItem) return { success: false, message: 'Item not in inventory' };

            const storeItem = invItem.store_items as any;

            if (storeItem.is_consumable) {
                // Calculate expiry
                const now = new Date();
                const expiresAt = storeItem.effect_duration_minutes
                    ? new Date(now.getTime() + storeItem.effect_duration_minutes * 60 * 1000)
                    : null;

                await supabase
                    .from('user_inventory')
                    .update({
                        quantity: invItem.quantity - 1,
                        is_active: true,
                        activated_at: now.toISOString(),
                        expires_at: expiresAt?.toISOString() || null,
                    })
                    .eq('id', invItem.id);
            } else {
                // Non-consumable (cosmetic) - just toggle active
                await supabase
                    .from('user_inventory')
                    .update({ is_active: !invItem.is_active })
                    .eq('id', invItem.id);
            }

            return { success: true, message: 'activated' };
        } catch (err) {
            LogManager.getInstance().warn('Activate error:', err);
            return { success: false, message: 'activation_failed' };
        }
    }

    // Use streak freeze
    public async useStreakFreeze(): Promise<boolean> {
        try {
            const supabase = SupabaseService.getInstance().getClient();
            const { data: { user } } = await supabase.auth.getUser();
            if (!user) return false;

            const { data: freezeItem } = await supabase
                .from('user_inventory')
                .select('*, store_items:item_id!inner(*)')
                .eq('user_id', user.id)
                .eq('store_items.effect_type', 'streak_freeze')
                .gt('quantity', 0)
                .single();

            if (!freezeItem) return false;

            await supabase
                .from('user_inventory')
                .update({ quantity: freezeItem.quantity - 1 })
                .eq('id', freezeItem.id);

            return true;
        } catch (err) {
            LogManager.getInstance().warn('Streak freeze error:', err);
            return false;
        }
    }

