  // ==================== AVATAR / STORAGE ====================

  /**
   * Upload a profile avatar image to Supabase Storage.
   * Returns the public URL on success.
   */
  public async uploadAvatar(userId: string, imageUri: string): Promise<{ url: string | null; error: any }> {
    try {
      const response = await fetch(imageUri);
      const blob = await response.blob();

      const ext = imageUri.split('.').pop()?.toLowerCase() || 'jpg';
      const filePath = `avatars/${userId}.${ext}`;

      const { error: uploadError } = await this.client.storage
        .from('avatars')
        .upload(filePath, blob, {
          contentType: `image/${ext === 'jpg' ? 'jpeg' : ext}`,
          upsert: true,
        });

      if (uploadError) {
        return { url: null, error: uploadError };
      }

      const { data: urlData } = this.client.storage
        .from('avatars')
        .getPublicUrl(filePath);

      const publicUrl = urlData?.publicUrl
        ? `${urlData.publicUrl}?t=${Date.now()}`
        : null;

      // Update profile with avatar_url
      if (publicUrl) {
        await this.client
          .from('users')
          .update({ avatar_url: publicUrl, updated_at: new Date().toISOString() })
          .eq('id', userId);
      }

      return { url: publicUrl, error: null };
    } catch (err) {
      return { url: null, error: err };
    }
  }

  /**
   * Get public URL for an avatar path.
   */
  public getAvatarUrl(path: string): string | null {
    if (!path) return null;
    if (path.startsWith('http')) return path;
    const { data } = this.client.storage.from('avatars').getPublicUrl(path);
    return data?.publicUrl || null;
  }
}

import { SupabaseService } from './supabase';

export interface Supplement {
  id: string;
  name: string; // Dynamic based on language (name_en or name_tr)
  nameEn?: string;
  nameTr?: string;
  description?: string; // Dynamic
  descriptionEn?: string;
  descriptionTr?: string;
  category: 'vitamin' | 'mineral' | 'protein' | 'amino_acid' | 'herbal' | 'other';
  form: 'tablet' | 'capsule' | 'powder' | 'liquid' | 'gummy' | 'softgel' | 'drops';
  dosageAmount: string;
  dosageUnit: string;
  servingSize: string;
  benefits: string[]; // Dynamic
  benefitsEn?: string[];
  benefitsTr?: string[];
  sideEffects: string[]; // Dynamic
  sideEffectsEn?: string[];
  sideEffectsTr?: string[];
  usageInstructions: string; // Dynamic
  usageInstructionsEn?: string;
  usageInstructionsTr?: string;
  imageUrl?: string;
  isVerified: boolean;
  createdAt: string;
  updatedAt: string;
}

export interface SupplementLog {
  id: string;
  userId: string;
  supplementId: string;
  quantity: number;
  unit: string;
  takenAt: string;
  notes?: string;
  createdAt: string;
  // Expanded fields for UI
  supplementName?: string;
  supplementCategory?: string;
}

export class SupplementService {
  private static instance: SupplementService;
  private supabase: any;

  private constructor() {
    this.supabase = SupabaseService.getInstance().getClient();
  }

  public static getInstance(): SupplementService {
    if (!SupplementService.instance) {
      SupplementService.instance = new SupplementService();
    }
    return SupplementService.instance;
  }

  // Get all supplements with language support
  public async getSupplements(
    language: 'en' | 'tr' = 'en',
    category?: string,
    search?: string,
    page: number = 1,
    limit: number = 50
  ): Promise<{ data: Supplement[]; count: number }> {
    try {
      let query = this.supabase
        .from('supplements')
        .select('*', { count: 'exact' })
        .eq('is_verified', true);

      if (category) {
        query = query.eq('category', category);
      }

      if (search) {
        const safe = search.replace(/[,.*()%_\\]/g, '');
        if (language === 'tr') {
          query = query.or(`name_tr.ilike.%${safe}%`);
        } else {
          query = query.or(`name_en.ilike.%${safe}%`);
        }
      }

      const from = (page - 1) * limit;
      const to = from + limit - 1;

      const { data, count, error } = await query
        .order(language === 'tr' ? 'name_tr' : 'name_en', { ascending: true })
        .range(from, to);

      if (error) throw error;

      const formattedData = (data || []).map((item: any) => this.mapDbToSupplement(item, language));

      return { data: formattedData, count: count || 0 };
    } catch (error) {
      console.error('Error getting supplements:', error);
      return { data: [], count: 0 };
    }
  }

  // Get supplement by ID
  public async getSupplementById(supplementId: string, language: 'en' | 'tr' = 'en'): Promise<Supplement | null> {
    try {
      const { data, error } = await this.supabase
        .from('supplements')
        .select('*')
        .eq('id', supplementId)
        .single();

      if (error) throw error;
      if (!data) return null;

      return this.mapDbToSupplement(data, language);
    } catch (error) {
      console.error('Error getting supplement by ID:', error);
      return null;
    }
  }

  // Helper to map DB row to Supplement interface
  private mapDbToSupplement(item: any, language: 'en' | 'tr'): Supplement {
    return {
      id: item.id,
      name: language === 'tr' ? item.name_tr : item.name_en,
      nameEn: item.name_en,
      nameTr: item.name_tr,
      description: language === 'tr' ? item.description_tr : item.description_en,
      descriptionEn: item.description_en,
      descriptionTr: item.description_tr,
      category: item.category,
      form: item.form,
      dosageAmount: item.dosage_amount,
      dosageUnit: item.dosage_unit,
      servingSize: item.serving_size,
      benefits: language === 'tr' ? (item.benefits_tr || []) : (item.benefits_en || []),
      benefitsEn: item.benefits_en,
      benefitsTr: item.benefits_tr,
      sideEffects: language === 'tr' ? (item.side_effects_tr || []) : (item.side_effects_en || []),
      sideEffectsEn: item.side_effects_en,
      sideEffectsTr: item.side_effects_tr,
      usageInstructions: language === 'tr' ? item.usage_instructions_tr : item.usage_instructions_en,
      usageInstructionsEn: item.usage_instructions_en,
      usageInstructionsTr: item.usage_instructions_tr,
      imageUrl: item.image_url,
      isVerified: item.is_verified,
      createdAt: item.created_at,
      updatedAt: item.updated_at,
    };
  }

  // Get supplement logs for a user
  public async getSupplementLogs(
    userId: string,
    language: 'en' | 'tr' = 'en',
    date?: string,
    page: number = 1,
    limit: number = 50
  ): Promise<{ data: SupplementLog[]; count: number }> {
    try {
      let query = this.supabase
        .from('user_supplement_logs')
        .select(`
          *,
          supplement:supplements(name_en, name_tr, category)
        `, { count: 'exact' })
        .eq('user_id', userId)
        .order('taken_at', { ascending: false });

      if (date) {
        const startOfDay = new Date(date);
        startOfDay.setHours(0, 0, 0, 0);
        const endOfDay = new Date(date);
        endOfDay.setHours(23, 59, 59, 999);

        query = query
          .gte('taken_at', startOfDay.toISOString())
          .lte('taken_at', endOfDay.toISOString());
      }

      const from = (page - 1) * limit;
      const to = from + limit - 1;

      const { data, count, error } = await query.range(from, to);

      if (error) throw error;

      const formattedData = (data || []).map((item: any) => ({
        id: item.id,
        userId: item.user_id,
        supplementId: item.supplement_id,
        quantity: item.quantity,
        unit: item.unit,
        takenAt: item.taken_at,
        notes: item.notes,
        createdAt: item.created_at,
        supplementName: language === 'tr' ? item.supplement?.name_tr : item.supplement?.name_en,
        supplementCategory: item.supplement?.category,
      }));

      return { data: formattedData, count: count || 0 };
    } catch (error) {
      console.error('Error getting supplement logs:', error);
      return { data: [], count: 0 };
    }
  }

  // Add supplement log
  public async addSupplementLog(log: Omit<SupplementLog, 'id' | 'createdAt'>): Promise<{ success: boolean; error?: any }> {
    try {
      const { error } = await this.supabase
        .from('user_supplement_logs')
        .insert({
          user_id: log.userId,
          supplement_id: log.supplementId,
          quantity: log.quantity,
          unit: log.unit,
          taken_at: log.takenAt,
          notes: log.notes
        });

      if (error) throw error;
      return { success: true };
    } catch (error) {
      console.error('Error adding supplement log:', error);
      return { success: false, error };
    }
  }

  // Delete supplement log
  public async deleteSupplementLog(logId: string): Promise<{ success: boolean; error?: any }> {
    try {
      const { error } = await this.supabase
        .from('user_supplement_logs')
        .delete()
        .eq('id', logId);

      if (error) throw error;
      return { success: true };
    } catch (error) {
      console.error('Error deleting supplement log:', error);
      return { success: false, error };
    }
  }

  // Get user's supplement routine
  public async getUserRoutine(userId: string): Promise<{ data: any[]; error?: any }> {
    try {
      const { data, error } = await this.supabase
        .from('user_supplement_routines')
        .select('*, supplement:supplements(name_en, name_tr, category, dosage_amount, dosage_unit)')
        .eq('user_id', userId)
        .eq('is_active', true);

      if (error) throw error;
      return { data };
    } catch (error) {
      console.error('Error getting user routine:', error);
      return { data: [], error };
    }
  }

  // Add supplement to routine
  public async addToRoutine(userId: string, supplementId: string, reminderTime?: string): Promise<{ success: boolean; error?: any }> {
    try {
      const { error } = await this.supabase
        .from('user_supplement_routines')
        .upsert({
          user_id: userId,
          supplement_id: supplementId,
          reminder_time: reminderTime,
          is_active: true,
          updated_at: new Date()
        }, { onConflict: 'user_id,supplement_id' });

      if (error) throw error;
      return { success: true };
    } catch (error) {
      console.error('Error adding to routine:', error);
      return { success: false, error };
    }
  }

  // Remove supplement from routine (set is_active to false)
  public async removeFromRoutine(userId: string, supplementId: string): Promise<{ success: boolean; error?: any }> {
    try {
      const { error } = await this.supabase
        .from('user_supplement_routines')
        .update({ is_active: false, updated_at: new Date() })
        .eq('user_id', userId)
        .eq('supplement_id', supplementId);

      if (error) throw error;
      return { success: true };
    } catch (error) {
      console.error('Error removing from routine:', error);
      return { success: false, error };
    }
  }
}

import { SupabaseService } from './supabase';

const supabase = SupabaseService.getInstance().getClient();

// Sanitize user input for PostgREST .or() filters to prevent injection
function sanitizePostgrestValue(input: string): string {
    return input.replace(/[%_,().\\]/g, '');
}

export interface VideoContent {
    id: string;
    title: string;
    description: string;
    video_url: string;
    thumbnail_url: string;
    duration_seconds: number;
    category: 'workout' | 'nutrition' | 'education' | 'motivation' | 'recovery';
    difficulty_level: 'beginner' | 'intermediate' | 'advanced';
    instructor_id: string;
    instructor_name: string;
    instructor_avatar: string;
    views_count: number;
    likes_count: number;
    comments_count: number;
    is_premium: boolean;
    tags: string[];
    created_at: string;
    updated_at: string;
}

export interface VideoProgress {
    id: string;
    user_id: string;
    video_id: string;
    progress_seconds: number;
    total_seconds: number;
    completed: boolean;
    last_watched_at: string;
    created_at: string;
    updated_at: string;
}

export interface VideoComment {
    id: string;
    video_id: string;
    user_id: string;
    user_name: string;
    user_avatar: string;
    content: string;
    likes_count: number;
    replies_count: number;
    created_at: string;
    updated_at: string;
}

export interface VideoPlaylist {
    id: string;
    title: string;
    description: string;
    thumbnail_url: string;
    creator_id: string;
    creator_name: string;
    videos_count: number;
    is_public: boolean;
    tags: string[];
    created_at: string;
    updated_at: string;
}

export class VideoContentService {
    /**
     * Get videos by category
     */
    static async getVideosByCategory(
        category: string,
        limit: number = 20,
        offset: number = 0
    ): Promise<VideoContent[]> {
        try {
            const { data, error } = await supabase
                .from('videos')
                .select('*')
                .eq('category', category)
                .eq('is_published', true)
                .order('created_at', { ascending: false })
                .range(offset, offset + limit - 1);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error getting videos by category:', error);
            return [];
        }
    }

    /**
     * Get recommended videos for user
     */
    static async getRecommendedVideos(
        userId: string,
        limit: number = 10
    ): Promise<VideoContent[]> {
        try {
            // Get user's watched videos and preferences
            const watchedVideos = await this.getUserWatchedVideos(userId, 30);
            const userPreferences = await this.getUserPreferences(userId);

            // Build recommendation query based on user history and preferences
            let query = supabase
                .from('videos')
                .select('*')
                .eq('is_published', true)
                .not('id', 'in', `(${watchedVideos.map(v => v.video_id).join(',') || '0'})`);

            // Filter by user preferences if available
            if (userPreferences?.preferred_categories?.length > 0) {
                query = query.in('category', userPreferences.preferred_categories);
            }

            if (userPreferences?.preferred_difficulty) {
                query = query.eq('difficulty_level', userPreferences.preferred_difficulty);
            }

            const { data, error } = await query
                .order('views_count', { ascending: false })
                .limit(limit);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error getting recommended videos:', error);
            return [];
        }
    }

    /**
     * Search videos
     */
    static async searchVideos(
        query: string,
        filters: {
            category?: string;
            difficulty?: string;
            duration_min?: number;
            duration_max?: number;
            is_premium?: boolean;
        } = {},
        limit: number = 20,
        offset: number = 0
    ): Promise<VideoContent[]> {
        try {
            let supabaseQuery = supabase
                .from('videos')
                .select('*')
                .eq('is_published', true)
                .or(`title.ilike.%${sanitizePostgrestValue(query)}%,description.ilike.%${sanitizePostgrestValue(query)}%`);

            // Apply filters
            if (filters.category) {
                supabaseQuery = supabaseQuery.eq('category', filters.category);
            }

            if (filters.difficulty) {
                supabaseQuery = supabaseQuery.eq('difficulty_level', filters.difficulty);
            }

            if (filters.duration_min !== undefined) {
                supabaseQuery = supabaseQuery.gte('duration_seconds', filters.duration_min);
            }

            if (filters.duration_max !== undefined) {
                supabaseQuery = supabaseQuery.lte('duration_seconds', filters.duration_max);
            }

            if (filters.is_premium !== undefined) {
                supabaseQuery = supabaseQuery.eq('is_premium', filters.is_premium);
            }

            const { data, error } = await supabaseQuery
                .order('created_at', { ascending: false })
                .range(offset, offset + limit - 1);

            if (error) throw error;
            return data || [];
        } catch (error) {
            console.error('Error searching videos:', error);
            return [];
        }
    }

    /**
     * Get video by ID
     */
    static async getVideoById(videoId: string): Promise<VideoContent | null> {
        try {
            const { data, error } = await supabase
                .from('videos')
                .select('*')
                .eq('id', videoId)
                .eq('is_published', true)
                .single();

            if (error) throw error;

            // Increment view count
            await this.incrementViewCount(videoId);

            return data;
        } catch (error) {
            console.error('Error getting video by ID:', error);
            return null;
        }
    }

    /**
     * Get video progress for user
     */
    static async getVideoProgress(
        userId: string,
        videoId: string
    ): Promise<VideoProgress | null> {
        try {
            const { data, error } = await supabase
                .from('video_progress')
                .select('*')
                .eq('user_id', userId)
                .eq('video_id', videoId)
                .single();

            if (error && error.code !== 'PGRST116') throw error; // PGRST116 = no rows returned
            return data;
        } catch (error) {
            console.error('Error getting video progress:', error);
            return null;
        }
    }

    /**
     * Save video progress
     */
    static async saveVideoProgress(
        userId: string,
        videoId: string,
        progressSeconds: number,
        totalSeconds: number
    ): Promise<boolean> {
        try {
            const completed = progressSeconds >= totalSeconds * 0.95; // 95% watched considered complete

            const { error } = await supabase
                .from('video_progress')
                .upsert({
                    user_id: userId,
                    video_id: videoId,
                    progress_seconds: progressSeconds,
                    total_seconds: totalSeconds,
                    completed,
                    last_watched_at: new Date().toISOString()
                }, {
                    onConflict: 'user_id,video_id'
                });

            if (error) throw error;
            return true;
        } catch (error) {
            console.error('Error saving video progress:', error);
            return false;
        }
    }

    /**
     * Like a video
     */
    static async likeVideo(userId: string, videoId: string): Promise<boolean> {
        try {
            // Check if already liked
            const { data: existingLike, error: checkError } = await supabase
                .from('video_likes')
                .select('id')
                .eq('user_id', userId)
                .eq('video_id', videoId)
                .single();

            if (checkError && checkError.code === 'PGRST116') {
                // No existing like found (PGRST116 = no rows), add like
                const { error: insertError } = await supabase
                    .from('video_likes')
                    .insert({
                        user_id: userId,
                        video_id: videoId
                    });

                if (insertError) throw insertError;

                // Increment likes count
                await this.incrementLikesCount(videoId);
            } else if (!checkError && existingLike) {
                // Already liked, unlike
                const { error: deleteError } = await supabase
                    .from('video_likes')
                    .delete()
                    .eq('user_id', userId)
                    .eq('video_id', videoId);

                if (deleteError) throw deleteError;

                // Decrement likes count
                await this.decrementLikesCount(videoId);
            } else if (checkError) {
                throw checkError;
            }

            return true;
        } catch (error) {
            console.error('Error liking video:', error);
            return false;
        }
    }

    /**
     * Check if user liked a video
     */
    static async hasUserLikedVideo(userId: string, videoId: string): Promise<boolean> {
        try {
            const { data, error } = await supabase
                .from('video_likes')
                .select('id')
                .eq('user_id', userId)
                .eq('video_id', videoId)
                .single();

            return !error && data !== null;
        } catch (error) {
            console.error('Error checking if user liked video:', error);
            return false;
        }
    }

    /**
     * Add video comment
     */
    static async addComment(
        userId: string,
        videoId: string,
