                .insert({
                    video_id: videoId,
                    user_id: userId,
                    user_name: userProfile.username,
                    user_avatar: userProfile.avatar_url,
                    content,
                    likes_count: 0,
                    replies_count: 0
                })
                .select()
                .single();

            if (error) throw error;

            // Increment comments count
            await this.incrementCommentsCount(videoId);

            return data;
        } catch (error) {
            console.error('Error adding comment:', error);
            return null;
        }
    }

