export class LogManager {
    private static instance: LogManager;
    private responseTimes: number[] = [];
    private successCount: number = 0;
    private failureCount: number = 0;
    private tokenUsage: number = 0;

    private constructor() { }

    static getInstance(): LogManager {
        if (!LogManager.instance) {
            LogManager.instance = new LogManager();
        }
        return LogManager.instance;
    }

    info(message: string, data?: any): void {
        if (__DEV__) {
            console.log(`[INFO] ${message}`, data || '');
        }
        // In production, we could send this to a logging service
    }

    warn(message: string, data?: any): void {
        if (__DEV__) {
            console.warn(`[WARN] ${message}`, data || '');
        }
        this.logFailure(); // Count as a failure/issue
    }

    error(message: string, error?: any): void {
        if (__DEV__) {
            console.error(`[ERROR] ${message}`, error || '');
        }
        this.logFailure();
        // In production, send to Sentry/Bugsnag
    }

    logResponseTime(time: number): void {
        this.responseTimes.push(time);
        if (this.responseTimes.length > 100) {
            this.responseTimes.shift(); // Keep the last 100 response times
        }
    }

    logSuccess(): void {
        this.successCount++;
    }

    logFailure(): void {
        this.failureCount++;
    }

    logTokenUsage(tokens: number): void {
        this.tokenUsage += tokens;
    }

    getAverageResponseTime(): number {
        const total = this.responseTimes.reduce((sum, time) => sum + time, 0);
        return this.responseTimes.length ? total / this.responseTimes.length : 0;
    }

    getSuccessRate(): number {
        const total = this.successCount + this.failureCount;
        return total ? (this.successCount / total) * 100 : 0;
    }

    getFailureRate(): number {
        const total = this.successCount + this.failureCount;
        return total ? (this.failureCount / total) * 100 : 0;
    }

    getTotalTokenUsage(): number {
        return this.tokenUsage;
    }
}

import { AccessibilityInfo, Platform } from 'react-native';

export class AccessibilityService {
    private static instance: AccessibilityService;
    private isScreenReaderEnabled: boolean = false;
    private isBoldTextEnabled: boolean = false;
    private isReduceMotionEnabled: boolean = false;
    private isReduceTransparencyEnabled: boolean = false;
    private isInvertColorsEnabled: boolean = false;

    private constructor() {
        this.init();
        // IMPORTANT: Call cleanup() when component unmounts to prevent memory leaks:
        // useEffect(() => { return () => accessibility.cleanup(); }, []);
    }

    public static getInstance(): AccessibilityService {
        if (!AccessibilityService.instance) {
            AccessibilityService.instance = new AccessibilityService();
        }
        return AccessibilityService.instance;
    }

    private async init() {
        await this.checkAccessibilityFeatures();
        this.setupListeners();
    }

    private async checkAccessibilityFeatures() {
        try {
            this.isScreenReaderEnabled = await AccessibilityInfo.isScreenReaderEnabled();
            this.isBoldTextEnabled = await AccessibilityInfo.isBoldTextEnabled();
            this.isReduceMotionEnabled = await AccessibilityInfo.isReduceMotionEnabled();
            this.isReduceTransparencyEnabled = await AccessibilityInfo.isReduceTransparencyEnabled();
            this.isInvertColorsEnabled = await AccessibilityInfo.isInvertColorsEnabled();
        } catch {
            // Silently ignore - accessibility check failure is not critical
        }
    }

    private screenReaderSubscription: { remove: () => void } | null = null;
    private boldTextSubscription: { remove: () => void } | null = null;
    private reduceMotionSubscription: { remove: () => void } | null = null;
    private reduceTransparencySubscription: { remove: () => void } | null = null;
    private invertColorsSubscription: { remove: () => void } | null = null;

    private setupListeners() {
        // Screen reader status changes
        this.screenReaderSubscription = AccessibilityInfo.addEventListener(
            'screenReaderChanged',
            this.handleScreenReaderChanged
        );

        // Bold text status changes
        this.boldTextSubscription = AccessibilityInfo.addEventListener(
            'boldTextChanged',
            this.handleBoldTextChanged
        );

        // Reduce motion status changes
        this.reduceMotionSubscription = AccessibilityInfo.addEventListener(
            'reduceMotionChanged',
            this.handleReduceMotionChanged
        );

        // Reduce transparency status changes
        this.reduceTransparencySubscription = AccessibilityInfo.addEventListener(
            'reduceTransparencyChanged',
            this.handleReduceTransparencyChanged
        );

        // Invert colors status changes
        this.invertColorsSubscription = AccessibilityInfo.addEventListener(
            'invertColorsChanged',
            this.handleInvertColorsChanged
        );
    }

    private handleScreenReaderChanged = (enabled: boolean) => {
        this.isScreenReaderEnabled = enabled;
        this.emitAccessibilityChange('screenReader', enabled);
    };

    private handleBoldTextChanged = (enabled: boolean) => {
        this.isBoldTextEnabled = enabled;
        this.emitAccessibilityChange('boldText', enabled);
    };

    private handleReduceMotionChanged = (enabled: boolean) => {
        this.isReduceMotionEnabled = enabled;
        this.emitAccessibilityChange('reduceMotion', enabled);
    };

    private handleReduceTransparencyChanged = (enabled: boolean) => {
        this.isReduceTransparencyEnabled = enabled;
        this.emitAccessibilityChange('reduceTransparency', enabled);
    };

    private handleInvertColorsChanged = (enabled: boolean) => {
        this.isInvertColorsEnabled = enabled;
        this.emitAccessibilityChange('invertColors', enabled);
    };

    private emitAccessibilityChange(feature: string, enabled: boolean) {
        // Could be used to update UI or trigger actions
        // Example: EventEmitter.emit('accessibilityChange', { feature, enabled });
    }

    /**
     * Check if screen reader is enabled
     */
    public isScreenReaderOn(): boolean {
        return this.isScreenReaderEnabled;
    }

    /**
     * Check if bold text is enabled
     */
    public isBoldTextOn(): boolean {
        return this.isBoldTextEnabled;
    }

    /**
     * Check if reduce motion is enabled
     */
    public isReduceMotionOn(): boolean {
        return this.isReduceMotionEnabled;
    }

    /**
     * Check if reduce transparency is enabled
     */
    public isReduceTransparencyOn(): boolean {
        return this.isReduceTransparencyEnabled;
    }

    /**
     * Check if invert colors is enabled
     */
    public isInvertColorsOn(): boolean {
        return this.isInvertColorsEnabled;
    }

    /**
     * Get all accessibility settings
     */
    public getAccessibilitySettings() {
        return {
            screenReader: this.isScreenReaderEnabled,
            boldText: this.isBoldTextEnabled,
            reduceMotion: this.isReduceMotionEnabled,
            reduceTransparency: this.isReduceTransparencyEnabled,
            invertColors: this.isInvertColorsEnabled,
        };
    }

    /**
     * Announce message to screen reader
     */
    public announce(message: string, options?: { queue?: boolean }) {
        if (this.isScreenReaderEnabled) {
            AccessibilityInfo.announceForAccessibility(message);
        }
    }

    /**
     * Get accessibility props for a button
     */
    public getButtonProps(label: string, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'button' as const,
            accessibilityState: { disabled: false },
        };
    }

    /**
     * Get accessibility props for an input field
     */
    public getInputProps(label: string, hint?: string, value?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'text' as const,
            accessibilityValue: value ? { text: value } : undefined,
        };
    }

    /**
     * Get accessibility props for an image
     */
    public getImageProps(label: string, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'image' as const,
        };
    }

    /**
     * Get accessibility props for a link
     */
    public getLinkProps(label: string, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'link' as const,
        };
    }

    /**
     * Get accessibility props for a heading
     */
    public getHeadingProps(level: 1 | 2 | 3 | 4 | 5 | 6 = 1) {
        return {
            accessible: true,
            accessibilityRole: 'header' as const,
            accessibilityLevel: level,
        };
    }

    /**
     * Get accessibility props for a list item
     */
    public getListItemProps(label: string, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: Platform.OS === 'ios' ? 'listitem' : ('none' as const),
        };
    }

    /**
     * Get accessibility props for a switch/toggle
     */
    public getSwitchProps(label: string, value: boolean, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'switch' as const,
            accessibilityState: { checked: value },
            accessibilityValue: { text: value ? 'on' : 'off' },
        };
    }

    /**
     * Get accessibility props for a slider
     */
    public getSliderProps(label: string, value: number, min: number, max: number, hint?: string) {
        return {
            accessible: true,
            accessibilityLabel: label,
            accessibilityHint: hint,
            accessibilityRole: 'adjustable' as const,
            accessibilityValue: { min, max, now: value },
        };
    }

    /**
     * Get minimum touch target size (44x44 points as per Apple/Android guidelines)
     */
    public getMinTouchTargetSize(): { width: number; height: number } {
        return { width: 44, height: 44 };
    }

    /**
     * Get recommended font sizes for different text roles
     */
    public getFontSizes() {
        const baseSize = 16;
        const boldTextMultiplier = this.isBoldTextEnabled ? 1.2 : 1;

        return {
            body: baseSize * boldTextMultiplier,
            caption: baseSize * 0.875 * boldTextMultiplier,
            heading1: baseSize * 2 * boldTextMultiplier,
            heading2: baseSize * 1.75 * boldTextMultiplier,
            heading3: baseSize * 1.5 * boldTextMultiplier,
            heading4: baseSize * 1.25 * boldTextMultiplier,
            heading5: baseSize * 1.125 * boldTextMultiplier,
            heading6: baseSize * boldTextMultiplier,
        };
    }

    /**
     * Get recommended contrast ratios for text
     */
    public getContrastRatios() {
        return {
            normalText: 4.5, // WCAG AA
            largeText: 3.0, // WCAG AA for large text
            enhanced: 7.0, // WCAG AAA
        };
    }

    /**
     * Check if color combination has sufficient contrast
     */
    public hasSufficientContrast(foreground: string, background: string): boolean {
        // Simple contrast calculation (for demonstration)
        // In a real app, use a proper contrast ratio calculator
        const fg = this.getLuminance(foreground);
        const bg = this.getLuminance(background);
        const contrast = (Math.max(fg, bg) + 0.05) / (Math.min(fg, bg) + 0.05);
        return contrast >= 4.5;
    }

    private getLuminance(color: string): number {
        // Proper relative luminance calculation per WCAG 2.0
        const hex = color.replace('#', '');
        if (hex.length !== 6 && hex.length !== 3) return 0.5;

        let r: number, g: number, b: number;
        if (hex.length === 3) {
            r = parseInt(hex[0] + hex[0], 16) / 255;
            g = parseInt(hex[1] + hex[1], 16) / 255;
            b = parseInt(hex[2] + hex[2], 16) / 255;
        } else {
            r = parseInt(hex.substring(0, 2), 16) / 255;
            g = parseInt(hex.substring(2, 4), 16) / 255;
            b = parseInt(hex.substring(4, 6), 16) / 255;
        }

        // Linearize sRGB channels
        const linearize = (c: number) => c <= 0.03928 ? c / 12.92 : Math.pow((c + 0.055) / 1.055, 2.4);
        return 0.2126 * linearize(r) + 0.7152 * linearize(g) + 0.0722 * linearize(b);
    }

    /**
     * Get animation settings based on reduce motion preference
     */
    public getAnimationSettings() {
        if (this.isReduceMotionOn()) {
            return {
                duration: 0,
                useNativeDriver: true,
                shouldReduceMotion: true,
            };
        }

        return {
            duration: 300,
            useNativeDriver: true,
            shouldReduceMotion: false,
        };
    }

    /**
     * Get visual effect settings based on reduce transparency preference
     */
    public getVisualEffectSettings() {
        if (this.isReduceTransparencyOn()) {
            return {
                blurEffect: 'none' as const,
                backgroundColor: 'rgba(255, 255, 255, 0.95)',
                shouldReduceTransparency: true,
            };
        }

        return {
            blurEffect: 'regular' as const,
            backgroundColor: 'rgba(255, 255, 255, 0.8)',
            shouldReduceTransparency: false,
        };
    }

    /**
     * Get color settings based on invert colors preference
     */
    public getColorSettings() {
        if (this.isInvertColorsOn()) {
            return {
                shouldInvertColors: true,
                filter: 'invert(100%)',
            };
        }

        return {
            shouldInvertColors: false,
            filter: 'none',
        };
    }

    /**
     * Generate accessibility report
     */
    public generateAccessibilityReport() {
        const settings = this.getAccessibilitySettings();
        const issues: string[] = [];

        // Check for potential accessibility issues
        if (settings.screenReader) {
            // Screen reader specific checks
            issues.push('Screen reader is enabled - ensure all interactive elements have proper labels');
        }

        if (settings.boldText) {
            issues.push('Bold text is enabled - ensure text scaling works correctly');
        }

        if (settings.reduceMotion) {
            issues.push('Reduce motion is enabled - animations should be minimal or disabled');
        }

        if (settings.invertColors) {
            issues.push('Invert colors is enabled - ensure color contrast remains sufficient');
        }

        return {
            settings,
            issues,
            recommendations: [
                'Use semantic HTML elements where possible',
                'Ensure sufficient color contrast (minimum 4.5:1 for normal text)',
                'Provide text alternatives for non-text content',
                'Make all functionality available from a keyboard',
                'Help users avoid and correct mistakes',
            ],
        };
    }

    /**
     * Cleanup event listeners
     */
    public cleanup() {
        if (this.screenReaderSubscription) {
            this.screenReaderSubscription.remove();
        }
        if (this.boldTextSubscription) {
            this.boldTextSubscription.remove();
        }
        if (this.reduceMotionSubscription) {
            this.reduceMotionSubscription.remove();
        }
        if (this.reduceTransparencySubscription) {
            this.reduceTransparencySubscription.remove();
        }
        if (this.invertColorsSubscription) {
            this.invertColorsSubscription.remove();
        }
    }
}

import { Linking } from 'react-native';
import { NavigationContainerRef } from '@react-navigation/native';

type DeepLinkHandler = (params: Record<string, string>) => void;

export class DeepLinkingService {
    private static instance: DeepLinkingService;
    private navigationRef: NavigationContainerRef<any> | null = null;
    private linkHandlers: Map<string, DeepLinkHandler> = new Map();
    private readonly SCHEME = 'NextSelf';
    private readonly HOST = 'app.nextself.com';

    private constructor() {
        this.init();
    }

    public static getInstance(): DeepLinkingService {
        if (!DeepLinkingService.instance) {
            DeepLinkingService.instance = new DeepLinkingService();
        }
        return DeepLinkingService.instance;
    }

    private linkingSubscription: any;
    private pendingURLs: string[] = [];

    private init() {
        // Listen for incoming deep links
        this.linkingSubscription = Linking.addEventListener('url', this.handleIncomingLink);

        // Check if app was opened with a deep link
        this.getInitialURL();
    }

    /**
     * Set navigation reference for navigation
     */
    public setNavigationRef(ref: NavigationContainerRef<any>) {
        this.navigationRef = ref;
        // Process any pending URLs that arrived before navigation was ready
        if (this.pendingURLs.length > 0) {
            // Process in FIFO order
            const pending = [...this.pendingURLs];
            this.pendingURLs = [];
            for (const url of pending) {
                // processURL will route using the now-ready navigationRef
                // process asynchronously to avoid blocking
                setTimeout(() => {
                    this.processURL(url);
                }, 0);
            }
        }
    }

    /**
     * Register a handler for a specific path
     */
    public registerHandler(path: string, handler: DeepLinkHandler) {
        this.linkHandlers.set(path, handler);
    }

    /**
     * Generate a deep link URL
     */
    public generateDeepLink(path: string, params: Record<string, string> = {}): string {
        const queryString = Object.entries(params)
            .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
            .join('&');

        const url = `${this.SCHEME}://${path}${queryString ? `?${queryString}` : ''}`;
        return url;
    }

    /**
     * Generate a universal link URL
     */
    public generateUniversalLink(path: string, params: Record<string, string> = {}): string {
        const queryString = Object.entries(params)
            .map(([key, value]) => `${encodeURIComponent(key)}=${encodeURIComponent(value)}`)
            .join('&');

        const url = `https://${this.HOST}/${path}${queryString ? `?${queryString}` : ''}`;
        return url;
    }

    /**
     * Handle incoming deep link
     */
    private handleIncomingLink = (event: { url: string }) => {
        const url = event.url;
        this.processURL(url);
    };

    /**
     * Get initial URL if app was opened with a deep link
     */
    private async getInitialURL() {
        try {
            const initialUrl = await Linking.getInitialURL();
            if (initialUrl) {
                this.processURL(initialUrl);
            }
        } catch (error) {
            // Silently ignore - deep link processing failure is not critical
            return;
        }
    }

    /**
     * Process a URL and route accordingly
     */
    private async processURL(url: string) {
        try {
            // Parse URL
            const parsed = this.parseURL(url);
            if (!parsed) return;

            const { path, params } = parsed;

            // Check if we have a registered handler
            const handler = this.linkHandlers.get(path);
            if (handler) {
                handler(params);
                return;
            }

            // Default routing based on path
            this.routeByPath(path, params);
        } catch (error) {
            // Silently ignore - URL processing failure is not critical
            return;
        }
    }

    /**
     * Process any pending URLs now (useful after auth state changes)
     */
    public processPendingURLs() {
        if (!this.navigationRef || this.pendingURLs.length === 0) return;
        const pending = [...this.pendingURLs];
        this.pendingURLs = [];
        for (const url of pending) {
            setTimeout(() => this.processURL(url), 0);
        }
    }

    /**
     * Parse URL into path and parameters
     */
    private parseURL(url: string): { path: string; params: Record<string, string> } | null {
        try {
            // Handle both custom scheme and universal links
            let path = '';
            let query = '';

            if (url.startsWith(`${this.SCHEME}://`)) {
                // Custom scheme: NextSelf://path?param=value
                const withoutScheme = url.substring(`${this.SCHEME}://`.length);
                const [pathPart, queryPart] = withoutScheme.split('?');
                path = pathPart;
                query = queryPart || '';
            } else if (url.includes(this.HOST)) {
                // Universal link: https://app.nextself.com/path?param=value
                // SECURITY: Validate host strictly to prevent malicious redirects
                let urlObj: URL;
                try {
                    urlObj = new URL(url);
                } catch {
                    // Invalid URL format - security validation failed
                    return null;
                }

                // Strict host validation - only allow exact match or www subdomain
                const allowedHosts = [this.HOST, `www.${this.HOST}`];
                if (!allowedHosts.includes(urlObj.host)) {
                    // Rejected deep link from unauthorized host - security measure
                    return null;
                }

                path = urlObj.pathname.substring(1); // Remove leading slash
                query = urlObj.search.substring(1); // Remove leading ?
            } else {
                return null;
            }

            // Parse query parameters
            const params: Record<string, string> = {};
            if (query) {
                const pairs = query.split('&');
                for (const pair of pairs) {
                    const [key, value] = pair.split('=');
                    if (key && value) {
                        params[decodeURIComponent(key)] = decodeURIComponent(value);
                    }
                }
            }

            return { path, params };
        } catch (error) {
            // Silently ignore - URL parsing failure is not critical
            return null;
        }
    }

    /**
     * Route based on path
     */
    private routeByPath(path: string, params: Record<string, string>) {
        if (!this.navigationRef) {
            // Queue URL for processing when navigation ref becomes available
            const url = `${this.SCHEME}://${path}${Object.keys(params).length > 0 ? '?' + Object.entries(params).map(([k, v]) => `${k}=${v}`).join('&') : ''}`;
            if (this.pendingURLs.length >= 10) {
                this.pendingURLs.shift();
            }
            this.pendingURLs.push(url);
            return;
        }

        const navigation = this.navigationRef;

        // If the app is currently on the Auth flow and the deep link requires an
        // authenticated route, re-queue it for processing after auth completes.
        try {
            const currentRoute = (this.navigationRef as any).getCurrentRoute?.();
            const currentName = currentRoute?.name;
            const authStackNames = new Set(['Auth']);
            const allowedWhileAuth = new Set(['verify-email', 'reset-password']);
            if (currentName && authStackNames.has(currentName) && !allowedWhileAuth.has(path)) {
                const url = `${this.SCHEME}://${path}${Object.keys(params).length > 0 ? '?' + Object.entries(params).map(([k, v]) => `${k}=${v}`).join('&') : ''}`;
                if (this.pendingURLs.length >= 10) this.pendingURLs.shift();
                this.pendingURLs.push(url);
                return;
            }
        } catch (_) { }

        switch (path) {
            case 'home':
                navigation.navigate('Home');
                break;

            case 'workout':
                navigation.navigate('Sports');
                break;

            case 'nutrition':
                navigation.navigate('Nutrition');
                break;

            case 'health':
                navigation.navigate('Health');
                break;

            case 'supplements':
                navigation.navigate('Supplements');
                break;

            case 'water':
                navigation.navigate('Health');
                break;

            case 'missions':
                navigation.navigate('Missions');
                break;

            case 'store':
                navigation.navigate('Store');
                break;

            case 'smart-scale':
                navigation.navigate('SmartScale');
                break;

            case 'food-scanner':
                navigation.navigate('FoodScanner');
                break;

            case 'profile':
                navigation.navigate('Profile');
                break;

            case 'settings':
                navigation.navigate('Settings');
                break;

            case 'ai-coach':
                navigation.navigate('AIToolsStack', { screen: 'AICoach' });
                break;

            case 'ai-dietitian':
                navigation.navigate('AIToolsStack', { screen: 'AIDietitian' });
                break;

            case 'ai-chef':
                navigation.navigate('AIToolsStack', { screen: 'AIChef' });
                break;

            case 'exercise':
                if (params.id) {
                    navigation.navigate('ExerciseDetail', { exerciseId: params.id });
                }
                break;

            case 'food':
                if (params.id) {
                    navigation.navigate('FoodScanner', { foodId: params.id });
                }
                break;

            case 'supplement':
                if (params.id) {
                    navigation.navigate('Supplements');
                }
                break;

            case 'professional':
                if (params.id) {
                    navigation.navigate('ProfessionalSearch');
                }
                break;

            case 'verify-email':
                if (params.token) {
                    navigation.navigate('EmailVerification', {
                        token: params.token,
                        email: params.email
                    });
                }
                break;

            case 'reset-password':
                if (params.token) {
                    navigation.navigate('Auth', {
                        screen: 'ResetPassword',
                        params: { token: params.token }
                    });
                }
                break;

            default:
                // Fallback to home - no route found for path
                navigation.navigate('Home');
        }
    }

    /**
     * Open a URL in the app or browser
     */
    public async openURL(url: string): Promise<boolean> {
        try {
            const supported = await Linking.canOpenURL(url);
            if (supported) {
                await Linking.openURL(url);
                return true;
            }
            return false;
        } catch (error) {
            // Silently ignore - URL opening failure is not critical
            return false;
        }
    }

    /**
     * Open app settings
     */
    public async openAppSettings(): Promise<boolean> {
        return this.openURL('app-settings:');
    }

    /**
     * Open notification settings
