     */
    public async openLocationSettings(): Promise<boolean> {
        return this.openURL('app-settings:location');
    }

    /**
     * Open email app
     */
    public async openEmail(to: string, subject: string = '', body: string = ''): Promise<boolean> {
        const url = `mailto:${to}?subject=${encodeURIComponent(subject)}&body=${encodeURIComponent(body)}`;
        return this.openURL(url);
    }

    /**
     * Open phone app
     */
    public async openPhone(phoneNumber: string): Promise<boolean> {
        const url = `tel:${phoneNumber}`;
        return this.openURL(url);
    }

    /**
     * Open SMS app
     */
    public async openSMS(phoneNumber: string, body: string = ''): Promise<boolean> {
        const url = `sms:${phoneNumber}${body ? `?body=${encodeURIComponent(body)}` : ''}`;
        return this.openURL(url);
    }

    /**
     * Open maps app
     */
    public async openMaps(latitude: number, longitude: number, label: string = ''): Promise<boolean> {
        const url = `geo:${latitude},${longitude}${label ? `?q=${encodeURIComponent(label)}` : ''}`;
        return this.openURL(url);
    }

    /**
     * Open web browser
     * SECURITY: Only allows http:// and https:// URLs to prevent malicious schemes
     */
    public async openBrowser(url: string): Promise<boolean> {
        try {
            // Parse URL to validate scheme and host
            let urlObj: URL;
            try {
                urlObj = new URL(url);
            } catch {
                // If URL is invalid, try prepending https://
                if (!url.includes('://')) {
                    url = `https://${url}`;
                    try {
                        urlObj = new URL(url);
                    } catch {
                        // Invalid URL format - security validation failed
                        return false;
                    }
                } else {
                    // Invalid URL format - security validation failed
                    return false;
                }
            }

            // SECURITY: Only allow http and https schemes
            const allowedSchemes = ['http:', 'https:'];
            if (!allowedSchemes.includes(urlObj.protocol)) {
                // Rejected URL with disallowed scheme - security measure
                return false;
            }

            // Reject URLs with embedded credentials
            if (urlObj.username || urlObj.password) {
                // Rejected URL with embedded credentials - security measure
                return false;
            }

            return this.openURL(url);
        } catch (error) {
            // Silently ignore - browser opening failure is not critical
            return false;
        }
    }

    /**
     * Share content
     */
    public async shareContent(title: string, message: string, url?: string): Promise<boolean> {
        try {
            const { Share } = require('react-native');
            await Share.share({
                title,
                message: url ? `${message}\n\n${url}` : message,
                url,
            });
            return true;
        } catch (error: any) {
            if (error.message === 'User did not share') {
                // User cancelled, not an error
                return false;
            }
            console.error('Failed to share:', error);
            return false;
        }
    }

    /**
     * Cleanup event listeners
     */
    public cleanup() {
        if (this.linkingSubscription) {
            this.linkingSubscription.remove();
        }
    }
}

// A small runtime fallback for environments where `import.meta` isn't available
// Avoid referencing `import.meta` directly to prevent syntax errors when files
// are evaluated as non-modules. Prefer a global fallback, then `process.env`.
export const importMetaFallback: { env: any } = (() => {
    try {
        const globalAny: any = globalThis as any;
        const env = globalAny.__import_meta_fallback_env || (typeof process !== 'undefined' ? process.env : {});
        return { env };
    } catch (e) {
        return { env: {} };
    }
})();

// Also expose a helper to set the fallback during runtime (useful in dev/debug)
export function setImportMetaFallbackEnv(env: any) {
    (globalThis as any).__import_meta_fallback_env = env;
}

// Lightweight selective log filter for development.
// Suppresses known noisy dev messages (debug/info) and deduplicates warnings/errors.
const IGNORED_PATTERNS: RegExp[] = [
    /EXPO_PUBLIC_SUPABASE_URL/,
    /EXPO_PUBLIC_SUPABASE_ANON_KEY/,
    /EXPO_PUBLIC_ENCRYPTION_KEY/,
    /EXPO_PUBLIC_DEEPSEEK_API_KEY/,
    /EXPO_PUBLIC_SENTRY_DSN/,
    /\[SupabaseProvider\] EDGE_FN/,
    /EDGE_FN log failed/,
    /Failed to load language/,
    /Failed to load currency/,
    /Failed to load theme preference/,
];

let inited = false;
export function initLogFilter() {
    if (inited) return;
    inited = true;

    const origDebug = console.debug.bind(console);
    const origInfo = console.info.bind(console);
    const origWarn = console.warn.bind(console);
    const origError = console.error.bind(console);

    const seenWarns = new Set<string>();
    const seenErrors = new Set<string>();

    function matchesIgnored(args: any[]) {
        try {
            const text = args.map(a => (typeof a === 'string' ? a : JSON.stringify(a))).join(' ');
            return IGNORED_PATTERNS.some(p => p.test(text));
        } catch (e) {
            return false;
        }
    }

    console.debug = (...args: any[]) => {
        if (matchesIgnored(args)) return;
        origDebug(...args);
    };

    console.info = (...args: any[]) => {
        if (matchesIgnored(args)) return;
        origInfo(...args);
    };

    console.warn = (...args: any[]) => {
        try {
            const key = args.map(a => (typeof a === 'string' ? a : JSON.stringify(a))).join(' ');
            if (matchesIgnored(args)) return;
            if (seenWarns.has(key)) return;
            seenWarns.add(key);
        } catch (e) { }
        origWarn(...args);
    };

    console.error = (...args: any[]) => {
        try {
            const key = args.map(a => (typeof a === 'string' ? a : JSON.stringify(a))).join(' ');
            if (matchesIgnored(args)) return;
            if (seenErrors.has(key)) return;
            seenErrors.add(key);
        } catch (e) { }
        origError(...args);
    };
}

export default initLogFilter;

import { NavigationProp, ParamListBase, createNavigationContainerRef } from '@react-navigation/native';

export const navigationRef = createNavigationContainerRef<ParamListBase>();

export function navigate(name: string, params?: object) {
  if (navigationRef.isReady()) {
    navigationRef.navigate(name, params);
  }
}

/**
 * Safely navigate back, or navigate to a fallback screen if can't go back.
 * This prevents the "GO_BACK was not handled by any navigator" error.
 */
export function safeGoBack(
  navigation: NavigationProp<ParamListBase>,
  fallbackRoute?: string,
  fallbackParams?: object
): void {
  if (navigation.canGoBack()) {
    navigation.goBack();
  } else if (fallbackRoute) {
    (navigation as any).navigate(fallbackRoute, fallbackParams);
  }
}

import AsyncStorage from '@react-native-async-storage/async-storage';
import NetInfo, { NetInfoState } from '@react-native-community/netinfo';
import { CONFIG } from '../config/config';
import { SecurityUtils } from './security';

type OfflineOperation = {
    id: string;
    type: string;
    data: unknown;
    timestamp: number;
    retries: number;
    maxRetries: number;
};

type SyncCallback = (operation: OfflineOperation) => Promise<boolean>;

export class OfflineService {
    private static instance: OfflineService;
    private isOnline: boolean = true;
    private syncQueue: OfflineOperation[] = [];
    private syncCallbacks: Map<string, SyncCallback> = new Map();
    private syncInterval: NodeJS.Timeout | null = null;
    private isProcessing: boolean = false;
    private isPaused: boolean = false;
    private processingPromise: Promise<void> | null = null;
    private resolveProcessingPromise: (() => void) | null = null;
    private readonly STORAGE_KEY = '@NextSelf_offline_queue';
    private readonly MAX_RETRIES = 3;
    private readonly SYNC_INTERVAL = 30000; // 30 seconds

    private constructor() {
        this.init();
        // IMPORTANT: Call cleanup() when app unmounts or component unmounts:
        // useEffect(() => { return () => offlineService.cleanup(); }, []);
    }

    public static getInstance(): OfflineService {
        if (!OfflineService.instance) {
            OfflineService.instance = new OfflineService();
        }
        return OfflineService.instance;
    }

    private async init() {
        // Load saved queue from storage
        await this.loadQueue();

        // Monitor network connectivity
        this.monitorNetwork();

        // Start sync interval
        this.startSyncInterval();
    }

    private async loadQueue() {
        try {
            const savedQueue = await AsyncStorage.getItem(this.STORAGE_KEY);
            if (savedQueue) {
                const decrypted = SecurityUtils.decrypt(savedQueue);
                this.syncQueue = decrypted ? JSON.parse(decrypted) : [];
            }
        } catch (error) {
            this.syncQueue = [];
        }
    }

    private async saveQueue() {
        try {
            const encrypted = SecurityUtils.encrypt(JSON.stringify(this.syncQueue));
            await AsyncStorage.setItem(this.STORAGE_KEY, encrypted);
        } catch (error) { }
    }

    public async clearQueue() {
        this.syncQueue = [];
        try {
            await AsyncStorage.removeItem(this.STORAGE_KEY);
        } catch { }
    }

    private netInfoUnsubscribe: (() => void) | null = null;

    private monitorNetwork() {
        this.netInfoUnsubscribe = NetInfo.addEventListener((state: NetInfoState) => {
            const wasOnline = this.isOnline;
            this.isOnline = state.isConnected ?? false;

            if (!wasOnline && this.isOnline) {
                this.processQueue();
            }

            this.emitNetworkChange(this.isOnline);
        });
    }

    private emitNetworkChange(isOnline: boolean) { }

    private startSyncInterval() {
        if (this.syncInterval) {
            clearInterval(this.syncInterval);
        }

        this.syncInterval = setInterval(() => {
            if (this.isOnline && this.syncQueue.length > 0) {
                this.processQueue();
            }
        }, this.SYNC_INTERVAL);
    }

    public registerSyncHandler(type: string, callback: SyncCallback) {
        this.syncCallbacks.set(type, callback);
    }

    public async queueOperation(type: string, data: unknown, maxRetries: number = this.MAX_RETRIES): Promise<string> {
        const operation: OfflineOperation = {
            id: this.generateId(),
            type,
            data,
            timestamp: Date.now(),
            retries: 0,
            maxRetries,
        };

        this.syncQueue.push(operation);
        await this.saveQueue();

        // Always enqueue; let the single processor handle operations to avoid
        // concurrent processing of the same item. If not paused and online,
        // trigger the centralized queue processor.
        if (this.isOnline && !this.isPaused) {
            // Defer processing to next tick to avoid racing with multiple rapid enqueues
            setTimeout(() => {
                this.processQueue();
            }, 0);
        }

        return operation.id;
    }

    private async processOperation(operation: OfflineOperation): Promise<boolean> {
        const callback = this.syncCallbacks.get(operation.type);

        if (!callback) {
            return false;
        }

        try {
            const success = await callback(operation);

            if (success) {
                this.syncQueue = this.syncQueue.filter(op => op.id !== operation.id);
                await this.saveQueue();
                return true;
            } else {
                operation.retries++;

                if (operation.retries >= operation.maxRetries) {
                    this.syncQueue = this.syncQueue.filter(op => op.id !== operation.id);
                    await this.saveQueue();
                    this.emitOperationFailed(operation, 'max_retries');
                } else {
                    await this.saveQueue();
                }

                return false;
            }
        } catch (error) {
            operation.retries++;

            if (operation.retries >= operation.maxRetries) {
                this.syncQueue = this.syncQueue.filter(op => op.id !== operation.id);
                await this.saveQueue();
                this.emitOperationFailed(operation, 'error');
            } else {
                await this.saveQueue();
            }

            return false;
        }
    }

    private async processQueue() {
        if (!this.isOnline || this.syncQueue.length === 0 || this.isProcessing || this.isPaused) {
            return;
        }

        // Mark processing and expose a promise that callers can await to know
        // when processing is complete (used by sign-out to wait for quiescence).
        this.isProcessing = true;
        this.processingPromise = new Promise<void>((resolve) => {
            this.resolveProcessingPromise = resolve;
        });

        try {
            const operations = [...this.syncQueue];

            for (const operation of operations) {
                if (!this.isOnline || this.isPaused) {
                    break;
                }

                await this.processOperation(operation);
            }
        } finally {
            this.isProcessing = false;
            if (this.resolveProcessingPromise) {
                this.resolveProcessingPromise();
            }
            this.processingPromise = null;
            this.resolveProcessingPromise = null;
        }
    }

    /**
     * Pause processing and wait for any in-flight processing to finish.
     * After this resolves, no further processing will start until `resume()` is called.
     */
    public async pauseAndWait(timeoutMs: number = 4000): Promise<void> {
        this.isPaused = true;

        if (!this.isProcessing) return;

        // Race between quiescence and a fail-safe timeout to avoid hanging forever
        const quiescentPromise = this.awaitQuiescent();
        const timeoutPromise = new Promise<void>((resolve) => {
            setTimeout(() => {
                // If timeout fires, log a warning and resolve so callers can proceed
                try {
                    console.warn(`[OfflineService] pauseAndWait timed out after ${timeoutMs}ms; proceeding with paused queue.`);
                } catch (_) { }
                resolve();
            }, timeoutMs);
        });

        await Promise.race([quiescentPromise, timeoutPromise]);
    }

    public resume(): void {
        this.isPaused = false;
        if (this.isOnline && this.syncQueue.length > 0) {
            // kick the processor again
            this.processQueue();
        }
    }

    public async awaitQuiescent(): Promise<void> {
        if (!this.isProcessing) return;
        return this.processingPromise ?? Promise.resolve();
    }

    public getQueueStatus() {
        return {
            isOnline: this.isOnline,
            queueLength: this.syncQueue.length,
            operations: this.syncQueue.map(op => ({
                id: op.id,
                type: op.type,
                timestamp: op.timestamp,
                retries: op.retries,
                maxRetries: op.maxRetries,
            })),
        };
    }

    public async removeOperation(operationId: string): Promise<boolean> {
        const initialLength = this.syncQueue.length;
        this.syncQueue = this.syncQueue.filter(op => op.id !== operationId);

        if (this.syncQueue.length < initialLength) {
            await this.saveQueue();
            return true;
        }

        return false;
    }

    public getIsOnline(): boolean {
        return this.isOnline;
    }

    public async syncNow(): Promise<{ success: boolean; processed: number }> {
        if (!this.isOnline) {
            return { success: false, processed: 0 };
        }

        const initialLength = this.syncQueue.length;
        await this.processQueue();
        const processed = initialLength - this.syncQueue.length;

        return { success: true, processed };
    }

    private generateId(): string {
        return `${Date.now()}-${Math.random().toString(36).substring(2, 11)}`;
    }

    private emitOperationFailed(operation: OfflineOperation, reason: string) { }

    public cleanup() {
        if (this.syncInterval) {
            clearInterval(this.syncInterval);
            this.syncInterval = null;
        }
        if (this.netInfoUnsubscribe) {
            this.netInfoUnsubscribe();
            this.netInfoUnsubscribe = null;
        }
    }
}

import React from 'react';
import { InteractionManager } from 'react-native';

export class PerformanceUtils {
  // Run expensive operations after interactions complete
  static runAfterInteractions<T>(callback: () => Promise<T>): Promise<T> {
    return new Promise((resolve, reject) => {
      InteractionManager.runAfterInteractions(() => {
        callback().then(resolve).catch(reject);
      });
    });
  }

  // Debounce function for performance
  static debounce<T extends (...args: unknown[]) => unknown>(
    func: T,
    wait: number
  ): (...args: Parameters<T>) => void {
    let timeout: NodeJS.Timeout;

    return (...args: Parameters<T>) => {
      clearTimeout(timeout);
      timeout = setTimeout(() => func(...args), wait);
    };
  }

  // Throttle function for performance
  static throttle<T extends (...args: unknown[]) => unknown>(
    func: T,
    limit: number
  ): (...args: Parameters<T>) => void {
    let inThrottle: boolean;

    return (...args: Parameters<T>) => {
      if (!inThrottle) {
        func(...args);
        inThrottle = true;
        setTimeout(() => inThrottle = false, limit);
      }
    };
  }

  // Measure performance of a function
  static async measurePerformance<T>(
    name: string,
    fn: () => Promise<T>
  ): Promise<T> {
    const start = performance.now();
    const result = await fn();
    const end = performance.now();

    console.log(`${name} took ${end - start} milliseconds`);
    return result;
  }

  // Batch multiple operations
  static async batch<T>(
    operations: Array<() => Promise<T>>,
    batchSize: number = 5
  ): Promise<T[]> {
    const results: T[] = [];

    for (let i = 0; i < operations.length; i += batchSize) {
      const batch = operations.slice(i, i + batchSize);
      const batchResults = await Promise.all(batch.map(op => op()));
      results.push(...batchResults);

      // Allow UI to breathe between batches
      if (i + batchSize < operations.length) {
        await new Promise(resolve => setTimeout(resolve, 0));
      }
    }

    return results;
  }

  // Cache expensive computations
  static memoize<T extends (...args: unknown[]) => unknown>(
    fn: T,
    getKey?: (...args: Parameters<T>) => string,
    maxCacheSize: number = 500
  ): T {
    const cache = new Map<string, ReturnType<T>>();

    return ((...args: Parameters<T>) => {
      const key = getKey ? getKey(...args) : JSON.stringify(args);

      if (cache.has(key)) {
        // Move to end for LRU behavior
        const value = cache.get(key);
        cache.delete(key);
        cache.set(key, value!);
        return value;
      }

      const result = fn(...args);
      cache.set(key, result as ReturnType<T>);

      // Evict oldest entries when cache exceeds max size
      if (cache.size > maxCacheSize) {
        const firstKey = cache.keys().next().value;
        if (firstKey !== undefined) cache.delete(firstKey);
      }

      return result;
    }) as T;
  }

  // Lazy load expensive resources
  static lazyLoad<T>(factory: () => Promise<T>): () => Promise<T> {
    let instance: T | null = null;
    let loading: Promise<T> | null = null;

    return async () => {
      if (instance) return instance;

      if (loading) return loading;

      loading = factory();
      instance = await loading;
      return instance;
    };
  }

  // Optimize image loading
  static optimizeImageUri(uri: string, width: number, height: number): string {
    // This would integrate with image optimization services
    // For now, return the original URI
    return uri;
  }

  // Memory cleanup
  static cleanup() {
    // Clear any caches or perform memory cleanup
    if (global.gc) {
      global.gc();
    }
  }

  // Performance monitoring
  static startPerformanceMonitor() {
    // Monitor key performance metrics
    if (typeof window !== 'undefined' && window.PerformanceObserver) {
      const observer = new PerformanceObserver((list) => {
        for (const entry of list.getEntries()) {
          console.log(`Performance: ${entry.name} - ${entry.duration}ms`);
        }
      });

      observer.observe({ entryTypes: ['measure', 'navigation'] });

      return observer;
    }

    return null;
  }

  // Check if device is low-end
  static isLowEndDevice(): boolean {
    // This would check device capabilities
    // For now, return false
    return false;
  }

  // Adjust quality based on device performance
  static getQualityForDevice(): 'low' | 'medium' | 'high' {
    if (this.isLowEndDevice()) {
      return 'low';
    }

    return 'high';
  }

  // Optimize animations based on device
  static getAnimationConfig() {
    const quality = this.getQualityForDevice();

    switch (quality) {
      case 'low':
        return {
          duration: 200,
          useNativeDriver: true,
          reduceMotion: true,
        };
      case 'medium':
        return {
          duration: 300,
          useNativeDriver: true,
          reduceMotion: false,
        };
      default:
        return {
          duration: 400,
          useNativeDriver: true,
          reduceMotion: false,
        };
    }
  }
}

// Performance hooks
export const usePerformanceMonitor = () => {
  const [metrics, setMetrics] = React.useState<Record<string, number>>({});

  const measure = React.useCallback((name: string, duration: number) => {
    setMetrics(prev => ({
      ...prev,
      [name]: duration,
    }));
  }, []);

  const startMeasure = React.useCallback((name: string) => {
    if (typeof performance !== 'undefined') {
      const start = performance.now();

      return () => {
        const end = performance.now();
        measure(name, end - start);
      };
    }

    return () => { };
  }, [measure]);

  return { metrics, startMeasure };
};

// Memory monitoring
export const useMemoryMonitor = () => {
  const [memoryUsage, setMemoryUsage] = React.useState<number>(0);

  React.useEffect(() => {
    const interval = setInterval(() => {
      // Check if performance.memory is available (browser environment)
      interface PerformanceMemory {
        memory?: { usedJSHeapSize: number };
      }
      const perf = performance as unknown as PerformanceMemory;
      if (typeof performance !== 'undefined' && perf.memory) {
        setMemoryUsage(perf.memory.usedJSHeapSize);
      }
    }, 5000);

    return () => clearInterval(interval);
  }, []);

  return memoryUsage;
};

import CryptoJS from 'crypto-js';
import { CONFIG } from '../config/config';

declare const Buffer: {
  from(data: string, encoding?: string): { toString(encoding?: string): string };
};

export class SecurityUtils {
  // SECURITY: Client-side encryption keys MUST NOT be embedded in production builds.
  // Prefer server-side encryption (Edge Functions/KMS). If an env var is provided
  // (development/tests), it will be used; otherwise client-side encryption methods
  // will throw with a clear error instructing to use server-side endpoints.
  private static readonly ENCRYPTION_KEY = process.env.EXPO_PUBLIC_ENCRYPTION_KEY || '';

  // Encrypt sensitive data
  static encrypt(data: string, key: string = this.ENCRYPTION_KEY): string {
    try {
      if (!key) {
        throw new Error('Client-side encryption is disabled. Use server-side encryption (Edge Functions) or provide a key explicitly for development/tests.');
      }
      return CryptoJS.AES.encrypt(data, key).toString();
    } catch (error) {
      console.error('Encryption failed');
      throw new Error('Failed to encrypt data');
    }
  }

  // Decrypt sensitive data
  static decrypt(encryptedData: string, key: string = this.ENCRYPTION_KEY): string {
    try {
      if (!key) {
        throw new Error('Client-side decryption is disabled. Use server-side decryption (Edge Functions) or provide a key explicitly for development/tests.');
      }
      const bytes = CryptoJS.AES.decrypt(encryptedData, key);
      return bytes.toString(CryptoJS.enc.Utf8);
    } catch (error) {
      console.error('Decryption failed');
      throw new Error('Failed to decrypt data');
    }
  }

  // Hash data - SECURITY: SHA256 is NOT suitable for password hashing.
  // Supabase Auth handles password hashing with bcrypt server-side.
  // This method should only be used for non-security hashing (e.g., checksums).
  static hashData(data: string): string {
    try {
      return CryptoJS.SHA256(data).toString();
    } catch (error) {
      console.error('Hashing failed');
      throw new Error('Failed to hash data');
    }
  }

  /** @alias hashData - convenience alias expected by tests and consumers */
  static hashPassword(password: string): string {
    return this.hashData(password);
  }

  // Generate secure token using CryptoJS (cryptographically secure)
  static generateSecureToken(length: number = 32): string {
    // Use CryptoJS random bytes - cryptographically secure
    const wordArray = CryptoJS.lib.WordArray.random(length);
    return wordArray.toString(CryptoJS.enc.Hex).substring(0, length);
  }

  // Validate password strength
  static validatePasswordStrength(password: string): {
    score: number;
    feedback: string[];
  } {
    const feedback: string[] = [];
    let score = 0;

    // Length check
    if (password.length >= 8) {
      score += 20;
    } else {
      feedback.push('Password should be at least 8 characters long');
    }

    // Uppercase check
    if (/[A-Z]/.test(password)) {
      score += 20;
    } else {
      feedback.push('Password should contain at least one uppercase letter');
    }

    // Lowercase check
    if (/[a-z]/.test(password)) {
      score += 20;
    } else {
      feedback.push('Password should contain at least one lowercase letter');
    }

    // Number check
    if (/\d/.test(password)) {
      score += 20;
    } else {
      feedback.push('Password should contain at least one number');
    }

    // Special character check
    if (/[!@#$%^&*(),.?":{}|<>]/.test(password)) {
      score += 20;
    } else {
      feedback.push('Password should contain at least one special character');
    }

    return { score, feedback };
  }

  // Sanitize input to prevent XSS - strip dangerous content
  static sanitizeInput(input: string, maxLength: number = 10000): string {
    if (!input || typeof input !== 'string') return '';
    // Truncate to prevent ReDoS
    const truncated = input.length > maxLength ? input.slice(0, maxLength) : input;
    return truncated
      .replace(/<script\b[^>]*>[\s\S]*?<\/script>/gi, '') // Remove script tags
      .replace(/javascript:[^\s]*/gi, '')                  // Remove javascript: protocol
      .replace(/\bon\w+\s*=\s*(['"])[^'"]*\1/gi, '')       // Remove event handlers (quoted)
      .replace(/\bon\w+\s*=\s*\S+/gi, '')                  // Remove event handlers (unquoted)
      .replace(/\s+/g, ' ')                                 // Collapse multiple spaces
      .trim();
  }

  // Validate API request
  static validateApiRequest(request: {
    method: string;
    url: string;
    headers?: Record<string, string>;
    body?: string;
  }): boolean {
    // Check for suspicious patterns
    const suspiciousPatterns = [
      /<script/i,
      /javascript:/i,
      /on\w+\s*=/i,
      /eval\s*\(/i,
      /document\.cookie/i,
      /window\.location/i,
    ];

    const checkString = (str: string) => {
      return suspiciousPatterns.some(pattern => pattern.test(str));
    };

    // Check URL
    if (checkString(request.url)) {
      return false;
    }

    // Check headers
    if (request.headers) {
      for (const [key, value] of Object.entries(request.headers)) {
        if (checkString(key) || checkString(value)) {
          return false;
        }
      }
    }

    // Check body
    if (request.body && checkString(request.body)) {
      return false;
    }

    return true;
  }

  // Rate limiting
  static createRateLimiter(maxRequests: number, windowMs: number) {
    const requests: number[] = [];

    return {
      isAllowed: (): boolean => {
        const now = Date.now();

        // Remove old requests outside the window
        while (requests.length > 0 && requests[0] < now - windowMs) {
          requests.shift();
        }

        // Check if under the limit
        if (requests.length < maxRequests) {
          requests.push(now);
          return true;
        }

        return false;
      },
    };
  }

  // Generate CSRF token
  static generateCSRFToken(): string {
    return this.generateSecureToken(64);
  }

  // CSRF comparison key — MUST be set in env vars in production
  // Falls back to empty string which will cause validation to fail safely
  private static readonly CSRF_COMPARE_KEY = process.env.EXPO_PUBLIC_CSRF_KEY || '';

  // Validate CSRF token using constant-time comparison to prevent timing attacks
  static validateCSRFToken(token: string, sessionToken: string): boolean {
    if (!token || !sessionToken || typeof token !== 'string' || typeof sessionToken !== 'string') return false;
    if (token.length !== sessionToken.length) return false;
    // Constant-time comparison via HMAC with per-instance key
    const hmac1 = CryptoJS.HmacSHA256(token, this.CSRF_COMPARE_KEY).toString();
    const hmac2 = CryptoJS.HmacSHA256(sessionToken, this.CSRF_COMPARE_KEY).toString();
    return hmac1 === hmac2;
  }

  // Check for common passwords
  static isCommonPassword(password: string): boolean {
    const commonPasswords = [
      'password', '123456', '123456789', 'qwerty', 'abc123',
      'password123', 'admin', 'letmein', 'welcome', 'monkey',
      '1234567890', 'password1', '123123', 'iloveyou',
      'adobe123', '1231234', 'sunshine', 'password123',
      'princess', 'azerty', 'trustno1', '1q2w3e4r5t',
    ];

    return commonPasswords.includes(password.toLowerCase());
  }

  // Generate device fingerprint with more entropy
  static generateDeviceFingerprint(): string {
    try {
      const deviceInfo = {
        platform: require('react-native').Platform?.OS || 'react-native',
        version: require('react-native').Platform?.Version || 'unknown',
        timezone: Intl.DateTimeFormat().resolvedOptions().timeZone,
        locale: Intl.DateTimeFormat().resolvedOptions().locale || 'unknown',
        screenWidth: require('react-native').Dimensions?.get('window')?.width || 0,
        screenHeight: require('react-native').Dimensions?.get('window')?.height || 0,
      };
      const fingerprint = Object.values(deviceInfo).join('|');
      return CryptoJS.SHA256(fingerprint).toString();
    } catch {
      // Fallback for non-RN environments
      return CryptoJS.SHA256(`rn|${Intl.DateTimeFormat().resolvedOptions().timeZone}`).toString();
    }
  }

  // Validate session
  static validateSession(session: {
    token: string;
    expiresAt: number;
    userId: string;
  }): boolean {
    const now = Date.now();

    // Check if session is expired
    if (now > session.expiresAt) {
      return false;
    }

    // Check if token is valid (basic validation)
    if (!session.token || session.token.length < 10) {
      return false;
    }

    // Check if userId is valid
    if (!session.userId || session.userId.length < 1) {
      return false;
    }

    return true;
  }

  // Encrypt file data
  static encryptFileData(data: ArrayBuffer, key: string = this.ENCRYPTION_KEY): string {
    try {
      const wordArray = CryptoJS.lib.WordArray.create(data as any);
      return CryptoJS.AES.encrypt(wordArray, key).toString();
    } catch (error) {
      console.error('File encryption failed');
      throw new Error('Failed to encrypt file data');
    }
  }

  // Decrypt file data
  static decryptFileData(encryptedData: string, key: string = this.ENCRYPTION_KEY): ArrayBuffer {
    try {
      const decrypted = CryptoJS.AES.decrypt(encryptedData, key);
      const latin1String = decrypted.toString(CryptoJS.enc.Latin1);
      const bytes = new Uint8Array(latin1String.length);
      for (let i = 0; i < latin1String.length; i++) {
        bytes[i] = latin1String.charCodeAt(i);
      }
      return bytes.buffer;
    } catch (error) {
      console.error('File decryption failed');
      throw new Error('Failed to decrypt file data');
    }
  }

  // Generate secure random number
  static secureRandom(min: number, max: number): number {
    const range = max - min + 1;
    const randomArray = CryptoJS.lib.WordArray.random(4);
    // Use unsigned right shift (>>> 0) to convert signed 32-bit to unsigned,
    // preventing negative modulo results
    const unsignedValue = randomArray.words[0] >>> 0;
    const randomValue = unsignedValue % range;
    return min + randomValue;
  }

  // Validate email format with additional security checks
  static validateEmailSecure(email: string): {
    isValid: boolean;
    isDisposable: boolean;
    risk: 'low' | 'medium' | 'high';
  } {
    const basicValidation = /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);

    if (!basicValidation) {
      return { isValid: false, isDisposable: false, risk: 'high' };
    }

    // Check for disposable email domains
    const disposableDomains = [
      '10minutemail.com', 'guerrillamail.com', 'mailinator.com',
      'tempmail.org', 'yopmail.com', 'maildrop.cc',
    ];

    const domain = email.split('@')[1].toLowerCase();
    const isDisposable = disposableDomains.some(d => domain.includes(d));

    // Assess risk based on domain and patterns
    let risk: 'low' | 'medium' | 'high' = 'low';

    if (isDisposable) {
      risk = 'high';
    } else if (domain.includes('temp') || domain.includes('throwaway')) {
      risk = 'medium';
    }

    return { isValid: true, isDisposable, risk };
  }
}

export interface ValidationResult {
  isValid: boolean;
  errors: string[];
}

export class ValidationUtils {
  // Email validation
  static validateEmail(email: string): ValidationResult {
    const errors: string[] = [];

    if (!email) {
      errors.push('Email is required');
    } else if (!/^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email)) {
      errors.push('Please enter a valid email address');
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Password validation
  static validatePassword(password: string): ValidationResult {
    const errors: string[] = [];

    if (!password) {
      errors.push('Password is required');
    } else {
      if (password.length < 8) {
        errors.push('Password must be at least 8 characters long');
      }
      if (!/(?=.*[a-z])/.test(password)) {
        errors.push('Password must contain at least one lowercase letter');
      }
      if (!/(?=.*[A-Z])/.test(password)) {
        errors.push('Password must contain at least one uppercase letter');
      }
      if (!/(?=.*\d)/.test(password)) {
        errors.push('Password must contain at least one number');
      }
      if (!/(?=.*[@$!%*?&])/.test(password)) {
        errors.push('Password must contain at least one special character');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Username validation
  static validateUsername(username: string): ValidationResult {
    const errors: string[] = [];

    if (!username) {
      errors.push('Username is required');
    } else {
      if (username.length < 3) {
        errors.push('Username must be at least 3 characters long');
      }
      if (username.length > 20) {
        errors.push('Username must be no more than 20 characters long');
      }
      if (!/^[a-zA-Z0-9_]+$/.test(username)) {
        errors.push('Username can only contain letters, numbers, and underscores');
      }
      if (/^[0-9]/.test(username)) {
        errors.push('Username cannot start with a number');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Name validation
  static validateName(name: string, field: string = 'Name'): ValidationResult {
    const errors: string[] = [];

    if (!name) {
      errors.push(`${field} is required`);
    } else {
      if (name.length < 2) {
        errors.push(`${field} must be at least 2 characters long`);
      }
      if (name.length > 50) {
        errors.push(`${field} must be no more than 50 characters long`);
      }
      if (!/^[a-zA-Z\s'-]+$/.test(name)) {
        errors.push(`${field} can only contain letters, spaces, hyphens, and apostrophes`);
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Height validation
  static validateHeight(height: string): ValidationResult {
    const errors: string[] = [];

    if (!height) {
      errors.push('Height is required');
    } else {
      const heightNum = parseFloat(height);
      if (isNaN(heightNum)) {
        errors.push('Height must be a valid number');
      } else if (heightNum < 50) {
        errors.push('Height must be at least 50 cm');
      } else if (heightNum > 300) {
        errors.push('Height must be no more than 300 cm');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Weight validation
  static validateWeight(weight: string): ValidationResult {
    const errors: string[] = [];

    if (!weight) {
      errors.push('Weight is required');
    } else {
      const weightNum = parseFloat(weight);
      if (isNaN(weightNum)) {
        errors.push('Weight must be a valid number');
      } else if (weightNum < 20) {
        errors.push('Weight must be at least 20 kg');
      } else if (weightNum > 500) {
        errors.push('Weight must be no more than 500 kg');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Date of birth validation
  static validateDateOfBirth(dateOfBirth: string): ValidationResult {
    const errors: string[] = [];

    if (!dateOfBirth) {
      errors.push('Date of birth is required');
    } else {
      const date = new Date(dateOfBirth);
      const now = new Date();
      const minAge = 13;
      const maxAge = 120;

      if (isNaN(date.getTime())) {
        errors.push('Please enter a valid date');
      } else {
        const age = Math.floor((now.getTime() - date.getTime()) / (365.25 * 24 * 60 * 60 * 1000));

        if (age < minAge) {
          errors.push(`You must be at least ${minAge} years old`);
        } else if (age > maxAge) {
          errors.push(`Please enter a valid date of birth`);
        }
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Phone number validation
  static validatePhoneNumber(phone: string): ValidationResult {
    const errors: string[] = [];

    if (phone) {
      // Remove all non-digit characters
      const cleanPhone = phone.replace(/\D/g, '');

      if (cleanPhone.length < 10) {
        errors.push('Phone number must be at least 10 digits');
      } else if (cleanPhone.length > 15) {
        errors.push('Phone number must be no more than 15 digits');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Calorie target validation
  static validateCalorieTarget(calories: string): ValidationResult {
    const errors: string[] = [];

    if (!calories) {
      errors.push('Calorie target is required');
    } else {
      const caloriesNum = parseInt(calories);
      if (isNaN(caloriesNum)) {
        errors.push('Calorie target must be a valid number');
      } else if (caloriesNum < 800) {
        errors.push('Calorie target must be at least 800 calories');
      } else if (caloriesNum > 5000) {
        errors.push('Calorie target must be no more than 5000 calories');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Protein target validation
  static validateProteinTarget(protein: string): ValidationResult {
    const errors: string[] = [];

    if (!protein) {
      errors.push('Protein target is required');
    } else {
      const proteinNum = parseInt(protein);
      if (isNaN(proteinNum)) {
        errors.push('Protein target must be a valid number');
      } else if (proteinNum < 10) {
        errors.push('Protein target must be at least 10 grams');
      } else if (proteinNum > 500) {
        errors.push('Protein target must be no more than 500 grams');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Exercise name validation
  static validateExerciseName(name: string): ValidationResult {
    const errors: string[] = [];

    if (!name) {
      errors.push('Exercise name is required');
    } else {
      if (name.length < 2) {
        errors.push('Exercise name must be at least 2 characters long');
      }
      if (name.length > 100) {
        errors.push('Exercise name must be no more than 100 characters long');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Food item validation
  static validateFoodItem(foodItem: {
    name: string;
    calories: string;
    protein: string;
    carbs: string;
    fat: string;
  }): ValidationResult {
    const errors: string[] = [];

    // Validate name
    const nameValidation = this.validateExerciseName(foodItem.name);
    errors.push(...nameValidation.errors);

    // Validate calories
    const caloriesValidation = this.validateCalorieTarget(foodItem.calories);
    if (caloriesValidation.errors.length > 0) {
      errors.push('Calories must be a valid number between 0 and 5000');
    }

    // Validate macronutrients
    ['protein', 'carbs', 'fat'].forEach((macro) => {
      const value = foodItem[macro as keyof typeof foodItem];
      if (value) {
        const num = parseFloat(value);
        if (isNaN(num) || num < 0 || num > 1000) {
          errors.push(`${macro.charAt(0).toUpperCase() + macro.slice(1)} must be a valid number between 0 and 1000`);
        }
      }
    });

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Sanitize input to prevent XSS
  static sanitizeInput(input: string): string {
    if (!input) return '';
    return input
      .trim()
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;')
      .replace(/\//g, '&#x2F;');
  }

  // Validate complete registration form
  static validateRegistrationForm(formData: {
    username: string;
    firstName: string;
    lastName: string;
    email: string;
    password: string;
    confirmPassword: string;
    dateOfBirth: string;
    height: string;
    weight: string;
  }): ValidationResult {
    const errors: string[] = [];

    // Validate each field
    const validations = [
      this.validateUsername(formData.username),
      this.validateName(formData.firstName, 'First name'),
      this.validateName(formData.lastName, 'Last name'),
      this.validateEmail(formData.email),
      this.validatePassword(formData.password),
      this.validateDateOfBirth(formData.dateOfBirth),
      this.validateHeight(formData.height),
      this.validateWeight(formData.weight),
    ];

    validations.forEach(validation => {
      errors.push(...validation.errors);
    });

    // Check if passwords match
    if (formData.password !== formData.confirmPassword) {
      errors.push('Passwords do not match');
    }

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // SQL injection validation: check for dangerous SQL characters
  static validateSQLInjection(input: string): ValidationResult {
    const errors: string[] = [];
    if (!input) return { isValid: true, errors };

    // SQL injection dangerous patterns
    const dangerousPatterns = [
      /(\-\-)/g,           // SQL comment
      /(\/\*)/g,           /* SQL comment start */
      /(\*\/)/g,           /* SQL comment end */
      /(\;)/g,             // Query delimiter
      /(\b(SELECT|INSERT|UPDATE|DELETE|DROP|UNION|ALTER|CREATE|EXEC|EXECUTE|TRUNCATE)\b)/gi, // SQL keywords (optional)
      /(\b(OR|AND)\s+['"\d])/gi, // OR/AND injection
      /(\b(WHERE|SET|VALUES)\s*['"])/gi, // SQL clause injection
    ];

    // Check for single quotes, double quotes that could break queries
    const singleQuoteCount = (input.match(/'/g) || []).length;
    const doubleQuoteCount = (input.match(/"/g) || []).length;
    const semicolonCount = (input.match(/;/g) || []).length;

    // If there are too many quotes, could be injection attempt
    if (singleQuoteCount > 5 || doubleQuoteCount > 5) {
      errors.push('Input contains excessive quotes which could indicate SQL injection attempt');
    }

    // Check patterns
    dangerousPatterns.forEach((pattern, index) => {
      if (pattern.test(input)) {
        errors.push('Input contains potential SQL injection characters');
        // break after first detection
      }
    });

    return {
      isValid: errors.length === 0,
      errors,
    };
  }

  // Sanitize SQL input by escaping dangerous characters (for LIKE/ILIKE)
  static escapeLike(input: string): string {
    if (!input) return '';
    // Escape PostgreSQL LIKE/ILIKE wildcard characters: %, _, \
    return input.replace(/[%_\\]/g, '\\$&');
  }

  // Sanitize input for use in raw SQL (parameterized queries are preferred)
  static sanitizeSQL(input: string): string {
    if (!input) return '';
    // Remove or escape dangerous SQL characters (basic)
    let sanitized = input
      .replace(/'/g, "''") // Escape single quotes by doubling (for PostgreSQL)
      .replace(/\\/g, '\\\\') // Escape backslashes
      .replace(/\-\-/g, '') // Remove SQL comments
      .replace(/;/g, '') // Remove semicolons
      .replace(/\/\*/g, '') // Remove block comment start
      .replace(/\*\//g, ''); // Remove block comment end
    // Trim extra spaces
    sanitized = sanitized.trim();
    return sanitized;
  }

  // Combined validation and sanitization for SQL input
  static validateAndSanitizeSQL(input: string): { sanitized: string; validation: ValidationResult } {
    const validation = this.validateSQLInjection(input);
    const sanitized = this.sanitizeSQL(input);
    return { sanitized, validation };
  }
}
